-- Poems batch 270
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('ef7167e2-1822-4eea-9c90-84dd0f1c2398','和聖俞鬥山鵲','韓維','宋','宋诗','song-poetry','','[]','稟此分鬥姿，用舍在所激。',48,'全唐诗/poet.song.24000.json','["稟此分鬥姿，用舍在所激。", "翻跳巧相中，一敗軀命擲。", "晨鷄鳴不渝，霜隼時乃擊。", "既無一二效，豈不愧肉食。"]'),
('3018f2f4-c235-4afb-9812-563f00851990','和聖俞飲會之作','韓維','宋','宋诗','song-poetry','','[]','幕府多俊良，乘間得邀命。',120,'全唐诗/poet.song.24000.json','["幕府多俊良，乘間得邀命。", "陳觴四座合，清笑發高興。", "冰梨走咸黽，霜橘薦穰鄧。", "肴羞愧無珍，粗竭我家稱。", "禮酬嫌已拘，戲罰甘太橫。", "詩誦唐人爲，議法漢儒正。", "新嘲時巧發，詭令或孤迸。", "聊矜一時快，豈校負與勝。", "行傷昆弟別，且樂賓友盛。", "但願會合頻，醉日敢辭併。"]'),
('35803d9a-df54-45e2-9758-ad6b34071cc2','飲聖俞西軒','韓維','宋','宋诗','song-poetry','','[]','歡常以飲合，歡意則非外。',192,'全唐诗/poet.song.24000.json','["歡常以飲合，歡意則非外。", "今吾二三子，共此西軒會。", "主人吾儒秀，言與二雅配。", "酒行倡大論，文字略瑣碎。", "上言評人物，要當本諸內。", "下言譏爲學，不以滿自概。", "唐之衆詩人，區別各異派。", "一經君子評，斂鑿棄秕糒。", "予曰吾聖俞，名足通後代。", "答我文如韓，尚有六經在。", "况吾何所立，聞譽若抱躉。", "聖俞善誘掖，斯語不無戒。", "意欲令吾曹，事業進以大。", "我雖頑無能，聞此亦健快。", "呼觴滿自引，不畏坐客怪。", "歸來書短篇，聊以記所佩。"]'),
('5d474c05-12e2-4057-8f97-03c0ba57cf8f','奉和興宗臘日招賓浴普光','韓維','宋','宋诗','song-poetry','','[]','嘉臘世所用，况今以令休。',132,'全唐诗/poet.song.24000.json','["嘉臘世所用，况今以令休。", "吾儕三四人，及辰爲茲游。", "茲游豈其遠，東城大道周。", "松檜寒色靜，臺殿香氣浮。", "振衣聊自潔，舉觴復相酬。", "淡泊顧多思，嘲諧訖無尤。", "京都豪貴兒，良馬輕衣裘。", "飛鷹搏狐兔，馳突明星流。", "歸來擊鮮飲，趙舞間齊謳。", "豈不一時樂，此樂異我求。", "願君勤置酒，簡薄非所羞。"]'),
('d72504b8-67dd-40cd-b76c-83eac96308ff','送宋鈞秀才落第還鄉','韓維','宋','宋诗','song-poetry','','[]','漆雕不肯仕，仲尼悅其然。',108,'全唐诗/poet.song.24000.json','["漆雕不肯仕，仲尼悅其然。", "乃知君子學，躁進非所先。", "去聖邈千載，茲風復誰傳。", "趨營不自反，廉耻一以捐。", "愛君抱沖淡，榮利不可遷。", "讀書本仁義，洞見末與顛。", "失志不爲辱，謀道方復堅。", "臨分求規言，顧我昧所宣。", "願君崇遠業，無愧古人賢。"]'),
('b6d1c283-5d81-463e-82d6-a677d98e9d97','送勾諶太博通判潁州','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖十里波，淥靜過新雨。',72,'全唐诗/poet.song.24000.json','["西湖十里波，淥靜過新雨。", "波間黄白花，繚亂不可數。", "浮舟翳佳樹，凉風生仰俯。", "回顧紅塵人，處身一何苦。", "君子愛民物，在樂思及溥。", "方期推所安，與衆式歌舞。"]'),
('c80ba82d-bfd1-4813-94e8-d34626f0fcef','送陳著作','韓維','宋','宋诗','song-poetry','','[]','高才不沉沒，奮筆動天幄。',96,'全唐诗/poet.song.24000.json','["高才不沉沒，奮筆動天幄。", "古今明治亂，王霸辨醇駁。", "文成數千言，粲若玉就琢。", "拜官諸侯府，千文茲把握。", "過別要我贈，强言慚鄙樸。", "董生崇正義，孫子陷曲學。", "彼其趨舍間，爲道一何邈。", "願君審茲術，名節重山嶽。"]'),
('5b016341-bc11-415b-b237-011b424ec9ed','奉送永州張中樂屯田','韓維','宋','宋诗','song-poetry','','[]','昔年曾讀子厚集，夢寐彼州山水佳。',64,'全唐诗/poet.song.24000.json','["昔年曾讀子厚集，夢寐彼州山水佳。", "循良今慰遠人望，瀟灑仍愜曠士懷。", "樓頭打鼓散群吏，林下啼鳥眠高齋。", "政閒境勝足佳句，好寫大字鎸蒼崖。"]'),
('b25fc064-a06e-4d48-81c9-bf2d8dec00ca','奉同原甫鄆州樂郊','韓維','宋','宋诗','song-poetry','','[]','詩人歌樂郊，以政不以遊。',168,'全唐诗/poet.song.24000.json','["詩人歌樂郊，以政不以遊。", "太守名是地，豈非爲民謀。", "下車布條教，惠愛春風柔。", "丹筆平枉訟，赭衣息奸偷。", "政和歲亦豐，閭里舞且謳。", "及我閑暇時，駕言此淹留。", "雜花艷暄朝，翠竹鮮霜秋。", "有臺下觀漁，有堂前抗侯。", "觴斝既紛錯，管鼓亦喧啾。", "都人從公來，小大畢休休。", "施設苟異此，且爲民所仇。", "臺高池益深，不若墟與丘。", "賢而後能樂，軻言良有由。", "聊書太守意，庶幾來者求。"]'),
('bf60fa8a-5265-44ba-8e38-9115b9f6b67a','答師厚和叔喜病起相招','韓維','宋','宋诗','song-poetry','','[]','韓孟天下好，祝身猶駏蛩。',108,'全唐诗/poet.song.24000.json','["韓孟天下好，祝身猶駏蛩。", "今吾二三友，幸而得相逢。", "如何病在枕，垂見月律窮。", "前日始能杖，氣力微春螽。", "出門候車馬，庶幾子予從。", "忽得連紙詩，爛然亂昏瞳。", "今我謝百事，無著如飛蓬。", "惟知爛漫飲，舍是非所通。", "願君勤貯酒，相期雪翻空。"]'),
('093f6c41-57cc-4143-84f3-e9ebd8163c4c','次韵和原甫遊會靈觀','韓維','宋','宋诗','song-poetry','','[]','松喬去我久，高駕不可攀。',204,'全唐诗/poet.song.24000.json','["松喬去我久，高駕不可攀。", "何意塵外遊，近在王城間。", "先帝昔臨御，抱沖啟玄關。", "營宮奉嶽鎮，縹緲當人寰。", "疏泉抗臺殿，擬迹三神山。", "想像列仙下，半空來佩環。", "雲車倏容與，旄節儼成班。", "翩翾萬玉女，紅頰翠羽鬟。", "世人那得見，石壇空自閑。", "伊予厭羈跼，酷甚負病瘝。", "茲行適所願，帖若賈在闤。", "春風吹園桃，幾日朱霞殷。", "寒碧竹間見，新黄柳際還。", "主人非素期，促具初無艱。", "抗侯角善手，持觴發歡顔。", "尚無形骸累，安問紱與綸。", "跋馬興不盡，東池水潺潺。"]'),
('5e331961-3937-4c04-8eb6-1bf53edc3b9d','答和鄰幾元夕聖俞及予過之','韓維','宋','宋诗','song-poetry','','[]','天衢十二大樹春，樓前結綵移嵩岷。',160,'全唐诗/poet.song.24000.json','["天衢十二大樹春，樓前結綵移嵩岷。", "游人衮衮去不已，街頭雪泥踏作塵。", "駘它館中好古士，紛華過眼輕浮雲。", "早休僕御謝賓客，翛然乞酒邀比鄰。", "杯盤如星下燭案，果以橘柚菹紫蘋。", "微吟疏笑見真野，昔之靖節今冠巾。", "門前少年將姣婦，電落馬足風兩輪。", "長髯健兒走先後，意氣欲無夜與晨。", "瞥然奔過不留迹，肯信亦有端坐人。", "若無吾曹同嗜好，枯槁到死誰嗟嚬。"]'),
('8a81635b-8f73-4047-a4b2-1e077b044a3f','答賀中道燈夕見詒','韓維','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','春風揭屋沙激窗，兀然孤坐如植杠。',176,'全唐诗/poet.song.24000.json','["春風揭屋沙激窗，兀然孤坐如植杠。", "酒昏兩眸澀不視，案上書策徒摐摐。", "獨待高篇恣哦咏，頓覺精銳還軀腔。", "前時官家不禁夜，九衢艷艷燒明釭。", "綵山插天衆樂振，游人肩摩車轂撞。", "君於此時守經籍，直欲行業純不尨。", "想初嘉句落紙際，筆下衮衮來長江。", "我今散懶世味薄，惟於靜者心爲降。", "江翁蕭閑梅老淡，文字酬酢交矛鏦。", "恨無奇麗與鬥角，日策疲馬參其雙。", "能來相從不憚數，與子賦詩傾酒缸。"]'),
('93d3fb06-27ac-4ae2-b1c4-a75119058ddb','和李大鄰幾聖俞及予見過小飲','韓維','宋','宋诗','song-poetry','','[]','朝朝騎馬出，請道所從何。',144,'全唐诗/poet.song.24000.json','["朝朝騎馬出，請道所從何。", "所從親且舊，恩義固匪它。", "京都衆權豪，門戶高軻峨。", "苟無勢利求，安事徒奔波。", "不如過親舊，雖數無嫌訶。", "君家庭館閑，遠在城北阿。", "惟吾二三友，暇日一來過。", "解鞭不肯去，得酒亦已歌。", "况逢春陽始，風力漸柔和。", "浮膏動郊壤，芳萌綴林柯。", "良辰遊不處，爲樂戒蹉跎。", "爛醉窮吾年，十日詎足多。"]'),
('b3a9861b-ba47-44fa-b745-aca4252780e8','和劉郎浴觀音予置酒見貽','韓維','宋','宋诗','song-poetry','','[]','禪關嚴城側，深靚闢華構。',120,'全唐诗/poet.song.24000.json','["禪關嚴城側，深靚闢華構。", "方吾挾書來，值子出杅後。", "欣然出濁酒，談笑坐清晝。", "三四同來人，頗喜出邂逅。", "牽衣起相酌，曾不煩勸侑。", "紛披索潛逃，顧壁恨無竇。", "不謂一樽樂，有踰萬金壽。", "瓶罍忽已竭，餘興不自收。", "走登故人堂，拜敘十年舊。", "夜深躍馬歸，不畏妾婦詬。"]'),
('8bffde0d-38e2-4561-8333-5844d1990549','子張子夏廟同鄰幾聖俞過作','韓維','宋','宋诗','song-poetry','','[]','峨峨道旁廟，庭戶煥丹黝。',120,'全唐诗/poet.song.24000.json','["峨峨道旁廟，庭戶煥丹黝。", "恭聞師商賢，下拜奠卮酒。", "大梁故王都，豪傑所奔走。", "當時多尊榮，死不道人口。", "二君夫何爲，血食獨傳後。", "豈於聖人道，自托致不朽。", "荒墳屹相望，荆棘不盈畝。", "衣冠應作塵，制度復何有。", "得無埋奇書，文字暗科斗。", "懷古意慘淡，春風一搔首。"]'),
('02aaf04a-0b60-4fcb-a664-204b0e4488c6','和聖俞食笋','韓維','宋','宋诗','song-poetry','','[]','犀皮包玉束作斤，有餽爲子盤中珍。',144,'全唐诗/poet.song.24000.json','["犀皮包玉束作斤，有餽爲子盤中珍。", "愛之不欲食客衆，夜密置酒呼其鄰。", "作詩盈紙頗瓌怪，胄出恐是龍之真。", "流涎溢吻極稱詫，兩都無芹吳無蓴。", "念我故園事栽插，獨於此物尤勤勤。", "春芽怒迸地皮裂，採掇入撰無虛晨。", "獨留晚出補林罅，幾日不見長過人。", "新梢秀葉動清景，蔭藉往往鋪吾茵。", "而今安得復致此，腹飽藜莧身埃塵。"]'),
('fece1a05-ba2c-4a8e-8e92-7d2451f70458','和叔惠薺','韓維','宋','宋诗','song-poetry','','[]','君居壓城根，厥産地宜薺。',72,'全唐诗/poet.song.24000.json','["君居壓城根，厥産地宜薺。", "呼兒乘晝暄，培壤露寒翠。", "擷之登盤蔬，藹蔚見春意。", "方其下筯時，絕甘遽吾遺。", "物雖美芹微，意重生芻比。", "苟爲勢利心，千金何足貴。"]'),
('55df35e2-7bab-4508-a4e1-9362f1642f64','同胡江范邵裴二宋司馬飲會靈水軒即席賦以日暮天無雲春風扇微和爲韵得日字','韓維','宋','宋诗','song-poetry','','[]','華軒壓春波，樽酒四座密。',48,'全唐诗/poet.song.24000.json','["華軒壓春波，樽酒四座密。", "柔軟柳間風，舒遲花後日。", "晚色簾捲靜，歡興觴行疾。", "一陪諸英遊，黽勉慚落筆。"]'),
('1131e7f0-6b17-461e-953f-bdd546073290','和如晦遊臨淄園示元明','韓維','宋','宋诗','song-poetry','','[]','平津開館大道西，桃夭杳姹通園蹊。',192,'全唐诗/poet.song.24000.json','["平津開館大道西，桃夭杳姹通園蹊。", "東風入林朱白動，次第裝遍枝高低。", "紅梅最好花正盛，我時往看歸仍携。", "爾來風雨就零謝，忍見踏盡隨春泥。", "廣文先生厭閑冷，投書結伴散馬蹄。", "主人同僚相門出，未肯朝暮甘鹽齏。", "歡然握手喜迎候，促具并走子與妻。", "插芳咀甘不知去，歸舍已見鷄在栖。", "坐揮大句鄙凡近，脫落塵迹登天梯。", "不因時節自娛放，頗置白黑爲愁凄。", "我昏如此漫不省，何異車鼓樂鷃鼷。", "長安綠酒春正美，與子一醉萬事齊。"]'),
('63dc0b33-df4c-4160-baf8-42aaab1666b1','送王二廣淵簽書洛中','韓維','宋','宋诗','song-poetry','','[]','吾嘗登嵩丘，下視伊與洛。',132,'全唐诗/poet.song.24000.json','["吾嘗登嵩丘，下視伊與洛。", "王都一何壯，氣象鬰回礴。", "又聞彼其下，地美民俗樂。", "朱宮待遊幸，窈窕飛觀閣。", "氣交卉木茂，奇艷或可愕。", "清渠碧玉色，左右隨釃鑿。", "丹櫻結春實，紫笋翻夏籜。", "喟予抱幽恨，神往迹屢却。", "羨君署吏去，躍馬春遊薄。", "追遊當及早，勝事不可落。", "爲我謝林岫，終期蹈前約。"]'),
('a547e365-324b-42cf-8577-f839818d2c4a','遊福聖院呈審言諸君','韓維','宋','宋诗','song-poetry','','[]','殘春去無幾，煩暑來已漸。',108,'全唐诗/poet.song.24000.json','["殘春去無幾，煩暑來已漸。", "驅車九衢裏，赤日汗兩臉。", "投身入佛寺，廊殿邃且儼。", "老僧一何賢，爲我拂清簟。", "神輕反無寐，性達非有檢。", "啾啾雀聲閑，悄悄人迹斂。", "却思吾廬下，此樂不爲欠。", "新蘋生明鏡，密笋排翠琰。", "時哉盍旋歸，塵土吾已厭。"]'),
('597d6319-a15a-4c36-8e8f-f503194b073c','上巳','韓維','宋','宋诗','song-poetry','','[]','欄干浮波走長橋，琉璃光中虹動摇。',64,'全唐诗/poet.song.24000.json','["欄干浮波走長橋，琉璃光中虹動摇。", "浪頭畫舸百龍首，鼓聲疊疊來塞慓。", "我欣禊事得壯觀，眼底不顧花飛飄。", "勸君酒到莫浪免，一春佳節惟今朝。"]'),
('6a598d2a-c5e4-4af0-904a-215e78aea9f2','鄰幾和叔飲定力同賦','韓維','宋','宋诗','song-poetry','','[]','城頭片雲黑，飛雨靄已至。',72,'全唐诗/poet.song.24000.json','["城頭片雲黑，飛雨靄已至。", "凉生芳樹顛，影亂樽中翠。", "沈煩忽去體，精銳颯生思。", "江翁發新嘲，陳子抗奇議。", "在言豈多同，於道不爲異。", "夜歸清有餘，微月照連騎。"]'),
('109a3c5c-e353-4b8d-b420-fe2afa486dbc','次道東軒賦惜春','韓維','宋','宋诗','song-poetry','','[]','青春忽已晚，去我劇奔馬。',48,'全唐诗/poet.song.24000.json','["青春忽已晚，去我劇奔馬。", "殘芳已掃園，濃綠空蔽野。", "春風欲有問，對酒不能把。", "人心正如此，狂雨自飛灑。"]'),
('b50154f5-3514-4862-b6fc-bc445bed7f12','同和叔飲王文正公三槐廳呈正卿','韓維','宋','宋诗','song-poetry','','[]','投杯送餘景，休駕避初燠。',96,'全唐诗/poet.song.24000.json','["投杯送餘景，休駕避初燠。", "久嫌花攪心，始愛樹清目。", "主人樂儒學，定契均季叔。", "疏簾翳廣坐，并薦肴與蔌。", "肅肅太尉館，簡儉見遺躅。", "中有戒子篇，慘淡刻寒玉。", "世傳盛德茂，名與清風穆。", "公乎不可見，悵望三槐綠。"]'),
('606269df-be10-48a6-b63d-1c329459c3fe','普安席上作得蔗字','韓維','宋','宋诗','song-poetry','','[]','羞隨輕薄兒，淚眼塵土下。',48,'全唐诗/poet.song.24000.json','["羞隨輕薄兒，淚眼塵土下。", "朅來精舍遊，置酒樂清暇。", "杯盤春物少，惟見杏與蔗。", "流陰足可惜，將子緩歸駕。"]'),
('bd2a8ccd-f190-4ab7-a92d-463bb78b81bb','借馬','韓維','宋','宋诗','song-poetry','','[]','吾生不自勉，無馬以縶羈。',84,'全唐诗/poet.song.24000.json','["吾生不自勉，無馬以縶羈。", "不能徒步遊，鄰里更借之。", "東家號駛疾，出門無停馳。", "西家苦駑緩，百箠足不移。", "驚怪同行客，問我遽爾爲。", "駛也吾撇烈，駑也吾逶遲。", "物情有如此，且當執其隨。"]'),
('e6b6cc35-9a7e-4278-8934-d1e897825868','鄰幾舍對菊無酒','韓維','宋','宋诗','song-poetry','','[]','陶公愛佳節，對菊愁空杯。',48,'全唐诗/poet.song.24000.json','["陶公愛佳節，對菊愁空杯。", "日晏東籬下，竟見白衣來。", "今君亦嗜飲，復有伊人才。", "惜無王江州，黄花徒自開。"]'),
('3a32fb6b-776c-412e-827d-df06bfa726cb','同鄰幾和叔登定力閣','韓維','宋','宋诗','song-poetry','','[]','清風何飄飄，萬里吹曾軒。',72,'全唐诗/poet.song.24000.json','["清風何飄飄，萬里吹曾軒。", "側身紅塵外，却視飛雲根。", "王都屹雄勝，長河中怒奔。", "上有懷歸子，心隨驚浪翻。", "登臨豈非壯，悲傷久客魂。", "日暮下危級，且復同一樽。"]'),
('4cc5a435-71c6-4859-a0c8-e4d89ecff344','鄰幾晚見過小飲','韓維','宋','宋诗','song-poetry','','[]','朝居厭喧呶，暮坐苦幽獨。',84,'全唐诗/poet.song.24000.json','["朝居厭喧呶，暮坐苦幽獨。", "忽聞江翁來，喜視樽中醁。", "所慚升斗微，不足滿君腹。", "强酌良勝無，逡巡怯行速。", "蕭蕭風著樹，慘慘雨昏燭。", "談精幾喪言，道在空擊目。", "此興自不淺，豈要酩酊足。"]'),
('56c6d9e1-ee84-4883-bc82-70147fff8ede','答聖俞設膾示客','韓維','宋','宋诗','song-poetry','','[]','梅侯三年江上居，盤羞慣飽鮆與鱸。',112,'全唐诗/poet.song.24000.json','["梅侯三年江上居，盤羞慣飽鮆與鱸。", "客居京城厭粗糲，買魚斫膾邀朋徒。", "孰親刀匕擅精巧，閨中麗人家本吳。", "縷裁長絲葉剪藿，飣餖自與尋常殊。", "霜橙搗齏飯香稻，一飽豈顧家有無。", "我雖目病興不淺，坐想落紙霏紅腴。", "雕盤雋味儻可再，贈子玉酒隨長魚。"]'),
('873a0cb7-2ed4-400a-9c5a-2db75089b16c','與江梅景德夜歸','韓維','宋','宋诗','song-poetry','','[]','吾交陳與謝，屢結東城遊。',48,'全唐诗/poet.song.24000.json','["吾交陳與謝，屢結東城遊。", "春宵燈火繁，躍馬此道周。", "懷人邈何遠，念歲忽以遒。", "况自抱私感，歸來清淚流。"]'),
('0652019c-3838-496c-a745-42fa0f911d41','答和叔城東尋春','韓維','宋','宋诗','song-poetry','','[]','尋春之何所，乃在城東隅。',204,'全唐诗/poet.song.24000.json','["尋春之何所，乃在城東隅。", "東隅信佳處，名園間精廬。", "時屬積雪霽，田壤墳以蘇。", "雍容二三騎，并轡徐厥驅。", "僕童怪且議，寒野安所娛。", "不知陽和氣，泱漭于空虛。", "仰視孤剎起，突兀疑神扶。", "其下萬華屋，碧瓦魚鱗鋪。", "南行歷亭館，近接棟與櫨。", "陰草含碧色，陽條散紅腴。", "周覽氣象嘉，高步形蹤舒。", "提携上樽酒，饌不過魚蔬。", "爲奉豈非薄，歡至自有餘。", "却思九衢上，車馬何區區。", "紅塵塞兩眼，勢利各有趨。", "雖欲求暇逸，何能幸須臾。", "君勿輕此樂，此樂未易圖。"]'),
('9c9dfcf2-4dda-4b01-ac09-1372dd6abbce','景仁次道齋禮院予與和叔過之值其方飲引去二君以詩見謝三首 答景仁','韓維','宋','宋诗','song-poetry','','[]','自我伏田里，三駕遊上都。',144,'全唐诗/poet.song.24000.json','["自我伏田里，三駕遊上都。", "其誰肯來顧，莫與夫子如。", "久積疏野抱，况茲病薾餘。", "厚意不即報，悁勞在朝晡。", "驅馬寒日中，薄暮到省廬。", "屬聞從衆賢，高會羅盤盂。", "逡巡望華闥，却走不及徐。", "鸞儀與鴻舉，其勢固自殊。", "胡爲枉嘉藻，似欲相牽拏。", "中論十年舊，見許道義徒。", "管鮑久不作，知音幾終初。", "豈敢忘君言，誓將守淳愚。"]'),
('0c4241c3-b166-453f-94de-6db0126c874d','景仁次道齋禮院予與和叔過之值其方飲引去二君以詩見謝三首 答次道 其一','韓維','宋','宋诗','song-poetry','','[]','肅肅奉常署，高門敞天街。',120,'全唐诗/poet.song.24000.json','["肅肅奉常署，高門敞天街。", "群英謹邦祠，先事戒潔齋。", "我時過其舍，值與衆客儕。", "方聞治杯酌，避去禮亦諧。", "愧無孟公名，安使所至懷。", "不知賢豪意，未遽見睍排。", "明日出長篇，正聲謝淫哇。", "如畏明義重，殷勤懼暌乖。", "幾時持筆和，落紙還成揩。", "何以敘繾綣，晨當策疲騧。"]'),
('03cecbec-0238-4c32-bc6c-fc5cb482c76f','景仁次道齋禮院予與和叔過之值其方飲引去二君以詩見謝三首 答次道 其二','韓維','宋','宋诗','song-poetry','','[]','昔予有行邁，辱贈猗蘭辭。',120,'全唐诗/poet.song.24000.json','["昔予有行邁，辱贈猗蘭辭。", "今我復來遊，重貽黄鵠詩。", "蘭以喻芳潔，擷佩正所宜。", "鵠以興翅邈，鸞皇共追隨。", "句成自有法，意厚良不訾。", "投非所當授，乃反駭且疑。", "蘭生深林間，藹然抱幽姿。", "鵠有江海志，孤軒謝羈雌。", "殘折蘭色改，跂尚鵠性悲。", "願君兩置是，逍遥以相期。"]'),
('a4afb4d8-4b6c-4ec3-b9c5-99b14ac6cd40','答呂晦叔見贈','韓維','宋','宋诗','song-poetry','','[]','人情紛言僞，吾道本一純。',84,'全唐诗/poet.song.24000.json','["人情紛言僞，吾道本一純。", "苟爲趨嚮合，不待結約親。", "曰今得夫子，所涉無異津。", "邀我醉華館，正逢雪花春。", "談笑不近俗，文史自娛賓。", "明發枉嘉贈，辭氣玉醴醇。", "三復同心言，雜佩非所珍。"]'),
('f29f0073-8af8-41a5-b767-c350eea15225','同景仁况之諸君遊南園飲梅花下','韓維','宋','宋诗','song-poetry','','[]','茲園曠不涉，寒草忽已芽。',96,'全唐诗/poet.song.24000.json','["茲園曠不涉，寒草忽已芽。", "同遊三四人，及此風景嘉。", "芳梅如我期，朱萼承素華。", "欣然坐其下，偃君初月斜。", "攀條酌醇酒，談笑時一譁。", "歌童雖非妍，清唱凌烟霞。", "人生自有適，豈要外物加。", "興盡復云返，修竹盤昏鴉。"]'),
('bcbca0e9-5b1e-4b9b-908e-008cd0e56499','招景仁飲','韓維','宋','宋诗','song-poetry','','[]','紅薇花拆萱草丹，萬鈴嘉菊重臺蓮。',144,'全唐诗/poet.song.24000.json','["紅薇花拆萱草丹，萬鈴嘉菊重臺蓮。", "問公此時胡不飲，樂有至理須鑽研。", "后夔已遠師曠死，寂寞千載無其傳。", "公窮天數索聖作，坐使綠鬢成華顛。", "屠龍絕藝豈世用，儀鳳至業非公專。", "洛陽有客金石堅，持議不屈難鑱鎸。", "園收獨樂會真率，以勞校逸寧非偏。", "古稱兩忘化於道，此理豈不曠且然。", "折花持酒待公醉，樂至無聲方得全。"]'),
('a7bc8d7b-69ab-4c82-a04e-d35c3e91d3f6','和朱簿對雪','韓維','宋','宋诗','song-poetry','','[]','公堂寂無事，默坐擁重裘。',108,'全唐诗/poet.song.24000.json','["公堂寂無事，默坐擁重裘。", "餘霰竹上集，寒風日颼颼。", "哀鴻不停征，好鳥鳴相求。", "君能於此時，爲我發新謳。", "上言有年慶，幸免刺史憂。", "下言美光景，宜以歡燕酬。", "名園抱城角，亭觀俯清溝。", "松桂有佳色，芳梅朱白稠。", "晨昏儻霽止，當復從君游。"]'),
('1eaa2920-e302-46c3-8d11-22b0a62056d5','置酒湖光亭示幕中諸君','韓維','宋','宋诗','song-poetry','','[]','東風不能和，朔雪屢成晦。',84,'全唐诗/poet.song.24000.json','["東風不能和，朔雪屢成晦。", "置酒高亭上，豁與清景對。", "霏微遠林表，蕭散平湖內。", "稍急征雁群，偏凌舞姝態。", "爲藩昧仁術，撫事增永慨。", "閭閻半無褐，畎畝方興耒。", "幸祈陰沴消，庶卒豐年賚。"]'),
('e1f1e2ae-45ea-4baf-b406-f087bd204484','送朱主簿','韓維','宋','宋诗','song-poetry','','[]','浮舟下東溪，春寒花未遍。',48,'全唐诗/poet.song.24000.json','["浮舟下東溪，春寒花未遍。", "共約征車行，復此華堂餞。", "人事多齟齬，臨分闕芳燕。", "坐想竹間風，雜英紛如霰。"]'),
('fa00e914-aa0e-4739-9bfa-4a79cf77950f','後圃偶成','韓維','宋','宋诗','song-poetry','','[]','氣昏聊止酒，訟簡時閉閣。',48,'全唐诗/poet.song.24000.json','["氣昏聊止酒，訟簡時閉閣。", "池紅落花委，岸綠新蒲合。", "厭暄解重衣，息倦偃清榻。", "永日林下風，山禽響相答。"]'),
('1db7aaa9-e1a0-41e5-8e92-40cdd8bbfa85','寄題黄州德厚庵','韓維','宋','宋诗','song-poetry','','[]','達命斯順受，務德其勉修。',108,'全唐诗/poet.song.24000.json','["達命斯順受，務德其勉修。", "誠己有要道，茲外非所求。", "使君名是庵，可謂善自謀。", "端居若無營，志業日以休。", "心端物自正，化行速如郵。", "野闢歲有獲，庭虛訟無留。", "民俗興禮讓，閭閻息姦偷。", "可以報上恩，可以嗣先猷。", "倘異於此道，則爲是庵羞。"]'),
('ee1e54db-f6c2-42a4-8446-301b1480e343','燕諸生於內集堂作詩以勉之','韓維','宋','宋诗','song-poetry','','[]','濟濟衆君子，庠序之冠冕。',120,'全唐诗/poet.song.24000.json','["濟濟衆君子，庠序之冠冕。", "來燕升我堂，良用慰衰蹇。", "清言屏絲竹，善意陋肴膳。", "茲藩實故國，賢哲世多顯。", "荀陳沒已遠，餘迹竟未踐。", "顧慚爲政久，儒道不加闡。", "雲飛乏孔翠，廟薦闕瑚璉。", "非期寵祿光，或慮志業淺。", "惟天儻有待，在己固當勉。", "臨觴無以侑，相敦在誠善。"]'),
('5015850a-149d-48c9-bdb7-d7d07a820d57','次韵和崔朝散西湖避暑','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','人生苦炎歊，我所得蕭爽。',72,'全唐诗/poet.song.24000.json','["人生苦炎歊，我所得蕭爽。", "喬林無纖穿，好鳥不停響。", "馮軒縱遐矚，萬象歸一掌。", "道心流水閑，世事浮雲往。", "豈同中林士，所樂在膏壤。", "寄語同心人，金鱗當透網。"]'),
('b6c284ce-a6ca-4eee-bbb4-15e8442297fb','和子華兄太素泛舟香菜門','韓維','宋','宋诗','song-poetry','','[]','霜髯照四坐，宛是商顔來。',48,'全唐诗/poet.song.24000.json','["霜髯照四坐，宛是商顔來。", "舟移一水遠，樓對群峰開。", "談笑盡永日，聲利輕浮埃。", "既同剡溪往，亦類稽山回。"]'),
('26895337-1011-4882-81d9-d2a999e3e05b','又絕句','韓維','宋','宋诗','song-poetry','','[]','芙蓉落盡荷葉黄，西風測測梧桐凉。',32,'全唐诗/poet.song.24000.json','["芙蓉落盡荷葉黄，西風測測梧桐凉。", "歲登訟息休吏早，林間獨坐歌還鄉。"]'),
('a84296f8-ee7b-45bd-876c-9f4e9917a027','次韵和君實寄景仁','韓維','宋','宋诗','song-poetry','','[]','予年行七十，惟日就志昏。',240,'全唐诗/poet.song.24000.json','["予年行七十，惟日就志昏。", "雖高鴻鵠舉，尚困鷄鶩喧。", "壯心久已摧，弱羽不得翻。", "每誦少游言，顧慚下澤轅。", "蜀公有高志，謝事久杜門。", "擾擾世俗務，不復掛口論。", "群經雜圖史，擁坐如周垣。", "上談千載故，速若水注盆。", "客來必命酒，左右拱諸孫。", "雖無鼓舞懽，自喜談笑溫。", "仰高顧吾私，有類羝觸藩。", "尚期蓬蓽完，亦有桑榆存。", "近觀敕子詩，尤見朋義敦。", "卜居近吾廬，指日駕君轓。", "構堂始云基，築圃亦已樊。", "前知會合期，不慘離索魂。", "想像入第初，親賓燕華樽。", "談高一理會，體王百疾奔。", "共完天純粹，豈識世詐諼。", "方笑司馬翁，獨樂守空園。"]'),
('0d797441-c16f-46da-8479-34c95d55cd8e','效陶呈景仁','韓維','宋','宋诗','song-poetry','','[]','仲冬景氣和，游步獨徘徊。',72,'全唐诗/poet.song.24000.json','["仲冬景氣和，游步獨徘徊。", "微痾忽消散，我興在尊罍。", "東鄰久廢飲，百勸首不回。", "所憂在鐘律，未致儀鳳來。", "此志豈不佳，孤論良難裁。", "願公少置之，起視甕頭醅。"]'),
('f5af4ed2-6489-49d0-a7b6-381973802995','答梁大夫斷求息緣以躋高蹠兼簡清臣大夫','韓維','宋','宋诗','song-poetry','','["\u7ec8\u5357\u5c71"]','人生會有本，本得求自忘。',96,'全唐诗/poet.song.24000.json','["人生會有本，本得求自忘。", "緣來與之俱，源壯流亦長。", "趨高顧爲下，在得良已亡。", "金仙不吾欺，莊生助之揚。", "嗟我聞道淺，妄言豈非狂。", "緬懷終南山，紫翠峨宮牆。", "二賢謝塵滓，接翼參雲翔。", "相望孰云遠，共此愛日光。"]'),
('ead3bc70-6ac6-4cbd-9f64-a19969d46805','和朱少府','韓維','宋','宋诗','song-poetry','','[]','自我還故棲，再見炎與凉。',120,'全唐诗/poet.song.24000.json','["自我還故棲，再見炎與凉。", "朝游每含哺，晝坐常焚香。", "擷圃得奇艷，俯池鑒清光。", "不憂饑所驅，非爲飽則颺。", "同里四三人，每過必命觴。", "濁醪無孤斟，嘉果有新嘗。", "看舞雪翻席，度曲塵飛梁。", "桑榆儻徘徊，此樂未渠央。", "行止固有命，貴棄乃其常。", "與君酣且歌，幸世方歡康。"]'),
('920e5a61-c3b7-44fa-af91-521fb29f68b9','次韵和景仁兄','韓維','宋','宋诗','song-poetry','','[]','既酬斯有酢，在禮猶可追。',48,'全唐诗/poet.song.24000.json','["既酬斯有酢，在禮猶可追。", "起勸孰曰狂，狂在捉白髭。", "白髭雖見捉，淥酒安可辭。", "歌童小如拳，聊以開公眉。"]'),
('77d30bb9-1ccf-4f57-bf1c-1a58c83e514d','次韵答景仁喜雨','韓維','宋','宋诗','song-poetry','','[]','凉雲四向復，沴氣一消沉。',48,'全唐诗/poet.song.24000.json','["凉雲四向復，沴氣一消沉。", "上天垂景貺，高秋霑喜霖。", "槁苗變新實，時菊抽芳心。", "聆君得意句，起我掉頭吟。"]'),
('a06a5da5-bb08-446e-9b20-c353b6209e7e','令綽泛舟潩河作詩詒之','韓維','宋','宋诗','song-poetry','','[]','投閑歸里閭，幸與故人遇。',108,'全唐诗/poet.song.24000.json','["投閑歸里閭，幸與故人遇。", "情期夙所敦，邀迓已去屢。", "尚嫌城闕拘，未盡林壑趣。", "導河高其梁，輕舟具指顧。", "寒花黄被堤，秋實翠登俎。", "白鬚二三翁，相對無俗語。", "夷猶起遐想，恬曠絕近慕。", "適野詎有謀，登高亦非賦。", "信哉莊生言，忘我带與履。"]'),
('4e278572-7f8b-4afc-83f1-b92a4f160152','景仁示去歲所賦菊屏菊塔二詩輒以一篇答之','韓維','宋','宋诗','song-poetry','','[]','斯民去古遠，日與巧僞遷。',72,'全唐诗/poet.song.24000.json','["斯民去古遠，日與巧僞遷。", "粲粲黄金花，揉屈同杯棬。", "列屏聳浮圖，光彩生盤筵。", "匪惟悅群兒，愛咏及華顛。", "我欲叱園史，解結除其編。", "萬物有本性，各使歸自然。"]'),
('1da61a38-04fd-4011-aabb-156d7e466fca','對雨獨酌','韓維','宋','宋诗','song-poetry','','[]','褰簾雨正繁，附火寒已薄。',48,'全唐诗/poet.song.24000.json','["褰簾雨正繁，附火寒已薄。", "修竹摇清音，芳梅綻朱萼。", "感此時運駛，對酒成獨酌。", "多謝枝上禽，飛鳴慰寂寞。"]'),
('e5d1f387-ab2c-4054-a995-1da0325995ea','和玉汝弟感秋偶書','韓維','宋','宋诗','song-poetry','','[]','園林雨餘清，碧色遍秋草。',108,'全唐诗/poet.song.24000.json','["園林雨餘清，碧色遍秋草。", "露葉委閑階，風荷亂幽沼。", "晨昏爽氣嘉，吾意欲輕矯。", "古來達道者，冥冥獨見曉。", "四序雖代換，一物未嘗老。", "况茲浮幼質，終非智人保。", "唯有至真界，日日無非好。", "豈同世俗情，妄計遲與早。", "矢詩勿庸多，萬事一能了。"]'),
('65c88502-2143-48bf-9a2f-ba787dcfdce0','題巽亭','韓維','宋','宋诗','song-poetry','','[]','薄陰散秋曦，爽氣來孟月。',120,'全唐诗/poet.song.24000.json','["薄陰散秋曦，爽氣來孟月。", "慨然登茲亭，嘉觀非遠涉。", "徑幽出深竹，棧峻躋危堞。", "身騰塵境外，心與空界接。", "前臨潩波泛，却視隗峰列。", "來遠得清飈，灑迥想飛雪。", "君家兄弟賢，問學繼先業。", "橫經咨老師，置醴延大耋。", "方從賢者樂，豈爲游子設。", "詩人亦有言，佻達在城闕。"]'),
('9befdb7b-ed46-4e95-b080-ee5fcaf1f0c5','和景仁除夜','韓維','宋','宋诗','song-poetry','','[]','六十復過六，逐物何當足。',48,'全唐诗/poet.song.24000.json','["六十復過六，逐物何當足。", "善惡兩都忘，寧論擇魚肉。", "流光速於電，至道明如燭。", "孰謂吾廬卑，隨時自凉燠。"]'),
('042f0506-f9f8-48ea-b073-93bcd7c0ccf2','奉酬樂道','韓維','宋','宋诗','song-poetry','','[]','故人從我遊，里閈非瀟湘。',120,'全唐诗/poet.song.24000.json','["故人從我遊，里閈非瀟湘。", "文章老益壯，欲掩李杜光。", "新詩來連翩，奔走獲與臧。", "調高豈能繼，愛重如琳琅。", "春風動地來，急雨催群芳。", "梅蕊亦已落，坐看飛絮狂。", "誰能於此時，默默但退藏。", "且傾杯中物，莫顧腰下章。", "緩舞金縷衣，高歌玉爐香。", "白頭自有樂，豈愧少年場。"]'),
('6dfa3d79-e45f-49b1-b9dc-6ef5819a2426','次韵奉答君實問禪','韓維','宋','宋诗','song-poetry','','[]','仲尼稱無我，老氏貴不仁。',48,'全唐诗/poet.song.24000.json','["仲尼稱無我，老氏貴不仁。", "存心一鄰虛，去道萬由旬。", "入俗權立聖，達空安取真。", "摩詰非有法，還公本來人。"]'),
('c3487db5-d717-41cd-92d6-298699adeb9e','答李先生','韓維','宋','宋诗','song-poetry','','[]','衆人張眼，我視明明。',112,'全唐诗/poet.song.24000.json','["衆人張眼，我視明明。", "衆人開口，我笑泠泠。", "百姓不我知，我與同醉醒。", "惟有北庵李家老，足智解語通人情。", "恐物盜我本真處，勸我閉口藏眼睛。", "翁意我甚愧，我語翁亦聽。", "萬物不是賊，我家門畜停。", "我勸李老莫憂驚，詐稱强盜國有刑，太守行令當不輕。"]'),
('24301b11-94d6-4a15-9dd4-4fa4aa6c5134','次韵答和樂道侍讀給事','韓維','宋','宋诗','song-poetry','','[]','歲豐訟滋簡，拙守容晏眠。',228,'全唐诗/poet.song.24000.json','["歲豐訟滋簡，拙守容晏眠。", "起來視雲景，春意亦已鮮。", "驅車望南城，精廬屹當前。", "華堂坐沈邃，遲日步暄妍。", "流覽高僧壁，稽首金像蓮。", "即事豈非適，感懷良慨然。", "宮藩與鄉閈，早接二公賢。", "高文炳群宿，大論傾長川。", "爾來曾幾時，急景凋朱顔。", "從容味真理，蕭灑賦高篇。", "豈無安民策，坐惜成棄捐。", "尚期雅正音，入和薰風弦。", "余本巖壑姿，臺閣繆見延。", "淵明亦有言，誤落塵網間。", "命固有行止，理非可控搏。", "素髪紛已垂，行當掛吾冠。", "側聞治林圃，栽插及晴天。", "芳芽吐膏壤，柔條擢暖烟。", "光景非我力，爲君導鳴泉。"]'),
('876b246f-efe1-4114-b00f-4e8f914f9ca3','次韵謝尉公靖同遊北園五首  其一','韓維','宋','宋诗','song-poetry','','[]','我本巖壑人，何意裨衮闕。',48,'全唐诗/poet.song.24000.json','["我本巖壑人，何意裨衮闕。", "一從譴逐歸，林下聊散髪。", "步堤得幽花，照水見新月。", "即此窮朝曛，平夷免歌蹶。"]'),
('c3ff0a56-34ea-4cb2-b0c4-942695a30afd','次韵謝尉公靖同遊北園五首  其二','韓維','宋','宋诗','song-poetry','','[]','陰陰喬木交，竦竦修竹翠。',48,'全唐诗/poet.song.24000.json','["陰陰喬木交，竦竦修竹翠。", "黄花與丹實，夾路何瑣細。", "是辰雨新足，支策問田事。", "一感孤征鴻，淚落衣襟際。"]'),
('8a7ad953-c9c8-41e0-bf5b-3d5d92ca163d','次韵謝尉公靖同遊北園五首  其三','韓維','宋','宋诗','song-poetry','','[]','鑿堤要水近，依竹任逕斜。',48,'全唐诗/poet.song.24000.json','["鑿堤要水近，依竹任逕斜。", "殘葉時委地，晚笋猶穿沙。", "不知人間世，况論空中花。", "却思城市喧，閣閣鳴群蛙。"]'),
('d66cbca2-b17c-48ad-8bbd-f8d7248fe97d','次韵謝尉公靖同遊北園五首  其四','韓維','宋','宋诗','song-poetry','','[]','今茲冬已孟，青林猶蔽野。',48,'全唐诗/poet.song.24000.json','["今茲冬已孟，青林猶蔽野。", "愛此晴景嘉，置酒衡茅下。", "緬思陶公句，異代同瀟灑。", "結廬在人境，而無車與馬。"]'),
('fb5e4dc4-5228-46a5-91db-d31c25b8cc12','次韵謝尉公靖同遊北園五首  其五','韓維','宋','宋诗','song-poetry','','[]','九夏困炎毒，出門如探湯。',48,'全唐诗/poet.song.24000.json','["九夏困炎毒，出門如探湯。", "不知此幽亭，俯仰皆清光。", "寒流給我濯，白雲供我望。", "况有尊中酒，猶泛殘菊香。"]'),
('14414ab5-6b57-4dc8-81d8-1e3a23610db0','奉和太素見詒','韓維','宋','宋诗','song-poetry','','[]','幸有新醪對新菊，莫嘆樽前光景促。',32,'全唐诗/poet.song.24000.json','["幸有新醪對新菊，莫嘆樽前光景促。", "請公更唱自爲詞，緩奏金絲續銀燭。"]'),
('46ad0476-a0ba-4463-b3f7-22dde98893d4','寄秦川馬從事','韓維','宋','宋诗','song-poetry','','[]','往歲遊西謁季長，隴雲秦樹勝風光。',64,'全唐诗/poet.song.24000.json','["往歲遊西謁季長，隴雲秦樹勝風光。", "分題紅葉蠻牋膩，對舉流霞綵袖香。", "宴洽翠娥連象榻，夜寒嬌鳳泥銀黄。", "未知早晚重携手，惆悵而今鬢已蒼。"]'),
('e67e16ea-5b04-43cf-b76a-f4794081b03a','春霽憶洛陽','韓維','宋','宋诗','song-poetry','','[]','少年結客洛陽時，閑傍東風駐馬蹄。',64,'全唐诗/poet.song.24000.json','["少年結客洛陽時，閑傍東風駐馬蹄。", "山色遠饒潘岳宅，波光輕撼窈娘堤。", "花繁到處紅如堵，酒好尋常醉似泥。", "頼有金臺舊知己，應憐魂斷虎牢西。"]'),
('0da81067-78b2-4de0-8d90-9924181eb677','雲','韓維','宋','宋诗','song-poetry','','[]','抱石情雖久，爲霖意若何。',48,'全唐诗/poet.song.24000.json','["抱石情雖久，爲霖意若何。", "天心如見用，風力不消多。", "冷濕朝仙洞，寒迷宿鳥窠。", "飛揚終得路，曾入漢皇歌。"]'),
('c2e1c9e7-4936-4766-9021-5ee20d1e5453','雪','韓維','宋','宋诗','song-poetry','','[]','屏翳驅雲結夜陰，素華飄墮惡氛沈。',64,'全唐诗/poet.song.24000.json','["屏翳驅雲結夜陰，素華飄墮惡氛沈。", "色欺曹國麻衣淺，寒入荆王翠被深。", "天上明河銀作水，海中仙樹玉成林。", "日高獨擁鸘裘卧，誰乞長安取酒金。"]'),
('2e89abd9-71e3-436e-b31d-e6bf781086fd','東郊','韓維','宋','宋诗','song-poetry','','[]','東郊絲雨破浮埃，繡騎尋芳兩兩來。',64,'全唐诗/poet.song.24000.json','["東郊絲雨破浮埃，繡騎尋芳兩兩來。", "十畝霜陰青翳目，一篙溪色碧於苔。", "林花泛日鶑求友，壠麥含風雉應媒。", "綠柳朱欄多酒市，杖頭誰伴玉山頹。"]'),
('40ef1ebb-ea23-41bb-968d-52f618f24038','春朝','韓維','宋','宋诗','song-poetry','','[]','燕語聞多日，蠶眠過幾宵。',48,'全唐诗/poet.song.24000.json','["燕語聞多日，蠶眠過幾宵。", "花深不辨蝶，柳暗欲迷橋。", "便面金環重，障泥玉勒驕。", "黄公酒壚上，誰貰阮孚貂。"]'),
('2cbd1e22-b6f9-4233-a20e-df4278ef43da','晚春','韓維','宋','宋诗','song-poetry','','[]','春暉東去月如弦，却拂凝埃敞北軒。',64,'全唐诗/poet.song.24000.json','["春暉東去月如弦，却拂凝埃敞北軒。", "幾曲雲屏空白晝，一簾花雨自黄昏。", "庭蕪碧合陰蟲息，窗樹紅稀鬥雀喧。", "細憶舊歡都入夢，習家池上子山園。"]'),
('85c3e619-1daa-4b28-bd9b-5b29a2b4d03c','題余山人壁','韓維','宋','宋诗','song-poetry','','[]','一室閉香林，蕭然物外心。',48,'全唐诗/poet.song.24000.json','["一室閉香林，蕭然物外心。", "棋聲敲月重，屐齒印苔深。", "竹徑茶烟細，山園鍛樹陰。", "會當逃世網，塵事締朋簪。"]'),
('d1fd1097-d578-4f2c-bc15-9d585e2722f0','水閣','韓維','宋','宋诗','song-poetry','','[]','約略橫雲島，欄干瞰玉淵。',48,'全唐诗/poet.song.24000.json','["約略橫雲島，欄干瞰玉淵。", "雨汀翹睡鷺，風樹咽嘶蟬。", "綠髪莓苔地，紅衣菡萏天。", "夜深三弄笛，月在釣魚船。"]'),
('e406f76a-83b5-46d9-89e2-1115300bda46','戲月','韓維','宋','宋诗','song-poetry','','[]','缺處還孤守，圓時亦獨棲。',48,'全唐诗/poet.song.24000.json','["缺處還孤守，圓時亦獨棲。", "何曾聞合璧，只見是如珪。", "桂子遺秋信，方諸寄夜啼。", "建章殘漏促，又伴玉繩低。"]'),
('c81ea67b-5509-411c-a6ec-5a20aad44377','和曼叔','韓維','宋','宋诗','song-poetry','','[]','官路飄蓬奈別何，塞垣相見此情多。',64,'全唐诗/poet.song.24000.json','["官路飄蓬奈別何，塞垣相見此情多。", "酒樽重喜爲親壽，華髪猶能繼子歌。", "行樹坐思新種色，斷冰應泛晚來波。", "紫荆山下游從少，獨把雕章醉後哦。"]'),
('5f700aae-684c-447e-b454-00d7e5a75396','長安留別七弟兼簡劉郎','韓維','宋','宋诗','song-poetry','','[]','二年牢落坐回山，平日交親夢寐間。',64,'全唐诗/poet.song.24000.json','["二年牢落坐回山，平日交親夢寐間。", "關外相逢非素約，樽前一笑慰衰顔。", "匡衡沿牒朝廷遠，王粲從軍幕府閒。", "跋馬題詩離緒亂，霜風蕭颯鬢毛班。"]'),
('a54c2799-2c1d-49b9-990c-8560e72689a0','和原甫見送','韓維','宋','宋诗','song-poetry','','[]','德義良所慕，風霜輕此行。',48,'全唐诗/poet.song.24000.json','["德義良所慕，風霜輕此行。", "放歌留客醉，高咏見公情。", "祖帳重開席，郊原少駐旌。", "還知別後意，寂寞對柴扃。"]'),
('a5cb4bf3-3029-4d67-a7d2-e0d2a4942a3e','送呂寺丞','韓維','宋','宋诗','song-poetry','','[]','古有從軍樂，人今衣綵行。',48,'全唐诗/poet.song.24000.json','["古有從軍樂，人今衣綵行。", "春風騏驥健，朝日鳳凰鳴。", "樹遠秦中道，花繁塞下城。", "篇章聞舊俗，當爲放遺聲。"]'),
('c83bae78-a8a5-4b30-8196-dc5cd71daf1d','元日寄袁州仲文兄','韓維','宋','宋诗','song-poetry','','[]','前日都門盡鷁飛，秋風執別淚交頤。',64,'全唐诗/poet.song.24000.json','["前日都門盡鷁飛，秋風執別淚交頤。", "清朝遠謫庸非命，直道終申自有時。", "佳句應因子卿賦，勝遊仍共鶺鴒期。", "宜春臺上春歸早，誰伴花前酒一卮。"]'),
('f62b40a3-164a-42a0-819b-da4a4e682a63','九月十日遊象之葆光亭寄曼叔','韓維','宋','宋诗','song-poetry','','[]','幾負高陽約，蹉跎此歲華。',48,'全唐诗/poet.song.24000.json','["幾負高陽約，蹉跎此歲華。", "論心看翠竹，感事對黄花。", "寒日悽征雁，清霜急暮鴉。", "臨風一樽酒，回首意無涯。"]'),
('576cce6a-15ba-4ede-bf72-ff53c09875ca','送戴處士還盧州','韓維','宋','宋诗','song-poetry','','[]','早識浮生妄，欣陪達士遊。',48,'全唐诗/poet.song.24000.json','["早識浮生妄，欣陪達士遊。", "觀心非本有，於法尚何求。", "煮茗林間寺，題詩湖上舟。", "還嗟別後夜，風雪擁貂裘。"]'),
('23825c37-3091-4509-919d-df265119800c','同子華仲連二兄遊湖','韓維','宋','宋诗','song-poetry','','[]','濁酒非陶令，方池似習家。',48,'全唐诗/poet.song.24000.json','["濁酒非陶令，方池似習家。", "放舡風動柳，著岸水涵花。", "對影情無極，高歌興轉賒。", "群鳥思共濟，何必問仙槎。"]'),
('4ea6261d-04d9-47f4-b199-0673c8d5f997','象之席上賦得寒字','韓維','宋','宋诗','song-poetry','','[]','愛子林亭勝，高秋駐馬鞍。',48,'全唐诗/poet.song.24000.json','["愛子林亭勝，高秋駐馬鞍。", "梨紅先著露，竹碧自生寒。", "慘戚傷多事，淹留强一歡。", "所嗟怯杯酌，不得倒吾冠。"]'),
('acb3ed82-53d6-4a93-af90-8f4d1dd1567e','同曼叔化光遊卞氏園','韓維','宋','宋诗','song-poetry','','[]','野圃無人到，秋風共子行。',48,'全唐诗/poet.song.24000.json','["野圃無人到，秋風共子行。", "花臨流水落，草上廢臺生。", "氣晚才看菊，天寒不見鶑。", "幽閑固多味，濁酒詎須傾。"]'),
('d3df40fa-c7a9-4c79-a2e7-1cca1683986a','和晏相公答張提刑州名詩三首 頌聖','韓維','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','文德綏中夏，威靈鎮遠夷。',48,'全唐诗/poet.song.24000.json','["文德綏中夏，威靈鎮遠夷。", "恩靈滄海潤，基業泰山維。", "漢曲白麟應，虞韶丹鳳儀。", "僞儒蒙景化，鼓舞慶淳熙。"]'),
('bcabff21-dbcb-462e-82dd-6dac6d8d7520','和晏相公答張提刑州名詩三首 講德','韓維','宋','宋诗','song-poetry','','[]','上德欽明代，中階翊亮司。',48,'全唐诗/poet.song.24000.json','["上德欽明代，中階翊亮司。", "夔龍曜勛業，鸞鳳肅威儀。", "復古高文麗，爲邦惠化綏。", "還當奉侯瑞，歸輔太平基。"]'),
('24f7d376-dd2d-4afe-995f-ff1546a77190','和晏相公答張提刑州名詩三首 陳情','韓維','宋','宋诗','song-poetry','','[]','濠上蒙莊達，田中彭澤歸。',48,'全唐诗/poet.song.24000.json','["濠上蒙莊達，田中彭澤歸。", "安能陳道德，直可景光輝。", "欣奉燕臺集，恭陪漢相威。", "陽春回麗曲，清越滿金徽。"]'),
('d07c58c3-4dc6-492a-aacf-24f88face811','西湖雨中同公懿諸君飲','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十月平湖上，繁霜藻荇空。',48,'全唐诗/poet.song.24000.json','["十月平湖上，繁霜藻荇空。", "柳枝橫墮雨，波白細生風。", "水鳥飛幽碧，寒花折淺紅。", "誰能盡一醉，燈火宿船篷。"]'),
('7b0cc016-da32-4518-b5c3-6a187800d914','答臨淄公見招','韓維','宋','宋诗','song-poetry','','[]','帝思元老付關西，公受兵符與命圭。',64,'全唐诗/poet.song.24000.json','["帝思元老付關西，公受兵符與命圭。", "應識疲羸須鎮撫，便期愚散豫招携。", "漢家宮殿看龍首，秦地山川入馬蹄。", "自愧不才多病者，空哦嘉句滯幽棲。"]'),
('fad8ab0c-4098-4732-8d93-c7f6a7f0741b','獨坐','韓維','宋','宋诗','song-poetry','','[]','雪屋生寒勁，風燈落燼頻。',48,'全唐诗/poet.song.24000.json','["雪屋生寒勁，風燈落燼頻。", "驚號獨過雁，默坐未眠人。", "世事存傷沒，年華故換新。", "還將寂寞意，强與凍醪親。"]'),
('359003ef-8310-4ea7-9ba5-f989cf4a8250','過卞氏園亭','韓維','宋','宋诗','song-poetry','','[]','桃李郊扉靜，東風拂面柔。',48,'全唐诗/poet.song.24000.json','["桃李郊扉靜，東風拂面柔。", "偶陪連騎客，來作探春遊。", "斜日池邊樹，輕雲城上樓。", "不須花艷動，一醉且淹留。"]'),
('5e54dc79-0890-44bf-835f-353a30caf811','西軒會中與辛楊諸君同賦','韓維','宋','宋诗','song-poetry','','[]','一笑聊爲適，非關事賞心。',48,'全唐诗/poet.song.24000.json','["一笑聊爲適，非關事賞心。", "芳菲逐風盡，時序感人深。", "世事無多問，香醪且細斟。", "更須乘月色，瀟灑坐中林。"]'),
('ef5f6d64-59fe-4e0a-882a-7619534ac288','再遊卞氏園亭','韓維','宋','宋诗','song-poetry','','[]','多謝春風意，殘芳得我遊。',48,'全唐诗/poet.song.24000.json','["多謝春風意，殘芳得我遊。", "綠陰人去遠，翠竹鳥啼幽。", "醉舞紛無次，狂歌漫不收。", "林間簇車馬，欲去尚遲留。"]'),
('46e494af-c69f-4fa2-88e2-975e228b19d3','象之以山藥見贈','韓維','宋','宋诗','song-poetry','','[]','龍山有遊客，贈藥滿筠籠。',48,'全唐诗/poet.song.24000.json','["龍山有遊客，贈藥滿筠籠。", "葉漬沙泉碧，苗分石竇紅。", "斸應侵曉露，來喜及春風。", "却笑丹砂遠，卒勤勾漏翁。"]'),
('eeb0f96a-e12c-4c57-96bc-384b4e904145','和象之同孔寧極遊石橋且簡寧極','韓維','宋','宋诗','song-poetry','','[]','春風杖藜客，同到石橋邊。',180,'全唐诗/poet.song.24000.json','["春風杖藜客，同到石橋邊。", "引袖披雲木，携樽俯澗泉。", "巖花聊採摘，野器不雕鎸。", "俯仰元和內，熙恬太古前。", "草心柔可綰，蒲葉密于編。", "澗麀來窺坐，沙鷗不改眠。", "濛濛桃李雨，冪冪薜蘿烟。", "舞類雩祠日，吟非楚澤年。", "魚跳聞急管，鳥語似幺弦。", "紫翠羞薇蕨，清香襲蕙荃。", "亂流時揭厲，微逕巧縈穿。", "德義心誠服，山林性所便。", "敢令然諾負，直以事爲牽。", "圯下履終跪，溱邊裳且褰。", "春醪可益釀，况有帛戔戔。"]'),
('e390972b-0ac3-4b5b-87ae-e85a3deb2d6b','晏相公湖上泛舟賦','韓維','宋','宋诗','song-poetry','','[]','小雪未成寒，平湖好放船。',48,'全唐诗/poet.song.24000.json','["小雪未成寒，平湖好放船。", "水光宜落日，人意喜晴天。", "雲薄翠微外，禽歸莽蒼前。", "上公寬禮數，清醉亦陶然。"]'),
('fe2758b2-c3be-4ea2-b5c3-9e4bbf32af05','城西二首  其一','韓維','宋','宋诗','song-poetry','','[]','繡鞅金羈十里塵，共傳恩詔樂芳辰。',64,'全唐诗/poet.song.24000.json','["繡鞅金羈十里塵，共傳恩詔樂芳辰。", "千重翠木開珍圃，百尺朱樓壓寶津。", "御麥初長遮雊雉，宮花未識駭遊人。", "自憐窮僻看山眼，來對天池禁籞春。"]'),
('c828f4e2-d1f1-4d62-ba59-3ebb5c33019a','城西二首  其二','韓維','宋','宋诗','song-poetry','','[]','西城馳道直如弦，百頃晴波御柳邊。',64,'全唐诗/poet.song.24000.json','["西城馳道直如弦，百頃晴波御柳邊。", "韶樂鏗轟羅帳殿，春旗偃蹇近樓船。", "曲江未賜唐家燕，靈沼空思鎬邑篇。", "幾日金輿下閶闔，魚龍奇戲出中淵。"]'),
('e6f1691b-0ba5-4260-804a-eb2ac67a04d7','和仲連兄城上晚步','韓維','宋','宋诗','song-poetry','','[]','久積端居滯，聊爲散步游。',48,'全唐诗/poet.song.24000.json','["久積端居滯，聊爲散步游。", "青苔跳怒黽，綠樹矯鳴鳩。", "雨暗橫舟浦，凉生調角樓。", "不妨乘晚興，更盡水西頭。"]'),
('fd1499ca-ddb2-471c-a144-60cd17402fd1','和象之北軒書事','韓維','宋','宋诗','song-poetry','','[]','舍北多嘉樹，重陰及四鄰。',48,'全唐诗/poet.song.24000.json','["舍北多嘉樹，重陰及四鄰。", "清風常滿竹，好鳥不驚人。", "圖史無它物，謳吟佚此身。", "應容千里客，一醉倒冠巾。"]'),
('3766e835-9bf9-4c24-8493-e01e12ee3c58','久雨奉懷象之九兄','韓維','宋','宋诗','song-poetry','','[]','蕭灑崔居士，高閑養性靈。',48,'全唐诗/poet.song.24000.json','["蕭灑崔居士，高閑養性靈。", "凉風滿樽酒，永日一函經。", "竹色垂遮戶，桐花開滿庭。", "未嗟相見闊，交照本忘形。"]'),
('7a693220-5ef4-49a7-a73a-2204f101dea4','同士則遊西湖','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','今日西湖好，來遊未覺喧。',48,'全唐诗/poet.song.24000.json','["今日西湖好，來遊未覺喧。", "柳枝風處亂，花艷暖中繁。", "橋遠歸人渡，舟移集鳥翻。", "何須更樽酒，道勝有清言。"]'),
('45518b96-3036-4d26-9e24-8216ec2489d0','和象之河上見懷之作','韓維','宋','宋诗','song-poetry','','[]','一昨芳郊祖畫輪，索居南北對殘春。',64,'全唐诗/poet.song.24000.json','["一昨芳郊祖畫輪，索居南北對殘春。", "忽傳河上相望意，未覺庵中獨處人。", "幾有高懷投紱冕，尚緣微祿走風塵。", "世間萬事徒勞耳，清潁歸來理釣綸。"]'),
('fc939ed7-923d-47ee-9f5a-4bfe1921f63f','謁晁大夫廟','韓維','宋','宋诗','song-poetry','','[]','春草空庭綠，無人燕自飛。',48,'全唐诗/poet.song.24000.json','["春草空庭綠，無人燕自飛。", "英魂傳廟食，遺像儼朝衣。", "弊大謀何卒，才高禍所歸。", "空令策畫士，千古鑒危機。"]'),
('95333ff1-cb59-4e0d-acb5-89860434f74b','暮春遊卞氏園','韓維','宋','宋诗','song-poetry','','[]','路出清陰下，殘花著馬蹄。',48,'全唐诗/poet.song.24000.json','["路出清陰下，殘花著馬蹄。", "過城春水靜，度墅野橋低。", "池廢青蘋合，林深綠笋齊。", "流鶑知我恨，落日再三啼。"]'),
('4b5a753b-b480-44ab-a063-89463fab9a88','遊象之葆光亭因以寄之','韓維','宋','宋诗','song-poetry','','[]','東亭不到久，雙桂長新梢。',48,'全唐诗/poet.song.24000.json','["東亭不到久，雙桂長新梢。", "窗靜蟲收網，檐低燕護巢。", "晚花紅自照，繁笋翠相交。", "清景成虛委，知君嘆繫匏。"]'),
('4ba67765-0bcb-4fbc-863d-823c41e867da','西軒雨中期象之夜話','韓維','宋','宋诗','song-poetry','','[]','積雨空堂暮，清宵獨掩門。',48,'全唐诗/poet.song.24000.json','["積雨空堂暮，清宵獨掩門。", "陳編徒自對，幽興欲何言。", "碧草生牆角，丹花發竹根。", "聊持靜者轍，一與道人論。"]'),
('2843ce79-ea56-4ec1-b501-2b3b787468a6','晚過象之葆光亭戲呈一首','韓維','宋','宋诗','song-poetry','','[]','蕭灑崔家宅，重門一逕通。',48,'全唐诗/poet.song.24000.json','["蕭灑崔家宅，重門一逕通。", "竹烟虛晚碧，花雨重秋紅。", "傲睨憐苔石，徘徊俯桂叢。", "自期新月色，不爲主人翁。"]'),
('b0451d94-124a-4b4d-a359-6ba00c78e3c6','送休上人之荆門玉泉寺','韓維','宋','宋诗','song-poetry','','[]','憐師真達者，於世了無求。',48,'全唐诗/poet.song.24000.json','["憐師真達者，於世了無求。", "萬事漚起滅，一身雲去留。", "樓臺金地古，風雨玉泉秋。", "安得超塵網，相從物外遊。"]'),
('da944d6b-0e48-43ec-961b-9722abbe33b0','遊龍興寺','韓維','宋','宋诗','song-poetry','','[]','空庭落葉赤，聯步得幽尋。',48,'全唐诗/poet.song.24000.json','["空庭落葉赤，聯步得幽尋。", "蘚剝殘碑字，塵昏古象金。", "菊烟凄晚秀，松日淡秋陰。", "南陌風埃滿，禪關只自深。"]'),
('eb26bb5d-b53d-46af-a52f-740a73a93c4e','飲方君舍晚歸','韓維','宋','宋诗','song-poetry','','[]','慘淡秋原思，歸鞍暮向城。',48,'全唐诗/poet.song.24000.json','["慘淡秋原思，歸鞍暮向城。", "野風吹酒散，寒日上衣明。", "躑躅樵兒聚，喧呼獵騎輕。", "村醪處處熟，准擬數來行。"]'),
('dad0397e-2925-457d-9ba3-c0b5be151ed6','謁漢高帝廟','韓維','宋','宋诗','song-poetry','','[]','魂魄應遊沛，空嗟廟貌殘。',48,'全唐诗/poet.song.24000.json','["魂魄應遊沛，空嗟廟貌殘。", "蒼碑火剝裂，畫壁雨闌干。", "帳幙虛風肅，松槐白日寒。", "陞堂欲進拜，猶怯戴儒冠。"]'),
('f2f0c5cf-dced-457a-af86-fe76ef6dab81','雨過化光西齋','韓維','宋','宋诗','song-poetry','','[]','華屋衡茅接，閑門杖屨通。',48,'全唐诗/poet.song.24000.json','["華屋衡茅接，閑門杖屨通。", "客來非載酒，君坐正書空。", "白菊晚霜後，青蔬寒雨中。", "從今日無事，來聽竹窗風。"]'),
('7fac1aac-1c4d-47f9-9e6e-8955fd0e82ab','潁橋會曼叔坐中寫呈','韓維','宋','宋诗','song-poetry','','[]','朔雪清初霽，風生翠柏陰。',48,'全唐诗/poet.song.24000.json','["朔雪清初霽，風生翠柏陰。", "星辰寒殿近，燈火夜堂深。", "坐愛溫爐密，歡從濁酒斟。", "何當老吾里，杖屨日相尋。"]'),
('66d50922-5628-4b07-a990-a194e2ba1638','坐中呈寧極','韓維','宋','宋诗','song-poetry','','[]','歸馬繫庭柏，張燈開酒樽。',48,'全唐诗/poet.song.24000.json','["歸馬繫庭柏，張燈開酒樽。", "留連遥夜飲，款曲故人言。", "清笑非無適，長歌未覺喧。", "它時相望意，雪屋倚雲根。"]'),
('aa722fdf-cf5c-40cf-a69c-2f33f0b38c09','答方祐甫感懷見示之作','韓維','宋','宋诗','song-poetry','','[]','壯士何憔悴，寒郊獨掩扉。',48,'全唐诗/poet.song.24000.json','["壯士何憔悴，寒郊獨掩扉。", "有親垂素髪，爲客化緇衣。", "風雪燈生暈，塵埃劍失威。", "多慚佳句贈，無力助騫飛。"]'),
('72ec0809-2cbb-4c3d-9a18-46ffddc1ffd8','同辛楊遊李氏園隨意各賦古律詩一首','韓維','宋','宋诗','song-poetry','','[]','臘近雲容變，陽生日景添。',120,'全唐诗/poet.song.24000.json','["臘近雲容變，陽生日景添。", "偶然回晚轡，相與坐晴檐。", "水綠冰微泮，沙明雪尚霑。", "弄襟風力薄，著履土膏粘。", "驚鳥不成下，寒魚猶在潛。", "翠深荒岸竹，黄折敗池蒹。", "礙徑藤梢曲，鈎衣棘刺銛。", "辭鋒憐子淬，閒癖詎予砭。", "自以清談勝，寧非樂事兼。", "春芳有近信，頻此醉厭厭。"]'),
('53bc4534-862f-4cbc-87cf-c84b65872186','自靜教院晚步潩上','韓維','宋','宋诗','song-poetry','','[]','雪盡岡頭路，風和臘後天。',48,'全唐诗/poet.song.24000.json','["雪盡岡頭路，風和臘後天。", "人安閑淡內，鳥下寂寥前。", "凍水晴初浪，荒城晚自烟。", "西橋車馬急，歸意尚留連。"]'),
('908c3507-9de2-41b8-9a5b-dec77f48463a','自城南濠上步月之葆光','韓維','宋','宋诗','song-poetry','','[]','厭踏塵中路，遠尋濠上行。',48,'全唐诗/poet.song.24000.json','["厭踏塵中路，遠尋濠上行。", "水聲喧夜塹，月色滿春城。", "衎衎交遊樂，依依里巷情。", "優哉不知老，何暇慕軒纓。"]'),
('77b7af84-c276-48df-b74f-5436e7e99ed1','遊北園賦','韓維','宋','宋诗','song-poetry','','[]','多病傷春客，經時獨掩扉。',48,'全唐诗/poet.song.24000.json','["多病傷春客，經時獨掩扉。", "偶隨游騎出，已見落花飛。", "芳草微迎履，香風細弄衣。", "扁舟可載酒，便擬拍浮歸。"]'),
('31da41e5-8cf8-4b2d-8a5e-40949fb144a7','清明北園泛池舟中作','韓維','宋','宋诗','song-poetry','','[]','路繞高林盡，舟篷出近灣。',48,'全唐诗/poet.song.24000.json','["路繞高林盡，舟篷出近灣。", "鳥啼青竹影，人對綠波間。", "野色平當坐，春愁巧作顔。", "已知湖榭近，飛絮落班班。"]'),
('7d792838-d0a2-4791-a0fc-2abcbaec2278','送王奉議知吳江縣','韓維','宋','宋诗','song-poetry','','[]','聞說吳江上，長橋百丈虹。',48,'全唐诗/poet.song.24000.json','["聞說吳江上，長橋百丈虹。", "蠔粘能固本，人度若乘空。", "明委三秋月，清來萬里風。", "君知此爲政，名惠廣無窮。"]'),
('3b5d3555-7e06-43d7-8125-3f80ee2ac2af','孤雁','韓維','宋','宋诗','song-poetry','','[]','節物何催逼，翩翩不可留。',48,'全唐诗/poet.song.24000.json','["節物何催逼，翩翩不可留。", "楓丹湘渚暮，蘆白楚江秋。", "隻影侵霜月，孤鳴入戍樓。", "天高雲路杳，安穩過羅浮。"]'),
('8b3afc6b-83d3-4940-aad4-6b088b22d1b3','陪寧極游南谿夜還山墅','韓維','宋','宋诗','song-poetry','','[]','南谿晚酌罷，歸路笑言同。',48,'全唐诗/poet.song.24000.json','["南谿晚酌罷，歸路笑言同。", "家在碧山下，人行清露中。", "鵲飛斜映月，蟲響暗移叢。", "下馬兒童喜，誰知爲德公。"]'),
('2fedae01-56c0-4278-80cf-e8436417e0d0','字谷道中','韓維','宋','宋诗','song-poetry','','[]','驅車背河去，鷄犬幾家村。',48,'全唐诗/poet.song.24000.json','["驅車背河去，鷄犬幾家村。", "山斷春風急，雲生野氣昏。", "涉溪沙水亂，步逕草花繁。", "谷口多幽思，青林啼鳥喧。"]'),
('30759632-ad35-4bb6-a6c6-5b3916815403','同化光陪寧極之滍陽城','韓維','宋','宋诗','song-poetry','','[]','不踏南溪路，于今五換春。',48,'全唐诗/poet.song.24000.json','["不踏南溪路，于今五換春。", "能來再聯騎，還是舊遊人。", "置酒真乘興，談經或入神。", "歡餘不無愧，林壑未還身。"]'),
('b0abf5cc-26f7-4ebd-83b6-4ae7474f33b6','之石橋','韓維','宋','宋诗','song-poetry','','[]','聞說西橋水樹間，不辭驅馬涉風烟。',64,'全唐诗/poet.song.24000.json','["聞說西橋水樹間，不辭驅馬涉風烟。", "疏籬老屋臨官道，瘦棘荒茅蔽石田。", "欲下鳴鴉盤木末，遠來驚雉落山前。", "瓢中幸有村醪美，不怕春寒雨滿川。"]'),
('f9c50c9e-51d0-4c68-865c-3b6e70b204ed','臨汝遇雨','韓維','宋','宋诗','song-poetry','','[]','回風蕭颯過山西，一望平郊雨脚齊。',64,'全唐诗/poet.song.24000.json','["回風蕭颯過山西，一望平郊雨脚齊。", "但使農疇蘇旱稼，敢辭客路踏春泥。", "暮投野寺明燈宿，聲入幽窗綠樹低。", "明日塵清洛陽道，呼童嚴駕候晨鷄。"]'),
('92188b8a-ba3c-4b4a-b68c-c4166dd58af5','普明亭賦','韓維','宋','宋诗','song-poetry','','[]','楊柳飛花盡，櫻桃結子成。',48,'全唐诗/poet.song.24000.json','["楊柳飛花盡，櫻桃結子成。", "蹊陰空凈綠，野艷有孤明。", "訪古重來地，傷春獨望情。", "幽禽亦何恨，百種向人鳴。"]'),
('59d29ed6-5500-47e0-8f1c-251820e11ecb','列子廟','韓維','宋','宋诗','song-poetry','','[]','廢壘荒祠古，空庭獨樹寒。',48,'全唐诗/poet.song.24000.json','["廢壘荒祠古，空庭獨樹寒。", "精誠褰畫帳，事迹問黄冠。", "晦昧塵籠墨，淋漓雨壁丹。", "冷風滿簾隙，仙馭或盤桓。"]'),
('647cb681-29ab-4239-9bca-5d2a07f3b0c6','和晏相公答邵校勘','韓維','宋','宋诗','song-poetry','','[]','兩朝典策成揮筆，二府勛庸在運籌。',64,'全唐诗/poet.song.24000.json','["兩朝典策成揮筆，二府勛庸在運籌。", "歷踐枯榮皆德舉，重陪閒燕是恩留。", "康寧必有神明勞，蕭灑真無世俗憂。", "早晚安車賜高退，碧嵩清潁從公游。"]'),
('465e4eeb-fab9-42d9-a187-cc8dcbbdb82b','和晏相公初春','韓維','宋','宋诗','song-poetry','','[]','春物華猶少，春風思已多。',48,'全唐诗/poet.song.24000.json','["春物華猶少，春風思已多。", "新黄先入柳，微綠自生波。", "酒興潛傾倒，詩情暗揣摩。", "流年不須問，判作白頭歌。"]'),
('1669196a-d9a0-4306-9301-73ed03c72088','和永叔病中寄諸君子','韓維','宋','宋诗','song-poetry','','[]','幾日東風獨掩門，忽傳佳咏感芳辰。',64,'全唐诗/poet.song.24000.json','["幾日東風獨掩門，忽傳佳咏感芳辰。", "應緣高位須憂國，未必多情便負春。", "過眼只看花艷疾，驚心初見草芽新。", "狂吟爛醉無拘束，始信光陰屬散人。"]'),
('2ef1fc4b-5d8d-40f1-b48a-ffed2c5a9625','依韵和沖卿槐花','韓維','宋','宋诗','song-poetry','','[]','翠葆連陰直，黄金布蕊齊。',96,'全唐诗/poet.song.24000.json','["翠葆連陰直，黄金布蕊齊。", "流塵一開眼，急節重含悽。", "蝶冷相携去，蟬清無數嘶。", "翻風隨御水，带雨落秋泥。", "自喜凋零後，何嫌採掇稽。", "朝緌映晨入，游袂拂宵携。", "慘淡林烟早，輕明樓日西。", "臨溪如有此，當似武陵迷。"]'),
('bccc4353-c7a2-4350-898a-1a2f898a90b9','送沈學士知常州','韓維','宋','宋诗','song-poetry','','[]','毗陵今古號名州，况是風流得隠侯。',64,'全唐诗/poet.song.24000.json','["毗陵今古號名州，况是風流得隠侯。", "吳岫稍迎雙隼旆，洛塵凡敝幾貂裘。", "預期庭下無嚚訟，還向樽前作艷謳。", "去去國門誰不羨，畫船烟浪入清秋。"]'),
('2d2e7c40-6130-41e9-8610-aa047d854e67','和十侄喜象之來飲兼簡龍陽孔先生','韓維','宋','宋诗','song-poetry','','[]','世事茫然劇轉蓬，一樽何意與君同。',64,'全唐诗/poet.song.24000.json','["世事茫然劇轉蓬，一樽何意與君同。", "從容談笑皆塵外，恍忽游從似里中。", "還有桂華來靜夜，稍驚梧葉下秋風。", "欲論歸去令人愧，高卧襄陽有德公。"]'),
('fade06ef-db61-46a9-b09e-08a0d1006883','重陽對雨招介甫','韓維','宋','宋诗','song-poetry','','[]','積潦行車絕，高舂閉戶眠。',48,'全唐诗/poet.song.24000.json','["積潦行車絕，高舂閉戶眠。", "蕭條黄葉下，冷落菊花前。", "廢卷憐佳節，銜杯想少年。", "君來慰愁坐，廄馬疾於烟。"]'),
('e5ce0585-dcb3-48e2-a049-968cca373d90','答楊辛二君重陽對雨見寄','韓維','宋','宋诗','song-poetry','','[]','秋風吹雨入荒城，城下籬邊菊艷明。',64,'全唐诗/poet.song.24000.json','["秋風吹雨入荒城，城下籬邊菊艷明。", "佳節相從平日事，新詩遥寄故人情。", "浮沉薄宦非吾願，俯仰流年只自驚。", "早晚郊扉收退迹，南阡北陌重逢迎。"]'),
('47ed398a-4aa8-44a0-b8f5-34f76879143d','奉和府判學士景彝喜雪','韓維','宋','宋诗','song-poetry','','[]','朔風收盡凍雲漫，細灑狂飄入夜寒。',64,'全唐诗/poet.song.24000.json','["朔風收盡凍雲漫，細灑狂飄入夜寒。", "潤浹土膏謠萬俗，喜聞玉色舞千官。", "川原誰作呼鷹出，樓觀朝宜跋馬看。", "亞尹勤民流咏嘆，一章高唱掩幽蘭。"]'),
('fe875d61-4cd6-4128-afe4-b3a6ea11e009','奉和介甫正月二日','韓維','宋','宋诗','song-poetry','','[]','春意來何早，乾坤潤澤中。',48,'全唐诗/poet.song.24000.json','["春意來何早，乾坤潤澤中。", "雪明初照日，雲斷欲隨風。", "世事蚊虻過，身謀雁鶩同。", "諸君亦詩酒，吾道未應窮。"]'),
('40a682bd-1982-471e-b074-0d6e23ac59ee','何龍圖赴上秘閣同諸君賦詩','韓維','宋','宋诗','song-poetry','','[]','華閣岧嶢冠道山，群公清曉集初筵。',64,'全唐诗/poet.song.24000.json','["華閣岧嶢冠道山，群公清曉集初筵。", "獨持金印承新命，重對牙籤識舊編。", "英俊雍容欣接袂，文章疏闊愧懷鉛。", "一時高會形風什，留作儒林故事傳。"]'),
('500842d9-4f6d-4bcb-bbc9-665ef9114ab7','和中道遊金明池','韓維','宋','宋诗','song-poetry','','[]','出苑花光朱雪動，壓波橋影綵虹摇。',64,'全唐诗/poet.song.24000.json','["出苑花光朱雪動，壓波橋影綵虹摇。", "飛揚鶑燕驚高管，偃蹇魚龍近畫橈。", "早識浮名身外事，久判閑日醉中消。", "幾年寥落同遊伴，還喜春風并馬鑣。"]'),
('74468356-949f-40b7-83d2-e7659dd5555a','江亭晚眺','韓維','宋','宋诗','song-poetry','','[]','日下崦嵫外，秋生沆碭間。',48,'全唐诗/poet.song.24000.json','["日下崦嵫外，秋生沆碭間。", "清江無限好，白馬不勝閑。", "雨過雲收族，天空月上彎。", "歸鞍侵調角，回首六朝山。"]'),
('f50609aa-33b9-40aa-80e4-b0af19de873a','廢烽臺','韓維','宋','宋诗','song-poetry','','[]','耆老不可問，高臺荆棘間。',48,'全唐诗/poet.song.24000.json','["耆老不可問，高臺荆棘間。", "一時戎馬散，千古暮鴉還。", "事往孤鴻斷，人來落照閒。", "興亡無限恨，慘淡對河關。"]'),
('3a45467b-e82b-4440-bdf6-c722e9c5daa0','和聖俞天津橋聞歌','韓維','宋','宋诗','song-poetry','','[]','飛雪朝來霽，朱樓月下過。',48,'全唐诗/poet.song.24000.json','["飛雪朝來霽，朱樓月下過。", "絕雲看麗構，裂玉墮清歌。", "醉燭輕摇箔，游鞍不動珂。", "回頭少年樂，慘淡一悲哦。"]'),
('2613e7d5-4e3b-4c3b-b3fc-d6e43d9be7d2','宿西京府署晚遊東池','韓維','宋','宋诗','song-poetry','','[]','牢落悲春事，蕭條作晚遊。',48,'全唐诗/poet.song.24000.json','["牢落悲春事，蕭條作晚遊。", "清光溢平沼，凉思近高樓。", "碧樹森將合，朱欄渺若浮。", "公來慰羈寓，華月許移舟。"]'),
('490c9f3a-8669-4d48-8f06-6fa5d16cbfc2','遊龍門歸','韓維','宋','宋诗','song-poetry','','[]','洛浦殘芳盡，來尋關塞春。',48,'全唐诗/poet.song.24000.json','["洛浦殘芳盡，來尋關塞春。", "青林橫石閣，翠壁涌金人。", "澗草薰衣晚，松風落面新。", "愁驅向城騎，還踏九衢塵。"]'),
('0728ad4f-ac7c-4258-9f8b-591c8bb557d9','宿紹隆院','韓維','宋','宋诗','song-poetry','','[]','東來鳴棹落河干，喜見孤幡佛樹端。',64,'全唐诗/poet.song.24000.json','["東來鳴棹落河干，喜見孤幡佛樹端。", "不謂塵埃走符檄，尚逢池榭拂衣冠。", "清風明月還相見，濁酒枯棋亦自懽。", "寄語京城騎馬客，優游到底是閑官。"]'),
('14355e0e-a226-4de5-a60e-a762e978bf61','紹隆池上對月','韓維','宋','宋诗','song-poetry','','[]','野月來何處，東池柳影深。',48,'全唐诗/poet.song.24000.json','["野月來何處，東池柳影深。", "微生水風力，稍散暝雲陰。", "冷極螢沈草，明多鵲動林。", "欲知清絕興，不寐有孤吟。"]'),
('5f50e62d-e37d-4aac-9fda-d1c975a3796f','野步','韓維','宋','宋诗','song-poetry','','[]','目倦風塵觀，身疲鞍馬行。',48,'全唐诗/poet.song.24000.json','["目倦風塵觀，身疲鞍馬行。", "春沙迎步潤，山雪照懷清。", "冰水初消色，林鴉欲乳聲。", "物華多感觸，一動故園情。"]'),
('f8efcb8a-5f51-4f56-9e98-9366131da01a','武牢道中','韓維','宋','宋诗','song-poetry','','[]','春寒驅傳馬，西度虎牢關。',48,'全唐诗/poet.song.24000.json','["春寒驅傳馬，西度虎牢關。", "草樹高低雪，烟雲左右山。", "英豪攻戰地，風物笑談間。", "俯仰看今古，翛然百慮間。"]'),
('00988c23-adf8-4522-af9d-b0b746f16307','過邵先生居','韓維','宋','宋诗','song-poetry','','[]','竹塢斜開逕，茅檐半卷書。',48,'全唐诗/poet.song.24000.json','["竹塢斜開逕，茅檐半卷書。", "幽閑入高卧，淡薄見平居。", "亂水隨釃引，殘花不掃除。", "因君動高興，回首想吾廬。"]'),
('5dc7c29b-0da0-46a3-a20f-3a01493b1a64','浴普靜同江二李叔中道賦','韓維','宋','宋诗','song-poetry','','[]','夜來飛雨濯殘芳，綠遍童童佛樹行。',64,'全唐诗/poet.song.24000.json','["夜來飛雨濯殘芳，綠遍童童佛樹行。", "把酒可勞悲暮節，振衣還自喜微凉。", "清簾不下輕颺燕，別院時來暗靄香。", "自是嵩陽欲歸客，爲公聊盡次公狂。"]'),
('3a262fa2-7092-4009-8b8b-697b0b972781','冬夜','韓維','宋','宋诗','song-poetry','','[]','繁陰掃無迹，庭雪尚餘光。',48,'全唐诗/poet.song.24000.json','["繁陰掃無迹，庭雪尚餘光。", "屋背生寒月，林梢綃暗霜。", "昏瞳頻廢卷，悲淚易霑裳。", "却想故園夜，張燈宿草堂。"]'),
('c6902efd-2595-433f-9e98-27c8b31a1e1c','同鄰幾原甫謁挺之','韓維','宋','宋诗','song-poetry','','[]','河面參差結凍凘，清風不展畫船旗。',64,'全唐诗/poet.song.24000.json','["河面參差結凍凘，清風不展畫船旗。", "偶驅羸馬知何適，獨過長橋問所思。", "可喜身閑親濁酒，未忘心競是枯棋。", "憑君莫唱陽關曲，自覺年來不能悲。"]'),
('c69a7a77-9c24-41e7-9e65-fc6fcb95b6a0','寶奎殿前花樹子去年與宋中道同賦今復答宋詩','韓維','宋','宋诗','song-poetry','','[]','長條飛動不依欄，淡粉濃朱巧作團。',64,'全唐诗/poet.song.24000.json','["長條飛動不依欄，淡粉濃朱巧作團。", "無語不辭終日立，有情曾是隔年看。", "春羅試舞衣新換，古錦藏詩墨未乾。", "我爲愁多悲節物，欲酬佳句淚霑翰。"]'),
('83497b3d-5f22-4cfc-9d81-3cbd7d88a0c4','送河秘校鬲主簿良原','韓維','宋','宋诗','song-poetry','','[]','平時太學客，文藻士林傳。',48,'全唐诗/poet.song.24000.json','["平時太學客，文藻士林傳。", "憔悴尚一邑，聲名空十年。", "風烟長夏始，關塞濁涇前。", "莫作歸來嘆，將軍好薦賢。"]'),
('961130fe-4302-44a2-b77f-4b64af77d9c1','奉同中道鎖宿南宮思寶奎殿前花樹子','韓維','宋','宋诗','song-poetry','','[]','曾見芳春二月時，弱枝繁萼動輝輝。',64,'全唐诗/poet.song.24000.json','["曾見芳春二月時，弱枝繁萼動輝輝。", "難忘絕艷驚心麗，重惜良遊與意違。", "好事幾人能載酒，感時今日爲霑衣。", "南宮老樹無妍思，坐想東風絳雪飛。"]'),
('29740387-bff7-49f6-8156-5059d77eb1ed','依韵和貢父見寄','韓維','宋','宋诗','song-poetry','','[]','早接英豪論，常多伯仲賢。',144,'全唐诗/poet.song.24000.json','["早接英豪論，常多伯仲賢。", "風塵一會合，歲月幾徂遷。", "稟性成樗散，干時類鑿圓。", "論心誰合者，握手子歡然。", "經訓開前古，談辭屈老先。", "春遊同爛漫，醉樂屢回旋。", "樂事嗟難久，離襟悵獨偏。", "驅車清汝曲，佐幕紫嵩前。", "官興惟高咏，人生得晏眠。", "丹鉛塗舊史，杖屨接幽禪。", "嘆息春期失，淹留夕夢牽。", "非因傳麗唱，何以慰勞悁。"]'),
('08f4fe9a-8da8-44be-9eb8-144ae7ad50c0','和原甫對月招江梅不至','韓維','宋','宋诗','song-poetry','','[]','塵事無時已，歸休慮暫空。',48,'全唐诗/poet.song.24000.json','["塵事無時已，歸休慮暫空。", "超颻廣庭步，蕭散葛衣風。", "默與清樽對，心期靜者同。", "獨憐新月色，百過達幽叢。"]'),
('af92f372-968b-4671-98ae-c1a2a9de45b7','和原甫立春日拜賜歸不赴鄰幾會','韓維','宋','宋诗','song-poetry','','[]','上閣群公拜賜歸，九衢春色遍熙熙。',64,'全唐诗/poet.song.24000.json','["上閣群公拜賜歸，九衢春色遍熙熙。", "後房絲竹爭相命，窮巷簞瓢亦我期。", "濁酒滿樽聊混俗，嘉蔬登俎在隨時。", "劉郎固自多幽思，門掩東風獨賦詩。"]'),
('a8f0f797-30c3-405e-b557-daa0b0996893','和鄰幾前歲同濟川原甫賞閣後杏花今茲對之有懷二君','韓維','宋','宋诗','song-poetry','','[]','春風幾日到蓬萊，仙伯初驚杏蕊開。',64,'全唐诗/poet.song.24000.json','["春風幾日到蓬萊，仙伯初驚杏蕊開。", "繞樹獨聽清夜漏，懷人空對昔年杯。", "坐憐珍賞同心隔，愁見新芳入眼來。", "欲折繁枝有所贈，九重丹禁照瑶魁。"]'),
('6eacd500-803b-4e6a-8c7c-14547a8d9203','雪中同鄰幾出游','韓維','宋','宋诗','song-poetry','','[]','絮糅瓊霏浩滿空，平明騎馬入春風。',64,'全唐诗/poet.song.24000.json','["絮糅瓊霏浩滿空，平明騎馬入春風。", "九重城闕寒光外，百萬人家喜氣中。", "不學閉門徒自潔，且欣携酒與君同。", "柳梢花甲從今始，便好尋芳下苑東。"]'),
('3fef7a16-aba6-498e-8230-3f4493516a6f','晚過鄰幾官舍三首  其一','韓維','宋','宋诗','song-poetry','','[]','炎日來休騎，紅塵喜放船。',48,'全唐诗/poet.song.24000.json','["炎日來休騎，紅塵喜放船。", "波平凉洗馬，樹凈晚吟蟬。", "風至披襟後，雲消倚拖前。", "潭心見華月，歸意一留連。"]'),
('bb4435da-d2bf-4090-9ba9-3e4cc96efe1d','晚過鄰幾官舍三首  其二','韓維','宋','宋诗','song-poetry','','[]','車馬東橋絕，凉風滿夕軒。',48,'全唐诗/poet.song.24000.json','["車馬東橋絕，凉風滿夕軒。", "水聲通沁苑，樹色入夷門。", "每接淵明咏，常懷仲理言。", "滄洲如可約，杯酒會重論。"]'),
('21d9bb99-4647-4b14-8ac8-b6d28fef24ea','晚過鄰幾官舍三首  其三','韓維','宋','宋诗','song-poetry','','[]','蕭灑君官舍，從來可數來。',48,'全唐诗/poet.song.24000.json','["蕭灑君官舍，從來可數來。", "養蓮疏濁水，薙草出荒臺。", "芡散初成籍，蒲長欲映杯。", "吾知蔣生逕，不爲俗人開。"]'),
('3bb7eeae-20ad-4df7-bc7c-cc96fd91f6d4','連日休務過鄰幾','韓維','宋','宋诗','song-poetry','','[]','廣文自古無羈束，况復三逢著令休。',64,'全唐诗/poet.song.24000.json','["廣文自古無羈束，况復三逢著令休。", "縱酒不防官長駡，驅車聊過故人遊。", "閑中日月隨方罫，遠外風雲入小舟。", "准擬牆根菊花好，共乘清露賞高秋。"]'),
('48f7075c-453d-4937-8709-993b7f592508','和歐陽內翰內直對月見寄','韓維','宋','宋诗','song-poetry','','[]','新銜佳命上金鑾，遞直連初寢未安。',64,'全唐诗/poet.song.24000.json','["新銜佳命上金鑾，遞直連初寢未安。", "霜氣稍依羅幕重，月華先近玉堂寒。", "詔函裁罷騫靈鳳，詩句書成舞瑞鸞。", "學省地閒清賞隔，懷賢空向斗杓看。"]'),
('d3e0c60a-3292-494b-9383-497b38793d3c','和永叔內直晨出馬上口占','韓維','宋','宋诗','song-poetry','','[]','天門朝日照崔嵬，車騎雍容下禁臺。',64,'全唐诗/poet.song.24000.json','["天門朝日照崔嵬，車騎雍容下禁臺。", "清景每將詩思遣，高情不爲寵名回。", "山林豈要須長往，軒冕當知是儻來。", "欲與明公論出處，會乘飛雪旁金罍。"]'),
('3ddad4d4-9d98-43db-ab10-23a3048aecc6','和永叔思滁州幽谷','韓維','宋','宋诗','song-poetry','','[]','滁陽山水翳荒榛，公爲開治物物新。',64,'全唐诗/poet.song.24000.json','["滁陽山水翳荒榛，公爲開治物物新。", "自作嘉名遍華牓，連題秀句入青岷。", "泉聲尚記巖寒夜，花思偏憐谷暖春。", "絕境坐馳高興動，安能碌碌久風塵。"]'),
('9b91882d-2e0e-4465-85d9-a9283d422be2','和子華兄同永叔飲三班官舍兼約明日飲永叔家','韓維','宋','宋诗','song-poetry','','[]','視草名臣潤色才，玉墀晨退共徘徊。',64,'全唐诗/poet.song.24000.json','["視草名臣潤色才，玉墀晨退共徘徊。", "朝廷無事文書省，臺閣相歡笑語開。", "少厭賡酬停落筆，旋尋歌舞約銜杯。", "廣文主簿官閒冷，不是詩情豈合來。"]'),
('52257d03-2639-4964-8dbe-8a937a95ba7f','寄題周著作江山縣溪亭','韓維','宋','宋诗','song-poetry','','[]','結亭遐僻古江山，勝絕終爲好事傳。',64,'全唐诗/poet.song.24000.json','["結亭遐僻古江山，勝絕終爲好事傳。", "溪泛夜聲來枕上，峰回午影過樽前。", "禽魚舊識應相樂，花木親栽益自憐。", "我抱滄洲未歸恨，羨君生計有林泉。"]'),
('7f0b59f3-3b8a-4d6d-93fc-68427751078a','和永叔從駕謁景靈宮','韓維','宋','宋诗','song-poetry','','[]','馳道塵清生紫烟，帝臨原廟拜衣冠。',64,'全唐诗/poet.song.24000.json','["馳道塵清生紫烟，帝臨原廟拜衣冠。", "日華先向金輿動，霜氣猶通玉仗寒。", "後騎綿裘明粲粲，侍臣瑶佩響珊珊。", "一聞佳句歌熙盛，不減都人夾路觀。"]'),
('ece61ebf-0f0d-4838-9c0a-654e3abb1212','和子履再遊李氏園','韓維','宋','宋诗','song-poetry','','[]','翠竹蒼林顔色老，遊人安得故時同。',64,'全唐诗/poet.song.24000.json','["翠竹蒼林顔色老，遊人安得故時同。", "沾衣似對金城柳，握管翻悲楚水楓。", "新鬢旋驚吟後白，好花猶記折來紅。", "須知世事徒勞耳，惟有清樽不負公。"]'),
('1ce96afb-5b98-4a2e-82dd-fde83b7c34ea','奉和楊直講除夜偶書','韓維','宋','宋诗','song-poetry','','[]','楊公白首困青騧，坐對流陰頗自嗟。',64,'全唐诗/poet.song.24000.json','["楊公白首困青騧，坐對流陰頗自嗟。", "半夜星文窮斗次，平明春色遍人家。", "漫將愁思驚天運，好看新詩待物華。", "何日一樽相就醉，爲君先探此園花。"]'),
('1e27b16f-f504-4d85-9d02-3980a999b08f','和周仲章出郊','韓維','宋','宋诗','song-poetry','','[]','萬里青天洗曙霜，秋曦滿眼對晴光。',64,'全唐诗/poet.song.24000.json','["萬里青天洗曙霜，秋曦滿眼對晴光。", "掃殘遺秉川原靜，折過寒花逕隧荒。", "偶入名園逢漆吏，遠尋香剎問支郎。", "浮生寵辱何須道，幸有田家濁酒嘗。"]'),
('18ba7be4-3798-4f89-9fcb-205a968fd849','奉答宋中道服除還朝示親友','韓維','宋','宋诗','song-poetry','','[]','喧然佳句落神都，哀此援琴尚有餘。',64,'全唐诗/poet.song.24000.json','["喧然佳句落神都，哀此援琴尚有餘。", "未見校文登子政，空傳爲賦似相如。", "道存固可輕華冕，談進當知得異書。", "推轂賢豪非我事，所期詩酒樂朋裾。"]'),
('2d55ad68-b90d-43b4-bb4e-9049793c8fea','許昌道中','韓維','宋','宋诗','song-poetry','','[]','荒郊不可望，極目盡傷心。',48,'全唐诗/poet.song.24000.json','["荒郊不可望，極目盡傷心。", "日薄不開凍，風凄還作陰。", "倦鴉飛趁馬，寒犬吠依林。", "頼有瓢中酒，愁來一獨斟。"]'),
('9497a01f-fbc9-47d7-9fa9-5b9b5e9f4d87','謁象之同諸君步之東禪院','韓維','宋','宋诗','song-poetry','','[]','二年憔悴走京塵，匹馬歸來訪四鄰。',64,'全唐诗/poet.song.24000.json','["二年憔悴走京塵，匹馬歸來訪四鄰。", "足滑舊諳城下徑，眼明重見里中人。", "青蔬不沒荒畦雪，翠柏常留野殿春。", "風物自如人事改，夕陽哀淚落衣巾。"]'),
('58e12db3-fa87-4b29-9c5a-7fd7709648b6','清漣磯獨坐','韓維','宋','宋诗','song-poetry','','[]','綠篠清漣得釣磯，制名翻與實相違。',64,'全唐诗/poet.song.24000.json','["綠篠清漣得釣磯，制名翻與實相違。", "沉鈎不忍潛魚亂，回棹常侵宿鳥飛。", "林靄散餘知月上，水風清極怯秋歸。", "興來詩就觴來盡，不信人間有是非。"]'),
('2ad901fb-def7-4a73-8f3b-3f5f10afed2d','謝微之送鴨脚','韓維','宋','宋诗','song-poetry','','[]','拔爾蒿萊際，微根僅自支。',48,'全唐诗/poet.song.24000.json','["拔爾蒿萊際，微根僅自支。", "勞心勤一溉，拭目待三移。", "穠李慚同列，芳橙合並枝。", "絳囊如有惠，莫忘贈君時。"]'),
('494ec4cc-4868-4e14-876f-40c1cfa79712','北園坐上探題得新杏','韓維','宋','宋诗','song-poetry','','[]','紅蘤隨風盡，團枝泣露光。',48,'全唐诗/poet.song.24000.json','["紅蘤隨風盡，團枝泣露光。", "葉深驚乍見，實小貴先嘗。", "點綴憐餘萼，飄零惜舊香。", "不須悲節物，且喜手中觴。"]'),
('854567ec-3e03-4abc-be2c-eecf8d9b32a0','送洵陽王令之官','韓維','宋','宋诗','song-poetry','','[]','離馬嘶高樹，郊原夏景深。',48,'全唐诗/poet.song.24000.json','["離馬嘶高樹，郊原夏景深。", "還持長者政，往慰遠人心。", "種黍侔千戶，張魚盛百金。", "江山永嘉咏，時寄草堂吟。"]'),
('b3af9fc6-c801-45c1-bd6e-3ee97d4e0bef','答寄廣信六弟','韓維','宋','宋诗','song-poetry','','[]','才見高帆落歸艑，又携輕劍逐戎麾。',64,'全唐诗/poet.song.24000.json','["才見高帆落歸艑，又携輕劍逐戎麾。", "步兵厨裏仍多酒，王粲軍中不廢詩。", "絕塞風烟通夕靜，近關榆柳識春遲。", "花時不得同嬉賞，腸斷東風把一卮。"]'),
('96d5026d-ca19-4c6b-a799-49c2a20cf8c2','九日席上賦得茱萸','韓維','宋','宋诗','song-poetry','','[]','寥落霜園樹，萸房獨照秋。',48,'全唐诗/poet.song.24000.json','["寥落霜園樹，萸房獨照秋。", "實兼蘭佩結，香近玉卮浮。", "嗔蕊醒殘醉，紉紅感舊遊。", "三英佳句在，殊喜繼風流。"]'),
('2398d467-ace6-421f-9a52-1a1605f538f0','和之美春日對酒','韓維','宋','宋诗','song-poetry','','[]','高軒怒馬一憧憧，夫子端居寂寞中。',64,'全唐诗/poet.song.24000.json','["高軒怒馬一憧憧，夫子端居寂寞中。", "綠酒細斟消暇日，朱弦緩撥對春風。", "官閑勢利無從入，道勝紛華豈易攻。", "即此便堪遺萬慮，可憐夸者自窮通。"]'),
('18b40207-48c2-473a-bf12-434ffb6ff992','又和寒食感懷','韓維','宋','宋诗','song-poetry','','[]','絮飛絲墮滿春陰，嘆息流光節物深。',64,'全唐诗/poet.song.24000.json','["絮飛絲墮滿春陰，嘆息流光節物深。", "鷄鞠自喧游俠地，鶑花空思長年心。", "寂寥功業看孤劍，淡薄情懷寄素琴。", "我亦新來有華髪，并須携酒白頭吟。"]'),
('78c766b7-aeb0-45de-aee9-80d8634ef91f','答楊之美春日書懷依韵','韓維','宋','宋诗','song-poetry','','[]','久宦憐官薄，端居惜歲芳。',72,'全唐诗/poet.song.24000.json','["久宦憐官薄，端居惜歲芳。", "世情徒枳棘，吾操自松篁。", "鐵擿敷經暇，檀槽度曲長。", "浮沈歸濁酒，感激見新章。", "守道言何固，安時志不忘。", "慚無推挽者，祝子壽而康。"]'),
('7ed92af1-da7a-43c1-9dc4-ebaff4cec734','次韵和唐公北使途中見寄二首  其一','韓維','宋','宋诗','song-poetry','','[]','文史平居樂，塵埃少別心。',48,'全唐诗/poet.song.24000.json','["文史平居樂，塵埃少別心。", "都門開柳色，樽酒駐車音。", "漢節光華遠，春風藻思深。", "一聞傳麗句，清興靄盈襟。"]'),
('2af5144d-2793-4bd6-bba4-4408e6297562','次韵和唐公北使途中見寄二首  其二','韓維','宋','宋诗','song-poetry','','[]','殘紅著樹春無幾，悵望君家綠玉杯。',32,'全唐诗/poet.song.24000.json','["殘紅著樹春無幾，悵望君家綠玉杯。", "美酒應容步兵醉，後堂先約戴崇開。"]'),
('a10b7343-bd6a-4894-990d-904be87a5dae','史局坐寢戲呈崇文掌學士','韓維','宋','宋诗','song-poetry','','[]','閑官身散誕，飽食坐欹斜。',48,'全唐诗/poet.song.24000.json','["閑官身散誕，飽食坐欹斜。", "永日槐陰靜，清風葆鬢華。", "廢書良愧馬，落帽偶同嘉。", "此適誰知者，逢人莫浪誇。"]'),
('36aee483-dcae-4008-859e-a30919e1832b','和景彝聖俞馬上見槐花','韓維','宋','宋诗','song-poetry','','[]','天津南望兩涯間，蓊若青雲乍吐山。',64,'全唐诗/poet.song.24000.json','["天津南望兩涯間，蓊若青雲乍吐山。", "花葉相催何日已，塵埃不斷幾人閑。", "郎官蕭灑裁詩麗，博士龍鍾嘆鬢班。", "我獨無詩亦無嘆，朝驅羸馬暮知還。"]'),
('9293cfd0-2901-4bed-89de-3d1ab338e9b9','寄溫州希用上人','韓維','宋','宋诗','song-poetry','','[]','炎塵滿天地，懷子邈湖江。',48,'全唐诗/poet.song.24000.json','["炎塵滿天地，懷子邈湖江。", "築隠雲峰亂，棲禪石樹雙。", "學禪仍慕孔，詩放欲兼龐。", "蕭灑高吾興，清風卧北窗。"]'),
('e95a7698-1c6a-429b-a91e-8bfea0577be0','和六弟苦雨','韓維','宋','宋诗','song-poetry','','[]','雷激霆奔夜復晨，天街流潦沒車輪。',64,'全唐诗/poet.song.24000.json','["雷激霆奔夜復晨，天街流潦沒車輪。", "清風皎日收無迹，妖蜧頑蛟亦有神。", "洊至已驚占習坎，汨陳深恐敗彝倫。", "蒼生可念非吾力，漏屋頹垣不庇身。"]'),
('134ba634-8551-412d-96b4-d393fb08a4a7','送思上人南歸','韓維','宋','宋诗','song-poetry','','[]','塵埃不可久，歸卧故山秋。',48,'全唐诗/poet.song.24000.json','["塵埃不可久，歸卧故山秋。", "榮利非其好，風騷得所求。", "晨征隨社燕，夜宿近江鷗。", "聞子禪林勝，它年一繫舟。"]'),
('0c68211d-40fc-4895-8290-2b88bf8f7973','送李瑜屯田通判潤州','韓維','宋','宋诗','song-poetry','','[]','耳熟江南勝事傳，聞君官去便翛然。',64,'全唐诗/poet.song.24000.json','["耳熟江南勝事傳，聞君官去便翛然。", "江流截楚紅塵斷，山勢吞吳秀色連。", "紫蟹迎霜新受釣，黄花吹酒正當前。", "嗟予不得從斯樂，坐看秋風發畫船。"]'),
('9f256269-a524-4744-8bb3-fdcbe998c834','次韵和之美十日菊','韓維','宋','宋诗','song-poetry','','[]','孤根隨地發，繁蕊破霜遲。',48,'全唐诗/poet.song.24000.json','["孤根隨地發，繁蕊破霜遲。", "但取凋零晚，何憂賞愛移。", "物情傷老大，人事閱興衰。", "會有陶彭澤，清樽與重持。"]'),
('bb2fbde2-b1f6-43f1-a31f-4cf0090291e7','寄題劉仲更澤州家園','韓維','宋','宋诗','song-poetry','','[]','聞君有佳尚，買勝不論錢。',72,'全唐诗/poet.song.24000.json','["聞君有佳尚，買勝不論錢。", "逕鑿蒼林蘚，亭開翠壁烟。", "徙花窮洛譜，得石記唐年。", "數卷書盈萬，言章木以千。", "晨昏板輿往，社臘燕觴傳。", "予亦耽幽事，西風一慨然。"]'),
('18036239-db04-491b-828a-69b8adb68bd3','奉和喬年館宿','韓維','宋','宋诗','song-poetry','','[]','蓬萊仙構斗魁旁，遞直初登漢署郎。',64,'全唐诗/poet.song.24000.json','["蓬萊仙構斗魁旁，遞直初登漢署郎。", "雲向城頭收暝色，月從樓角放寒光。", "行看砌菊嗟殘艷，坐對書芸襲暗香。", "景物過清渾不寐，素經讎罷得新章。"]'),
('8e52c091-3300-49fa-a952-bc68a89b316a','又和館西迎駕','韓維','宋','宋诗','song-poetry','','[]','宮樹烟開敞禁扉，儒冠羅立望天威。',64,'全唐诗/poet.song.24000.json','["宮樹烟開敞禁扉，儒冠羅立望天威。", "霜清廣殿鳴鞘肅，日上觚棱翠蓋飛。", "玉勒帊鞍龍在御，錦衣腰劍士成圍。", "暫來直舍支頤坐，却聽簫韶輦路歸。"]'),
('21657638-ba16-4417-b04e-d3a3ad65d330','覽楊樂道洛下諸詩','韓維','宋','宋诗','song-poetry','','[]','昔驅羸馬望嵩雲，正值嵩陽躑躅春。',64,'全唐诗/poet.song.24000.json','["昔驅羸馬望嵩雲，正值嵩陽躑躅春。", "千古廢興都邑地，百年勞苦宦遊身。", "曾耽勝事留連久，忽見新詩嘆息頻。", "君欲買山能遂否，它時願作社中人。"]'),
('6ed5fc0e-0ddb-4164-a86b-546f144e3b75','和仲巽誚京塵','韓維','宋','宋诗','song-poetry','','[]','輕如游泛坌如馳，朝雨才暗暮即飛。',64,'全唐诗/poet.song.24000.json','["輕如游泛坌如馳，朝雨才暗暮即飛。", "常恐旱風增氣勢，却教晴日損光輝。", "衣緇京洛言何驗，纓濯滄浪志尚違。", "此物無情君莫誚，九衢聲利走輪騑。"]'),
('6b90fc28-4531-48fc-bfa8-b9ab8a01f34b','送石昌言歸蜀','韓維','宋','宋诗','song-poetry','','[]','省署聊休直，皇恩許過家。',48,'全唐诗/poet.song.24000.json','["省署聊休直，皇恩許過家。", "朝廷寵儒雅，車騎有光華。", "行色星垣動，褒章宰樹加。", "遥知蜀父老，夾道競咨嗟。"]'),
('6df3a21e-1666-41b5-8065-e692920df4c7','寄題蘇子美滄浪亭','韓維','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','聞君買宅洞庭傍，白水千畦插稻秧。',64,'全唐诗/poet.song.24000.json','["聞君買宅洞庭傍，白水千畦插稻秧。", "生事已能支伏臘，歲華全得屬文章。", "騫飛靈鳳知何暮，蟠蟄蛟龍未可量。", "莫以江山足清尚，便收才業傲虞唐。"]'),
('753015de-da1d-4879-9c3b-a01bee4411c1','和邵興宗再還館','韓維','宋','宋诗','song-poetry','','[]','莫嗟華髪尚蓬瀛，自古儒生半滯榮。',64,'全唐诗/poet.song.24000.json','["莫嗟華髪尚蓬瀛，自古儒生半滯榮。", "學似楊雄老天祿，才如嚴助厭承明。", "一簞聊喜安吾道，幾騎當知達此生。", "聞說東郊可携手，能來從我並鞍行。"]'),
('5ae1cf94-ebf3-4e85-8436-3d719cf45642','送劉巽殿直官蜀','韓維','宋','宋诗','song-poetry','','[]','車馬蕭條西出門，憐君宦薄意能閑。',64,'全唐诗/poet.song.24000.json','["車馬蕭條西出門，憐君宦薄意能閑。", "並遊多得賢豪士，久困獨無憔悴顔。", "白酒園林休洛社，黄花風露見岷山。", "男兒榮滯古來有，收取功名晚節間。"]'),
('87d96113-e35c-48cf-a106-281270da33ec','送衛真晏太丞','韓維','宋','宋诗','song-poetry','','[]','才名宰相子，二十取辭科。',48,'全唐诗/poet.song.24000.json','["才名宰相子，二十取辭科。", "得縣古稱厲，登樓朝見渦。", "疲民勞賦役，靜理足弦歌。", "八檜仙祠在，知君秀句多。"]'),
('1cf2a6eb-5c48-458d-8410-b6b36d0c7a13','同江謝王出郊','韓維','宋','宋诗','song-poetry','','[]','東郊二月天，寒盡未成暄。',48,'全唐诗/poet.song.24000.json','["東郊二月天，寒盡未成暄。", "永日青絲騎，和風綠酒樽。", "逕抽萱甲細，牆倚杏梢繁。", "爛醉誰知者，行歌入國門。"]'),
('e44657d8-9559-4d91-94af-0968c435716e','寒食出郊','韓維','宋','宋诗','song-poetry','','[]','都門氣象雨餘佳，壓盡風塵見草芽。',67,'全唐诗/poet.song.24000.json','["都門氣象雨餘佳，壓盡風塵見草芽。", "日薄風和近郊路，朱紅粉白遠林花。", "堤開獨去媻珊女，柳下相逢輕{車录}車。", "絲鬢未催樽酒在，不須辛苦問年華。"]'),
('a9cc671d-2391-4f43-a2a8-dcbdecd8b0de','送晁懷州學士  其一','韓維','宋','宋诗','song-poetry','','[]','儒館讎書舊，侯藩請節行。',48,'全唐诗/poet.song.24000.json','["儒館讎書舊，侯藩請節行。", "山川猶古氣，鐃吹自春聲。", "問俗憐彫瘵，頒條頼簡平。", "從來寇河內，誰復繼聲名。"]'),
('a3f159b3-c970-4851-811e-e9c9e35ada98','送晁懷州學士  其二','韓維','宋','宋诗','song-poetry','','[]','退傳清門世有才，使君嘉譽藹中臺。',64,'全唐诗/poet.song.24000.json','["退傳清門世有才，使君嘉譽藹中臺。", "未甘文墨工彫篆，聊取圭符試剸裁。", "壟上勸耕春晼晚，山前聞笛月徘徊。", "明朝建隼臨長道，回首仙廬拂斗魁。"]'),
('e35f3984-4531-4436-aa88-3e630f9204c6','觀音精舍期鄰幾未至','韓維','宋','宋诗','song-poetry','','[]','懶驅羸馬傍朱門，來對祇園寂寞春。',64,'全唐诗/poet.song.24000.json','["懶驅羸馬傍朱門，來對祇園寂寞春。", "撩亂繞樓唯有燕，蕭條垂箔更無人。", "未回山簡池頭馬，空愧陶公頂上巾。", "留得清風滿衣袖，爲君吹盡鬢邊塵。"]'),
('52f7b258-caa1-4813-afea-bedf6276fb73','覽鄰幾重遊西池兼簡和叔','韓維','宋','宋诗','song-poetry','','[]','積雨淹連騎，新波灧廣池。',48,'全唐诗/poet.song.24000.json','["積雨淹連騎，新波灧廣池。", "喜聞重到客，更作復游詩。", "逐水無留絮，飄空有斷絲。", "送春吾得地，一問故人期。"]'),
('b47cbc81-7ce1-4f7e-8a15-d6272c9912c6','奉同鄰幾對','韓維','宋','宋诗','song-poetry','','[]','時律迎陽近，天雲带雪低。',216,'全唐诗/poet.song.24000.json','["時律迎陽近，天雲带雪低。", "欲飛含氣象，忽散失端倪。", "絳闕明先曙，清衢凍不泥。", "休祥占歲序，佳氣動烝黎。", "矯若翔廱鷺，紛疑剝楚圭。", "晨昏檐影眩，壬丙辨方迷。", "賀瑞彤墀集，凌寒玉仗齊。", "御筵開省戶，賜醴走宮奚。", "屋角懸珠網，林梢挂素霓。", "山號悲虎兕，淵伏怯龜蠵。", "哀響求群雁，喧啾得食鷄。", "饑鷹無近擊，狂兔有新刲。", "感往悲時物，懷幽夢故棲。", "溫爐期夜擁，傑閣想晨躋。", "驗古聞牛目，投閒讀馬蹄。", "吾交情不薄，今日手同携。", "酒撥新醅酌，詩看本字題。", "優游無不可，何必剡中溪。"]'),
('096070f3-7c6e-43cf-b4f4-9fc6604531dc','照鄰從予假韋蘇州集因以詩致之','韓維','宋','宋诗','song-poetry','','[]','都官郎署老，平淡古人如。',48,'全唐诗/poet.song.24000.json','["都官郎署老，平淡古人如。", "更覓蘇州集，長依釋子廬。", "室中無凈几，門外自華輿。", "爲問蕭疏意，如何善福居。"]'),
('64e4392b-a952-4a63-8c91-48f470168ea0','送高寺丞宰岐上','韓維','宋','宋诗','song-poetry','','[]','墨綬垂腰底，憐君尚一同。',48,'全唐诗/poet.song.24000.json','["墨綬垂腰底，憐君尚一同。", "人豪固秦俗，地古自豳風。", "春色鳴弦外，山光隠几中。", "定應傳善政，不日到關東。"]'),
('dcfbbe78-9284-4502-ba7b-ff5547834b85','答和叔見寄','韓維','宋','宋诗','song-poetry','','[]','清霜落堤水，知子戒歸舟。',48,'全唐诗/poet.song.24000.json','["清霜落堤水，知子戒歸舟。", "蹭蹬蛟龍雨，翻飛鴻鵠秋。", "文章真自樂，得喪豈吾憂。", "南國江山好，裁詩寄少游。"]'),
('0e61b077-1e13-4c21-b976-cfbf5eb85d9a','和永叔雪','韓維','宋','宋诗','song-poetry','','[]','浴鳳池邊雪舞風，題詩高揖杜陵翁。',64,'全唐诗/poet.song.24000.json','["浴鳳池邊雪舞風，題詩高揖杜陵翁。", "懷人共惜車音斷，對酒須論盞底空。", "授簡久虛梁苑候，引舟誰過剡溪中。", "今朝白雪聞君咏，千載風流未覺窮。"]'),
('123f38aa-3d8f-40bb-bf9b-3f80c08861d7','和永叔雪','韓維','宋','宋诗','song-poetry','','[]','二十年來野逸身，懶能奔走傍埃塵。',64,'全唐诗/poet.song.24000.json','["二十年來野逸身，懶能奔走傍埃塵。", "偶逢閭里閑游伴，同過叢林燕坐人。", "世事糾紛寧有盡，勞生蕭散不妨頻。", "晴陽緩轡殊多適，它日重來訪道真。"]'),
('1038123a-5e57-4eb6-aa3b-d9724438d07a','之雍丘舟中奉寄少述處士明叔公緼','韓維','宋','宋诗','song-poetry','','[]','柔櫓咿啞畫鷁東，翛然清興不知窮。',64,'全唐诗/poet.song.24000.json','["柔櫓咿啞畫鷁東，翛然清興不知窮。", "新秋草樹輕凉外，落日帆檣遠思中。", "人事感心懷素友，年華催鬢作衰翁。", "江湖舊約今仍負，腸斷從南萬里風。"]'),
('e1d909c1-52d8-4b57-a1c8-083763bbcc16','和三兄立冬祠太乙二首  其一','韓維','宋','宋诗','song-poetry','','[]','樓外闌班曉斗垂，霜晴宮瓦濕琉璃。',64,'全唐诗/poet.song.24000.json','["樓外闌班曉斗垂，霜晴宮瓦濕琉璃。", "珠幢羽節嚴仙仗，桂酒椒漿潔祠儀。", "寒氣導迎通律管，神光飛動屬壇壝。", "定聞賈傅開良對，天子齋居待受釐。"]'),
('fc2b3c0c-bea7-48e0-a51f-33a25648d0f1','和三兄立冬祠太乙二首  其二','韓維','宋','宋诗','song-poetry','','[]','曾爲祝史趨真館，屈指於今二十年。',32,'全唐诗/poet.song.24000.json','["曾爲祝史趨真館，屈指於今二十年。", "琪樹瑶林成想像，直疑當日夢遊仙。"]'),
('ab9afed1-c294-4026-8e1d-cd29557cf844','送劉景元觀察守襄陽','韓維','宋','宋诗','song-poetry','','[]','荆州太守駕朱轓，寶筆題詩出御前。',64,'全唐诗/poet.song.24000.json','["荆州太守駕朱轓，寶筆題詩出御前。", "應厭笙歌消暇日，欲將才業效當年。", "千章翠木雲間寺，百丈清江雪後船。", "看取古來良吏迹，蒼碑突兀峴山巔。"]'),
('a88411ef-239f-4964-b0c9-eca5feb932e1','奉和仲通秋宴','韓維','宋','宋诗','song-poetry','','[]','參差天仗拂雲臺，雉尾分行劍佩來。',64,'全唐诗/poet.song.24000.json','["參差天仗拂雲臺，雉尾分行劍佩來。", "萬壽稱觴臣節罄，九韶張樂帝顔開。", "班趨玉佩花相鬥，舞入文茵雪屢回。", "疏賤恭承湛露賜，慚無辭藻咏康哉。"]'),
('4985c183-39f6-4d40-b2fc-76d815a22ec3','又和史院晚出','韓維','宋','宋诗','song-poetry','','[]','新雨稍添清禁潤，斜陽初下直廬明。',32,'全唐诗/poet.song.24000.json','["新雨稍添清禁潤，斜陽初下直廬明。", "方慚飽食無裨補，更作長廊百步行。"]'),
('e5d904aa-3641-429c-a86b-4b988c504ee0','奉和運判朝散登樂山亭','韓維','宋','宋诗','song-poetry','','[]','看山日日上孤城，不問雲昏與雪晴。',64,'全唐诗/poet.song.24000.json','["看山日日上孤城，不問雲昏與雪晴。", "六六高峰長秀色，雙雙啼鳥忽春聲。", "心驚流水光陰逝，身慕冥鴻羽翼輕。", "方促吏文嚴指使，不知詩興坐中生。"]'),
('589828d6-b100-4419-a7cd-bfec42cb92cf','運判再以前韵見寄','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','突兀朱堂冠北城，雲峰滿目互陰晴。',64,'全唐诗/poet.song.24000.json','["突兀朱堂冠北城，雲峰滿目互陰晴。", "憑欄不負思山意，對酒何煩考鼓聲。", "清話從容雙麈禿，雕章溫麗百金輕。", "歸軒未必能相遲，夢繞西湖春水生。"]'),
('e3a2e8e7-c8cf-4595-850b-fc91fc9c4b16','湖上飲','韓維','宋','宋诗','song-poetry','','[]','高秋水木變清光，荷葉乾枯䆉稏黄。',64,'全唐诗/poet.song.24000.json','["高秋水木變清光，荷葉乾枯䆉稏黄。", "習靜久安融子懶，乘歡聊發次公狂。", "未甘濁酒欺人老，深喜寒花入坐香。", "更謝林端新月色，留連歸舫盡三觴。"]'),
('af548862-3a38-4b68-b8dd-edf88bfbf6d4','載酒過景仁東園','韓維','宋','宋诗','song-poetry','','[]','地勝依危堞，城高若半峰。',48,'全唐诗/poet.song.24000.json','["地勝依危堞，城高若半峰。", "銜觴驚歲序，候雪仰雲容。", "不假貓滋竹，須防犬敗松。", "顧慚文俗吏，游步躡仙蹤。"]'),
('a6995fb6-03f1-48e2-b6ee-a5ebdf6b8f64','和張太中館於西湖','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖榭從來與衆同，况於清晏奉群公。',64,'全唐诗/poet.song.24000.json','["湖榭從來與衆同，况於清晏奉群公。", "驅車即日趨翔鳳，就館初寒聽過鴻。", "霜雪滿髯仍自壯，珠璣落筆不知窮。", "太平魚鱉今咸若，豈繫區區一老翁。"]'),
('ed671892-0359-48c2-bdc4-587d69b9b641','和樂道','韓維','宋','宋诗','song-poetry','','[]','紅旆重來鎮故鄉，吏民歡喜拂牙床。',64,'全唐诗/poet.song.24000.json','["紅旆重來鎮故鄉，吏民歡喜拂牙床。", "忽頒優渥垂天詔，仍許衰殘守郡章。", "自笑木鷄猶獨立，人嗟竹馬漫相將。", "君皇念舊恩非淺，南北圭符各一方。"]'),
('3376d82c-1585-46d7-aace-97b9322bca71','和伯壽秘監','韓維','宋','宋诗','song-poetry','','[]','曾陪道論接清歡，屈指於今四十年。',64,'全唐诗/poet.song.24000.json','["曾陪道論接清歡，屈指於今四十年。", "不用笙歌娛上客，直將風月待高眠。", "黄花一醉猶能否，白首相逢是偶然。", "便欲投冠結閑伴，家山况與碧嵩連。"]'),
('fa34e75f-ba18-4a05-ac7b-3f3fd5aec0bd','和曾令綽','韓維','宋','宋诗','song-poetry','','[]','卧病河橋與死濱，還家重喜見芳春。',64,'全唐诗/poet.song.24000.json','["卧病河橋與死濱，還家重喜見芳春。", "輔藩行釋綏安重，仁里欣聞締構新。", "危堞遍臨雙遠岫，平湖不受一微塵。", "知君雅有超然興，香火它年作社人。"]'),
('56e93c1a-a07b-4cfc-81c9-a9242935ba35','和子華兄喜雨','韓維','宋','宋诗','song-poetry','','[]','膏潤涵濡萬物中，欣然生意滿和風。',67,'全唐诗/poet.song.24000.json','["膏潤涵濡萬物中，欣然生意滿和風。", "{扌嵌}飄先動吟毫紫，急灑疑催舞袂紅。", "病手便甘千日醉，疲農又得一年豐。", "歡聲定有歌堯壤，喜氣遥瞻繞漢宮。"]'),
('f95ab12d-23cc-4cef-8b67-066e405232d9','奉同景仁九日宴相公新堂','韓維','宋','宋诗','song-poetry','','[]','高堂突兀里人驚，丞相規模固自宏。',64,'全唐诗/poet.song.24000.json','["高堂突兀里人驚，丞相規模固自宏。", "移石遠分嵩嶠色，鑿池切放潩泉聲。", "茱萸結佩聊同俗，鸚鵡傳杯豈吝情。", "右席先生亦華構，便應次第落新成。"]'),
('eae58804-4d8e-41ff-af87-5da5d40e0b36','對雪送花走筆况之','韓維','宋','宋诗','song-poetry','','[]','春陰黯黯壓城低，亂撲簾帷細點衣。',64,'全唐诗/poet.song.24000.json','["春陰黯黯壓城低，亂撲簾帷細點衣。", "梅蕊更寒猶競發，楊花未暖忽先飛。", "便思樽酒陪公議，敢望笙歌近使威。", "絕景坐嗟清燕隔，一籃朱白慰旋歸。"]'),
('743ca8e8-818f-41b5-ba63-912f046ef221','答趙縣丞','韓維','宋','宋诗','song-poetry','','[]','止足常佳漢二臣，早思幽退謝朝紳。',64,'全唐诗/poet.song.24000.json','["止足常佳漢二臣，早思幽退謝朝紳。", "奉藩終乏三年最，學道才知一日真。", "目病懶將書卷展，心閑得近酒杯頻。", "朝吟夕嘯無厭斁，正頼賢賓與德鄰。"]'),
('4c506c7a-1220-42d1-9d97-de659681d40b','題卞大夫翠陰亭','韓維','宋','宋诗','song-poetry','','[]','新得亭名號翠陰，軒窗環合盡青林。',64,'全唐诗/poet.song.24000.json','["新得亭名號翠陰，軒窗環合盡青林。", "定知野客先回顧，何處山禽自好音。", "池面有蓮風氣馥，城根多竹月華深。", "明年便作歸來計，應許携樽與抱琴。"]'),
('1cb6764b-9e00-4a58-9a3b-415e4561569c','通判郎中以州早休特形詩咏輒依元韵','韓維','宋','宋诗','song-poetry','','[]','潁水箕山一腐儒，麟符何幸玷恩除。',64,'全唐诗/poet.song.24000.json','["潁水箕山一腐儒，麟符何幸玷恩除。", "未緣秕政休官去，真頼英賢接迹居。", "秀麥川原知雨足，清陰池館愛春餘。", "坐慚老拙無施用，空下齋帷學仲舒。"]'),
('4a8343a5-86dc-4b05-b1c1-150b52adfe60','依韵答欽之學士草堂見寄','韓維','宋','宋诗','song-poetry','','[]','白首徘徊玷善藩，慚君先解左魚還。',64,'全唐诗/poet.song.24000.json','["白首徘徊玷善藩，慚君先解左魚還。", "未同一笑清樽側，獨想高眠翠竹間。", "素節消餘寧復壯，妄情休盡只餘閑。", "田園雨足官無事，趣駕何妨慰病顔。"]'),
('b725e377-965b-4d8e-82f1-4f577a610d53','伏蒙三哥以某再領許昌賦詩爲寄謹依嚴韵','韓維','宋','宋诗','song-poetry','','[]','久陪法從常懷愧，再領鄉州始覺榮。',64,'全唐诗/poet.song.24000.json','["久陪法從常懷愧，再領鄉州始覺榮。", "政事敢言前可繼，寵光深見古爲輕。", "預裝白酒留春盎，旋剪紅葩出洛城。", "兩道况聞時澤足，不妨吟嘯玉杯傾。"]'),
('a7a46378-feb0-453a-b9ea-70025486ea35','化光殿丞謁告還里某數奉游集蒙賦詩道舊輒依元韵','韓維','宋','宋诗','song-poetry','','[]','定契多慚國士知，交歡重喜故人期。',64,'全唐诗/poet.song.24000.json','["定契多慚國士知，交歡重喜故人期。", "莫辭日嚼千觴酒，况值春歸百卉枝。", "披竹共尋前會處，插花仍學少年時。", "詞章褒紀明情重，坐諷行吟刻屢移。"]'),
('a7d8b60a-8488-44bd-9257-fd533cf8f025','和君俞喜雨','韓維','宋','宋诗','song-poetry','','[]','一夜歊炎散烈風，清和從令氣潛通。',64,'全唐诗/poet.song.24000.json','["一夜歊炎散烈風，清和從令氣潛通。", "誠微敢謂天心應，政拙惟希歲事豐。", "便有歡聲南畝俗，首傳佳句少陵翁。", "心灰鬢雪無餘願，飽食安居與衆同。"]'),
('a4bfc915-db6c-46b7-aabc-a4d5927ec5fd','奉答樂道','韓維','宋','宋诗','song-poetry','','[]','禁職臺綱佚舊儒，青林華屋儼高居。',64,'全唐诗/poet.song.24000.json','["禁職臺綱佚舊儒，青林華屋儼高居。", "炎天久隔揮犀論，暇日聊脂載酒車。", "雨逼秋容生戶牖，風回凉思入襟裾。", "東朝第一推調護，聖主寧容久卧廬。"]'),
('3d1907ab-9b06-4fc4-8267-811a61c3443a','和君俞偶成','韓維','宋','宋诗','song-poetry','','[]','竊比淮陽卧，幸非莊舄吟。',48,'全唐诗/poet.song.24000.json','["竊比淮陽卧，幸非莊舄吟。", "政餘無異事，物外得同心。", "遇興傾浮蟻，投閑作戲禽。", "世間并出世，於我兩沉沉。"]'),
('b867e6ef-a065-453b-a0e6-e5816098e7a8','和太素同看梅花寄子華','韓維','宋','宋诗','song-poetry','','[]','寒林凍卉誰觀者，繁艷清香自得之。',64,'全唐诗/poet.song.24000.json','["寒林凍卉誰觀者，繁艷清香自得之。", "天賦好花如有待，日尋幽徑不知疲。", "未逢驛使空懷遠，猶喜山翁亦好奇。", "昔歲一觴今一咏，共陶真意不爲私。"]'),
('e0940a50-09ae-4687-81e1-b02911032cd4','奉和樂道席上見詒','韓維','宋','宋诗','song-poetry','','[]','大隗山前一老翁，幸分州契接群公。',64,'全唐诗/poet.song.24000.json','["大隗山前一老翁，幸分州契接群公。", "飲豪肯放兵先北，論合須欣水必東。", "坐對華燈燃寶檠，行看紅艷發珍叢。", "良辰勝事從茲始，嘉與吾民樂歲豐。"]'),
('d0737b3b-eda3-462b-ae19-547e89b5894b','奉酬君俞席上偶成','韓維','宋','宋诗','song-poetry','','[]','候月紗籠合，看梅翠幄開。',48,'全唐诗/poet.song.24000.json','["候月紗籠合，看梅翠幄開。", "滿城均俗樂，同閈得君來。", "笑極時傾弁，歡狂欲倒罍。", "賦詩慚善祝，凡器豈公台。"]'),
('4da4b765-d911-4d9c-88f4-b0d952149553','觀燈市井之利得雨農田所急而二者不可以並時乃所願燈徹而雨作也今幸得之輒次原韵以酬來貺','韓維','宋','宋诗','song-poetry','','[]','風回協氣通青律，月破游氛上碧天。',64,'全唐诗/poet.song.24000.json','["風回協氣通青律，月破游氛上碧天。", "萬盞華燈輝永夜，一犁甘雨報豐年。", "梅含宿潤粧先試，荑展新桑手不拳。", "雲勢崇朝殊未已，坐看澤遍先垓田。"]'),
('af5cd713-99b1-41cc-a177-8bcd239509d1','再和樂道','韓維','宋','宋诗','song-poetry','','[]','鳳凰臺下芳林合，鴨子陂中綠水深。',64,'全唐诗/poet.song.24000.json','["鳳凰臺下芳林合，鴨子陂中綠水深。", "不惜清光輸曲沼，欲將幽韵伴鳴琴。", "餘波及晉良慚昔，春服沿沂正在今。", "洗耳濯纓何足道，願同沉醉復高吟。"]'),
('4bd819be-e565-4437-aa93-b4d52207704f','奉酬君俞','韓維','宋','宋诗','song-poetry','','[]','夫君有奇尚，與世實相差。',48,'全唐诗/poet.song.24000.json','["夫君有奇尚，與世實相差。", "不飲三春酒，唯看九日花。", "名雖賢士籍，心自法王家。", "顧我何能爾，東風醉弁斜。"]'),
('c6dd2ca3-430e-4ed6-9ac5-3feb39d34581','和君俞春暮書事','韓維','宋','宋诗','song-poetry','','[]','舉俗從多事，惟君獨閉關。',48,'全唐诗/poet.song.24000.json','["舉俗從多事，惟君獨閉關。", "廢觴豈爲戒，開卷不妨閑。", "小雨清湖面，飛花亂席間。", "應憐狂太守，心不到靈山。"]'),
('e4654cf9-66df-47b5-88f4-c0618ee7f6cf','次韵奉答四哥廷評欲垂訪以詩爲示','韓維','宋','宋诗','song-poetry','','[]','再臨鄉國兩逢春，乞與優閑荷帝宸。',64,'全唐诗/poet.song.24000.json','["再臨鄉國兩逢春，乞與優閑荷帝宸。", "德薄敢同商四老，論狂難預漢諸臣。", "行吟水際花粘履，燕坐林間絮點茵。", "早晚湖波照車馬，爲君酌酒鱠鮮鱗。"]'),
('b3af55ac-ee9c-46f0-95c1-13ff1fedf6c5','次韵奉答君俞','韓維','宋','宋诗','song-poetry','','[]','閭里幽居几案前，迹雖相異意同然。',64,'全唐诗/poet.song.24000.json','["閭里幽居几案前，迹雖相異意同然。", "禪書罷閱成端坐，訟牒希投得晏眠。", "情累已知超永劫，身名那復計當年。", "才疏政拙逢嘉歲，敢竊天功自謂賢。"]'),
('810c80e3-33cc-439d-a74d-4f49aee6509b','樂道示長句輒次韵','韓維','宋','宋诗','song-poetry','','[]','光陰不覺成陳迹，事變何嘗有定期。',64,'全唐诗/poet.song.24000.json','["光陰不覺成陳迹，事變何嘗有定期。", "身外閑愁無自入，飲中歡興未全衰。", "編排暑後新投酒，檢點秋來合唱辭。", "更欲邀君浮畫舫，藕花菱蔓滿西池。"]'),
('2db8736c-78ce-4518-ba02-aa89692975da','次韵君俞偶成  其一','韓維','宋','宋诗','song-poetry','','[]','我道非生滅，天時自去來。',48,'全唐诗/poet.song.24000.json','["我道非生滅，天時自去來。", "交親常在席，醪酒不空罍。", "默坐唯聽水，閒行忽見梅。", "何人同此適，君意亦悠哉。"]'),
('f488862c-1063-4ab8-adfb-4a27deb67f71','次韵君俞偶成  其二','韓維','宋','宋诗','song-poetry','','[]','雪意凝還解，冰紋結復開。',48,'全唐诗/poet.song.24000.json','["雪意凝還解，冰紋結復開。", "林鴉時嘯侶，城雉不憂媒。", "造適心無礙，忘機語絕猜。", "曹溪不欺我，何處有塵埃。"]'),
('1e06f814-9a7e-427a-9f54-dbfc1080eddb','奉和君俞佳雪二首  其一','韓維','宋','宋诗','song-poetry','','[]','老來事事皆拋盡，惟獨憂民尚有心。',64,'全唐诗/poet.song.24000.json','["老來事事皆拋盡，惟獨憂民尚有心。", "深喜天公回氣象，便同田父作謳吟。", "緣何更得閭閻暖，恨不偏於壠麥深。", "禪伯靜中知我意，琅琅佳句玉其音。"]'),
('b00a3ede-9edf-4408-9e3c-386a7cef588a','奉和君俞佳雪二首  其二','韓維','宋','宋诗','song-poetry','','[]','居塵不染先生意，與衆同憂太守心。',64,'全唐诗/poet.song.24000.json','["居塵不染先生意，與衆同憂太守心。", "兩處本來非異事，一時都把付高吟。", "忽驚瑞相家家遍，潛助春功日日深。", "擁鼻臨池哦麗句，水泉風竹共清音。"]'),
('bab46420-3f6f-4035-b827-1d932da3b080','酬盈祖中散','韓維','宋','宋诗','song-poetry','','[]','勇脫塵冠尚壯年，高齋圖史日蕭然。',64,'全唐诗/poet.song.24000.json','["勇脫塵冠尚壯年，高齋圖史日蕭然。", "不教歌舞家規在，善作文章世學傳。", "道舊每思傾濁酒，仰高徒覺愧華顛。", "相君昔展西陂盡，好約春風放畫船。"]'),
('18c3ed9d-5cf7-4500-863a-395aced405cf','和詹叔遊廬山見寄','韓維','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','香爐峰色壓群山，仰眺頻欹使者冠。',64,'全唐诗/poet.song.24000.json','["香爐峰色壓群山，仰眺頻欹使者冠。", "江面烟波摇紫翠，佛宮金碧照晴寒。", "密藏幽谷梅千樹，散走鳴泉竹萬竿。", "今日頓驚塵慮盡，一章佳句雪中看。"]'),
('cbf6b94c-bceb-406d-905f-b7951f81965c','東禪院坐上作','韓維','宋','宋诗','song-poetry','','[]','山林曾是自由身，豈合區區入世塵。',64,'全唐诗/poet.song.24000.json','["山林曾是自由身，豈合區區入世塵。", "蕭散未能忘故態，優游聊喜及時春。", "閑中濁酒偏親我，風外飛花欲趁人。", "多謝鳴鳩催對雨，坐慚無術粒斯民。"]'),
('1cb7ac85-ee62-4a01-8cea-7499ab35acc5','次韵和李公達見寄','韓維','宋','宋诗','song-poetry','','[]','五分符竹盡吾鄉，聖主恩私溢故常。',64,'全唐诗/poet.song.24000.json','["五分符竹盡吾鄉，聖主恩私溢故常。", "攬轡豈能清北道，支筇時得問西堂。", "湖邊凍柳生春意，月下晴梅動暗香。", "乘興可能同一醉，聞君筋力尚堅强。"]'),
('7754ef48-b955-46d0-95bd-8eefcdbe9c68','答張念七得科見寄','韓維','宋','宋诗','song-poetry','','[]','少年初見一經橫，籍籍文場藹俊名。',64,'全唐诗/poet.song.24000.json','["少年初見一經橫，籍籍文場藹俊名。", "抗志直思追二祖，得官今乃後諸生。", "賜袍便欲欺芳草，賀酒猶能及落英。", "我亦林泉有歸興，待君吟嘯樂昇平。"]'),
('6fd2e193-8b37-4e3d-b5f7-dbb295abe9c3','和朱主簿遊園','韓維','宋','宋诗','song-poetry','','[]','白首昏昏度歲年，忽聞春至便開顔。',64,'全唐诗/poet.song.24000.json','["白首昏昏度歲年，忽聞春至便開顔。", "溪頭凍水晴初漲，竹下名園晝不關。", "旋得歌辭教妓唱，遠尋梅艷喚人攀。", "如今尚有官拘束，解組歸來始是閑。"]'),
('cdd42671-7c8c-481d-b9ca-09c70078546f','和微之燕西湖','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三月韶華大半過，好花零謝已無多。',64,'全唐诗/poet.song.24000.json','["三月韶華大半過，好花零謝已無多。", "暮年光景如殘夢，浮世塵勞付浩歌。", "游子有時眠岸草，啼禽終日在庭柯。", "白頭不作垂鈎客，辜負春湖十里波。"]'),
('1b6a2995-b71d-4d22-8dc1-1f055602f731','和微之喜雪','韓維','宋','宋诗','song-poetry','','[]','凍雨吹花六出成，高樓一見瓦□□。',64,'全唐诗/poet.song.24000.json','["凍雨吹花六出成，高樓一見瓦□□。", "已驚密勢昏群岫，更想餘霖及列城。", "照水□□生秀氣，跳枝喜鵲弄和聲。", "曾陪舞蹈豐年□，□擁溫貂夢帝京。"]'),
('f0eecfe1-e3c8-4f08-95d9-0dc9e046fd21','和微之','韓維','宋','宋诗','song-poetry','','[]','庭訟蕭然晝景清，每因閑暇接耆英。',64,'全唐诗/poet.song.24000.json','["庭訟蕭然晝景清，每因閑暇接耆英。", "言詩屢奉從容論，對酒常懷淡泊情。", "解秩尚思嵩嶠色，入朝還聽禁鐘聲。", "憐君壯歲多留滯，不盡鵬摶九萬程。"]'),
('56f50c4e-c43f-4449-b356-dd3a913d6f55','登湖光亭','韓維','宋','宋诗','song-poetry','','[]','雪盡塵消徑露沙，公家池館似山家。',64,'全唐诗/poet.song.24000.json','["雪盡塵消徑露沙，公家池館似山家。", "翠痕滿地初生草，紅氣通林未放花。", "匝岸平波清照雁，壓城危榭斗回鴉。", "自慚白首猶圭組，此地年年賞物華。"]'),
('9296a70a-7a21-4073-ab51-07a098730695','千葉梅','韓維','宋','宋诗','song-poetry','','[]','南園卉木遍春光，獨愛瓊葩掩衆芳。',64,'全唐诗/poet.song.24000.json','["南園卉木遍春光，獨愛瓊葩掩衆芳。", "不爲雪摧緣正色，忽隨風至是真香。", "未經採折携樽酒，忍見飄零入野塘。", "醉客爲予簪白髪，欄邊幾作少年狂。"]'),
('c3e586aa-2ee5-4a70-aefc-6370592edd3d','曹通直以顔魯公墨迹題辭乞詩刊石','韓維','宋','宋诗','song-poetry','','[]','臨池餘事得忠臣，白刃林中不動身。',64,'全唐诗/poet.song.24000.json','["臨池餘事得忠臣，白刃林中不動身。", "見義捨生安爲己，懷諼保位獨何人。", "英名在世長如日，遺像於今凜若神。", "一覽精誠方自失，羞將累句刻蒼珉。"]'),
('88d174f0-4c34-4e42-a8e1-514c9c5148b6','答張念五見寄','韓維','宋','宋诗','song-poetry','','[]','林泉蕭灑逸平生，不識人間寵辱驚。',64,'全唐诗/poet.song.24000.json','["林泉蕭灑逸平生，不識人間寵辱驚。", "美質自全荆璞貴，嘉名長共洛波清。", "身雖貧約非原病，詩爲窮愁似孟精。", "命駕高蹤久無繼，一時風義獨歸程。"]'),
('55aaf491-3813-46b1-aad2-50653183e2f4','閑房書事示五弟及諸侄等獻肅公','韓維','宋','宋诗','song-poetry','','[]','老病歸休得桶樓，吾廬蕭灑樂天倪。',64,'全唐诗/poet.song.24000.json','["老病歸休得桶樓，吾廬蕭灑樂天倪。", "北窗偃卧都何有，東閣過從亦自揆。", "碧檜輕烟無鳥哢，綠槐風細或蟬嘶。", "世間萬事全如夢，豈得南華物我齊。"]'),
('4a7da023-3e5a-4943-a581-c29790deda6a','次韵','韓維','宋','宋诗','song-poetry','','[]','勢利拘牽無已時，超然真樂絕端倪。',64,'全唐诗/poet.song.24000.json','["勢利拘牽無已時，超然真樂絕端倪。", "家風淡寂從今見，人事塵勞與我暌。", "門外旌旗猶坌拂，轅間款段已鳴嘶。", "何當解組如初約，直與西京二傅齊。"]'),
('ded402de-3c4b-4608-98c9-7e1177cec218','和景仁之什','韓維','宋','宋诗','song-poetry','','[]','美疢隨冰釋，微陽應律生。',48,'全唐诗/poet.song.24000.json','["美疢隨冰釋，微陽應律生。", "嚴風散餘燠，密雪暗深更。", "預喜銜杯集，當期策杖行。", "知公有新慶，金奏動皇情。"]'),
('aa405794-a0c1-42cf-ad10-b2c614dcfb06','桃花菊  其一','韓維','宋','宋诗','song-poetry','','[]','誰測天工造化情，巧將紅粉傅金英。',64,'全唐诗/poet.song.24000.json','["誰測天工造化情，巧將紅粉傅金英。", "武陵溪上分佳色，陶令籬邊得異名。", "不使秋光全冷淡，却教陽艷再鮮明。", "甕頭消息香醪熟，何必黄花便可傾。"]'),
('0bcef28a-60b3-45ed-a6ef-ba7ce2ed85d1','桃花菊  其二','韓維','宋','宋诗','song-poetry','','[]','霜女星娥不俗情，施朱點出淺深更。',64,'全唐诗/poet.song.24000.json','["霜女星娥不俗情，施朱點出淺深更。", "平泉記上遺嘉品，本草經中注別名。", "氣得清凉開更早，色霑寒露久逾明。", "今朝樽酒來籬下，不爲重陽爲爾傾。"]'),
('a9db120f-8dda-4237-9bef-99463357c647','次韵奉同景仁答微之','韓維','宋','宋诗','song-poetry','','[]','鴉腹靈砂養就丹，知公不復更衰殘。',64,'全唐诗/poet.song.24000.json','["鴉腹靈砂養就丹，知公不復更衰殘。", "洛川花下經春醉，潩水亭邊盡日歡。", "白髪高吟思老筆，青娥嘉贈佇華鞍。", "淮陽過客如相問，莫道閑人姓范韓。"]'),
('f87c8c48-7aa3-411f-8583-35003f6fe4a3','覽景仁君實議樂以詩戲呈景仁','韓維','宋','宋诗','song-poetry','','[]','少年議樂至顛華，作得文章載滿車。',64,'全唐诗/poet.song.24000.json','["少年議樂至顛華，作得文章載滿車。", "律合鳳鳴猶是末，尺非天降豈無差。", "勞心未免爲詩刺，聚訟須防似禮家。", "一曲銀簧一杯酒，且於閑處避風沙。"]'),
('d47a41a3-6bc4-40c5-bfef-5c7b271239be','奉和樂道','韓維','宋','宋诗','song-poetry','','[]','昔聞有客薦揚雄，清世文章又見公。',64,'全唐诗/poet.song.24000.json','["昔聞有客薦揚雄，清世文章又見公。", "奏賦獨高天下士，辭榮遠繼古人風。", "懷賢不啻三秋久，置酒須期十日中。", "幸有紅芳粧點在，可無多愧白頭翁。"]'),
('4bab8774-14b5-4ddb-b1b9-90a8f5e3884c','和景仁湖中','韓維','宋','宋诗','song-poetry','','[]','繁花亂委茵鋪錦，弱柳交垂綠作籠。',64,'全唐诗/poet.song.24000.json','["繁花亂委茵鋪錦，弱柳交垂綠作籠。", "竹影入波添舊翠，橋陰橫岸見新紅。", "臨觴善謔如平日，落筆佳章有古風。", "早乏斯文華國體，更將何術代天工。"]'),
('e577633b-96df-42e4-81d5-90923fcb6c40','去冬蒙君實示嘉篇懶拙不即修謝臨書走筆深愧浼瀆','韓維','宋','宋诗','song-poetry','','[]','南園百草雨中秋，把燭題詩寄驛郵。',64,'全唐诗/poet.song.24000.json','["南園百草雨中秋，把燭題詩寄驛郵。", "意重不辭終日看，韵强深愧隔年酬。", "登山屢赴幽人約，築野猶稽聖主求。", "命駕幸無千里遠，春湖艤楫待君遊。"]'),
('ca663b02-ec12-49ec-b695-2b32ff0e6b48','寄題曹大夫棲真堂','韓維','宋','宋诗','song-poetry','','[]','聞君初欲挂冠纓，便構茲堂不日成。',64,'全唐诗/poet.song.24000.json','["聞君初欲挂冠纓，便構茲堂不日成。", "桐檜茂陰歸後得，烟霞高興坐中生。", "禪心皎月通宵靜，詩思寒泉徹底清。", "十五年來飽閑散，紛紛人世自浮榮。"]'),
('c64dc4e7-5318-4ab0-983d-3d5e8e1934ab','冬日喜雨呈穉卿景仁','韓維','宋','宋诗','song-poetry','','[]','嚴冬溫氣襲人間，忽聽繁聲慰病顔。',64,'全唐诗/poet.song.24000.json','["嚴冬溫氣襲人間，忽聽繁聲慰病顔。", "從律好風千里至，執權真令一朝還。", "頓抽隴麥全如揠，欲綻江梅已可攀。", "主尹勤民嘉歲望，徑携歌鼓樂幽閑。"]'),
('5bc67fa0-04db-4fdf-8f9e-d43ac840c003','次韵和相公九月八日所賜詩','韓維','宋','宋诗','song-poetry','','[]','叢頭金菊層層鬧，木末丹花艷艷紅。',64,'全唐诗/poet.song.24000.json','["叢頭金菊層層鬧，木末丹花艷艷紅。", "美景歲時暌壽斝，流光朝暮閱疏鍾。", "詩成洛社騰郵置，夢繞伊川捧杖從。", "早晚安車來就第，樽前重奏喜相逢。"]'),
('d178c3ab-a6f9-4171-9408-e0ea77b8dcca','宴湖上呈穉卿','韓維','宋','宋诗','song-poetry','','[]','熠熠螢光草際流，及時高宴落霞洲。',64,'全唐诗/poet.song.24000.json','["熠熠螢光草際流，及時高宴落霞洲。", "繁弦急管宜清月，細蕊濃芳艷晚秋。", "飛鷺欲來迎畫舫，跳鱗如喜脫金鈎。", "知公加數爲醇釀，應許閑官爛漫游。"]'),
('3e5881b4-2022-487f-801b-2dec31d511f8','和曾令綽買宅貽景仁','韓維','宋','宋诗','song-poetry','','[]','久治孤學慕軻丘，投老還鄉寡所求。',64,'全唐诗/poet.song.24000.json','["久治孤學慕軻丘，投老還鄉寡所求。", "蓬蓽隨緣安靜默，林泉乘興訪深幽。", "高門此地成君志，方駕何時寫我憂。", "白首故人知所待，一竿同釣鴨陂頭。"]'),
('1b91f59b-7075-44db-8e02-019891654853','和安國天鉢拈香','韓維','宋','宋诗','song-poetry','','[]','杖策乘緣利有生，聞風猶得耳根清。',64,'全唐诗/poet.song.24000.json','["杖策乘緣利有生，聞風猶得耳根清。", "去年俱是凝然體，存歿徒傷妄者情。", "靈骨不隨烟共盡，真心常與月孤明。", "世人欲識泥洹路，問取師今第幾程。"]'),
('d2edfd5d-668b-47eb-8571-3d77edef80ef','後園雜花特獻輒書呈子華兄','韓維','宋','宋诗','song-poetry','','[]','向晚低雲還作雨，稍寒飛雪又隨風。',64,'全唐诗/poet.song.24000.json','["向晚低雲還作雨，稍寒飛雪又隨風。", "新芽展盡枝頭綠，落蘤飄成水面紅。", "身外有名皆是妄，杯中無物未爲通。", "扁舟少待暗陽放，西閣何妨一醉同。"]'),
('e8875264-841d-49c0-8639-65dfa018d681','和子華兄方惜鶑聲之晚今忽聞之','韓維','宋','宋诗','song-poetry','','[]','山鳥凡禽處處鳴，獨憐清囀久無聲。',64,'全唐诗/poet.song.24000.json','["山鳥凡禽處處鳴，獨憐清囀久無聲。", "起從巖谷春風晚，飛過林塘霽日明。", "不爲好音輕俗耳，自逢真賞動詩情。", "少年樂事今拋盡，節物催人只自驚。"]'),
('ab966172-1019-4dfc-8808-7cd9dcf2a5af','陪景仁赴况之湖上燕集遇雨','韓維','宋','宋诗','song-poetry','','[]','炎蒸消盡作濃陰，湖上茲遊喜重尋。',64,'全唐诗/poet.song.24000.json','["炎蒸消盡作濃陰，湖上茲遊喜重尋。", "急雨洗開荷芰色，清風借出管弦音。", "凉生頓覺絺衣薄，歡至寧論酒盞深。", "善謔清談都有適，過從所得在知心。"]'),
('e0d71ce8-f7b5-473d-939e-5f0e873a1d1f','和子華湖上避暑','韓維','宋','宋诗','song-poetry','','[]','堤邊楊柳無窮碧，亭下芙蓉四面紅。',64,'全唐诗/poet.song.24000.json','["堤邊楊柳無窮碧，亭下芙蓉四面紅。", "島影低回明鏡裏，荷香浮動綠樽中。", "清心不厭飛山雨，動髪時欣過水風。", "鼎足坐談非俗侶，不歸名教即真空。"]'),
('56aed99e-98ac-4b67-86a0-f1a1c0b20f8b','和昌言太中','韓維','宋','宋诗','song-poetry','','[]','眉秀瞳青却少容，精神强健幾如公。',64,'全唐诗/poet.song.24000.json','["眉秀瞳青却少容，精神强健幾如公。", "相逢細雨開籬菊，自愧繁霜滿鬢蓬。", "談道遠追西域祖，題詩今得少陵翁。", "鋒車北去歸何日，且願從容一笑同。"]'),
('f7075c7a-0b12-4eb5-b323-3c74be887c6b','贈昌言太中','韓維','宋','宋诗','song-poetry','','[]','春風吹袂踰嵩嶺，秋雨隨軒過穎亭。',64,'全唐诗/poet.song.24000.json','["春風吹袂踰嵩嶺，秋雨隨軒過穎亭。", "達理偶同無剩語，論交雖晚便忘形。", "兩株枯木同危坐，數朵寒花伴獨醒。", "鴨子陂頭好光景，幾時重見聚華星。"]'),
('3ea764c9-33ee-43cf-8d36-25da2e07fb5b','和子華湖上書事','韓維','宋','宋诗','song-poetry','','[]','清霜彫遠木，潩水溢西陂。',48,'全唐诗/poet.song.24000.json','["清霜彫遠木，潩水溢西陂。", "畫鷁凌空界，鳴鷗矯翠漪。", "菊殘猶可折，竹密不容窺。", "物我同真際，誰當憚四知。"]'),
('faf8aef8-b906-4772-9d02-2a089461c53e','和况之提刑途中遇雪','韓維','宋','宋诗','song-poetry','','[]','雲凝野曠接高低，切切寒侵使者衣。',64,'全唐诗/poet.song.24000.json','["雲凝野曠接高低，切切寒侵使者衣。", "客路怳驚霜鬢改，家山回望玉觴飛。", "更添宿雨催花潤，未放春雷起蟄威。", "柳色壓堤清溜滿，艤船持酒待君歸。"]'),
('9d2f2707-d11d-4792-99e0-7b05df592b49','公時遺石榴','韓維','宋','宋诗','song-poetry','','[]','高冠趨尹君方掾，促席迎賓我已翁。',64,'全唐诗/poet.song.24000.json','["高冠趨尹君方掾，促席迎賓我已翁。", "交態不忘平日厚，歌聲猶似少年工。", "映階露菊秋吟苦，盈筥霜榴歲問通。", "每與東鄰話知舊，白頭强健幾人同。"]'),
('9f2d1168-7a4e-4d30-bee3-8ba76878fd3b','同三兄安公亭看雨','韓維','宋','宋诗','song-poetry','','[]','高堂六月苦炎曦，雨逐輕雷過後池。',64,'全唐诗/poet.song.24000.json','["高堂六月苦炎曦，雨逐輕雷過後池。", "水面凉生跳赤鯉，林端聲寂語黄鸝。", "翠深岸篠無風亂，紅重薔薇到地垂。", "清景雖嘉歡意少，白頭支策坐題詩。"]'),
('7f23e986-e20c-4f53-bc13-6d8020911c22','偶成寄曼叔','韓維','宋','宋诗','song-poetry','','[]','紅芳落盡鴨陂邊，白首傷春倍慘然。',64,'全唐诗/poet.song.24000.json','["紅芳落盡鴨陂邊，白首傷春倍慘然。", "自愧閑官消永日，獨吟佳句想當年。", "早休諸吏眠齋館，時引雙童上舞筵。", "聞說年來亦歸興，琳宮仙籍舊無員。"]'),
('f6a7e7c2-1597-4492-b81b-f88ef3f909e1','和君俞歲暮偶成','韓維','宋','宋诗','song-poetry','','[]','凍水迎風解，芳芽逐日新。',48,'全唐诗/poet.song.24000.json','["凍水迎風解，芳芽逐日新。", "不驚身漸老，還喜物皆春。", "髪短頻添雪，心虛不受塵。", "鷄豚如有燕，莫忘社中人。"]'),
('52725313-8731-4114-b52f-d71fc1d1e02c','和景仁賦才元寄牡丹圖','韓維','宋','宋诗','song-poetry','','[]','勝事常歸蜀，奇葩又驗今。',48,'全唐诗/poet.song.24000.json','["勝事常歸蜀，奇葩又驗今。", "仙官裁樣巧，彩筆費工深。", "白豈容施粉，紅須陋間金。", "不嗟珍賞異，千里見君心。"]'),
('6382aac8-cd27-49c6-9df3-04d6a21afa0f','登樓書事','韓維','宋','宋诗','song-poetry','','[]','病起思遐眺，茲樓寓一歡。',48,'全唐诗/poet.song.24000.json','["病起思遐眺，茲樓寓一歡。", "烟蕪連雨脚，秋稼入雲端。", "驚鷺銜魚起，饑鴉啄果殘。", "憑誰圖好景，畫手世無寬。"]'),
('cd64edff-3251-4bf9-a10b-205cdcdc0746','次韵君俞','韓維','宋','宋诗','song-poetry','','[]','世事真千變，年光又一新。',48,'全唐诗/poet.song.24000.json','["世事真千變，年光又一新。", "舉生皆是幻，熙我莫如春。", "嘯傲盈樽酒，詩書滿席塵。", "園林已芳意，懸榻待高人。"]'),
('5b1b93b4-77c2-488b-87e8-976a49b202eb','積雨成雪呈子華','韓維','宋','宋诗','song-poetry','','[]','寒威暗襲春和去，坐擁重裘僅自溫。',64,'全唐诗/poet.song.24000.json','["寒威暗襲春和去，坐擁重裘僅自溫。", "對景直須忘適適，隨機聊耳不言言。", "興來一笑非緣酒，道本無憂豈在萱。", "欲與何人論此意，竹風松雪滿西軒。"]'),
('0de03d57-0d44-4235-9230-8df649652666','和景仁','韓維','宋','宋诗','song-poetry','','[]','平池旋漲西山雨，密竹頻驚北戶風。',64,'全唐诗/poet.song.24000.json','["平池旋漲西山雨，密竹頻驚北戶風。", "垂箔屢銷檀炷紫，出門時看杏梢紅。", "酒成豈見甘而壞，花在須知色即空。", "只怪彫章今日至，不知清醉昨宵同。"]'),
('2ce7236d-059a-4a12-8960-3e9e4c66c481','登城樓呈子華','韓維','宋','宋诗','song-poetry','','[]','麥苗黄熟稻苗青，餉婦耘夫笑語聲。',64,'全唐诗/poet.song.24000.json','["麥苗黄熟稻苗青，餉婦耘夫笑語聲。", "樓上清風簾箔靜，田間白水鷺鷗輕。", "展親會集從容樂，娛老謳吟放曠情。", "羽孽漸消民食足，更無餘事計虧成。"]'),
('6bb24b5d-4078-4f4a-98a3-87e374437d4c','遊曲水園和景仁','韓維','宋','宋诗','song-poetry','','[]','樓峻城千堞，堤長竹萬竿。',120,'全唐诗/poet.song.24000.json','["樓峻城千堞，堤長竹萬竿。", "草芽生戢戢，花蕊落漫漫。", "走筆狂吟放，扶筇醉步跚。", "屢回宜舞袖，甘著墮游冠。", "野老來窺坐，沙禽不避觀。", "兩行桃艷暖，一道柳陰寒。", "縱棹非尋戴，掀車免效欒。", "官曹嗟倥傯，農事閔艱難。", "急景三春好，浮生幾日歡。", "康强直行樂，此興不應闌。"]'),
('0d5a94b9-bd0a-4844-8c49-63e6110037b9','又和子華','韓維','宋','宋诗','song-poetry','','[]','沉陰消盡見春和，初放扁舟泝綠波。',64,'全唐诗/poet.song.24000.json','["沉陰消盡見春和，初放扁舟泝綠波。", "水際踏青憐日暖，林間舉白爲花多。", "狂從田婦窺籬看，醉任家童刮鼓歌。", "年少縱歡饒點檢，老歡終不掛誰何。"]'),
('fc58677d-8ff5-4415-9769-c0499b25c29f','同化光飲象之家','韓維','宋','宋诗','song-poetry','','[]','又從鄰舍客，來折主人花。',48,'全唐诗/poet.song.24000.json','["又從鄰舍客，來折主人花。", "游處當年似，悲傷老去加。", "興長歌易放，情密語無譁。", "歸路生殘月，春風醉袂斜。"]'),
('dd9bf2bb-cf17-4de7-8349-fbfe7245bb99','襄城道中懷曼叔','韓維','宋','宋诗','song-poetry','','[]','吾交作尉地，南望一淹留。',48,'全唐诗/poet.song.24000.json','["吾交作尉地，南望一淹留。", "歲月催人老，山川記子遊。", "向城非昔勇，遇物更春愁。", "獨喜高陽近，嵐光逼馬頭。"]'),
('2eae30ca-4aaf-4694-a52b-fcf8f8f0af03','和謝主簿游西湖','韓維','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雲陰開剝日光穿，和氣隨風近酒船。',64,'全唐诗/poet.song.24000.json','["雲陰開剝日光穿，和氣隨風近酒船。", "湖面波清渾見底，樓頭山碧自生烟。", "興長不忍回孤棹，歌懶才能逐緩弦。", "因子樽前話歸計，醉魂先到峴山邊。"]'),
('9a01c957-8eff-4ebb-9bd8-995963c5603f','景仁招况之聞用歌舞望門而反作此戲之','韓維','宋','宋诗','song-poetry','','[]','一夜嚴風結素波，盍簪寧避曉寒多。',64,'全唐诗/poet.song.24000.json','["一夜嚴風結素波，盍簪寧避曉寒多。", "范滂攬轡方清俗，墨子回車豈惡歌。", "雲外雁寒驚歲晚，林間鴉語弄春和。", "知君不久承寬詔，始奈紅裙綠酒何。"]'),
('61cf85ff-8edd-4ea5-a079-a43a4ff5e0ff','對雪看梅','韓維','宋','宋诗','song-poetry','','[]','持梅况酒誠爲得，對雪看梅始見真。',64,'全唐诗/poet.song.24000.json','["持梅况酒誠爲得，對雪看梅始見真。", "失素定應潛送臘，露紅如欲巧矜春。", "神凝姑射今仍在，雲覆巫峰曉更新。", "誰識仙家事嚴秘，舞妍妝靚不傳人。"]'),
('870dbe91-1516-4f1d-8f0f-90750866b626','襄柑分惠景仁以詩將之','韓維','宋','宋诗','song-poetry','','[]','荆州解紱十經春，迴夢青林繞漢濱。',64,'全唐诗/poet.song.24000.json','["荆州解紱十經春，迴夢青林繞漢濱。", "霜氣輕寒催柑實，渚波餘潤作甘津。", "僧園採掇寧論數，客路奔馳竟占新。", "雪意垂收高會缺，分金聊助席間珍。"]'),
('350f7c83-4104-4072-ae9b-872ce9b086e7','答微之','韓維','宋','宋诗','song-poetry','','[]','南圃携樽數，西陂縱棹同。',48,'全唐诗/poet.song.24000.json','["南圃携樽數，西陂縱棹同。", "除書褒晚歲，歸馭觴西風。", "節物蕭條後，交游寂寞中。", "何時還一笑，池上舞驚鴻。"]'),
('070eaf5a-ec77-4d57-a427-cf5a18336a50','和沖公上人','韓維','宋','宋诗','song-poetry','','[]','遠色分諸島，清光湛一陂。',48,'全唐诗/poet.song.24000.json','["遠色分諸島，清光湛一陂。", "鳥行排夕照，竹影亂風漪。", "道體煩摩撮，禪心絕占窺。", "由來輸范老，佛法不曾知。"]'),
('e3811cec-e2a5-4cdc-b70d-42ea60830d9c','和盈祖中散見寄','韓維','宋','宋诗','song-poetry','','[]','朝言民事兩無裨，謝病還家獨掩扉。',64,'全唐诗/poet.song.24000.json','["朝言民事兩無裨，謝病還家獨掩扉。", "散髪時從溪叟樂，荷鋤仍逐野農歸。", "山當樓檻千螺髻，柳繞湖波萬羽旂。", "鵰鷃逍遥各天分，搶榆何意著雲飛。"]'),
('3ebb44c6-8cdb-45d5-9835-f7c7add43fd3','和景仁同游南園','韓維','宋','宋诗','song-poetry','','[]','喜公新就好林塘，方駕來遊屬盛陽。',64,'全唐诗/poet.song.24000.json','["喜公新就好林塘，方駕來遊屬盛陽。", "廣厦陰凉迴暑氣，平波炎赫變秋光。", "酒中未免分清濁，身外何曾校短長。", "地勝人高多樂事，須知洵美是吾鄉。"]'),
('a7ddf52b-6c40-4f8d-8f38-9fef5f0be40a','和三兄游湖','韓維','宋','宋诗','song-poetry','','[]','竹陰迴抱柳陰敷，石色青青潤不枯。',64,'全唐诗/poet.song.24000.json','["竹陰迴抱柳陰敷，石色青青潤不枯。", "暫到已經風力勁，更清須待月輪孤。", "波涵天影迷高下，雲覆山光變有無。", "暑退疾清人意健，縱吟狂醉是良圖。"]'),
('71081f22-0edf-4880-bdfc-140dcfdcbaba','和景仁探春  其一','韓維','宋','宋诗','song-poetry','','[]','山色青螺髻，清波綠鴨頭。',48,'全唐诗/poet.song.24000.json','["山色青螺髻，清波綠鴨頭。", "已欣春事起，那問歲陰流。", "玉蟻新浮盎，金鱗恰上鈎。", "衰年怯多酌，尤怕范家甌。"]'),
('347071c1-007f-4188-9799-0d555c84fbf4','和景仁探春  其二','韓維','宋','宋诗','song-poetry','','[]','才疏非所用，身退此其時。',48,'全唐诗/poet.song.24000.json','["才疏非所用，身退此其時。", "靜默安虛室，憂虞履薄凘。", "景和聞鵲稔，花近候梅知。", "杖履從茲數，非公孰與期。"]'),
('abc51bed-02df-458d-840a-16b6c35d89b4','和况之','韓維','宋','宋诗','song-poetry','','[]','湖上和風艷翠漪，柳枝摇動草芽齊。',64,'全唐诗/poet.song.24000.json','["湖上和風艷翠漪，柳枝摇動草芽齊。", "珍禽綵翼嬉晴日，游女紅裙上大堤。", "新試畫船浮鷁首，却慚美盎乏駝蹄。", "喜君不負持杯約，正是桃花水滿溪。"]'),
('3972d2b1-2f09-4fae-ae34-7b65e287c15c','和子華兄聞布穀聲而鶑聲寂然','韓維','宋','宋诗','song-poetry','','[]','楊花飛盡葉成陰，坐閱啼禽百種聲。',64,'全唐诗/poet.song.24000.json','["楊花飛盡葉成陰，坐閱啼禽百種聲。", "戴勝催耕當是月，杜鵑遺恨豈今生。", "及時燕樂風騷急，感物傷嗟老大情。", "自笑拙艱成底事，十年不聽上林鶑。"]'),
('f3defa5a-d7e9-4a53-9aee-ddb919897130','和景仁元夕  其一','韓維','宋','宋诗','song-poetry','','[]','月上朱樓角，風摇翠篠層。',48,'全唐诗/poet.song.24000.json','["月上朱樓角，風摇翠篠層。", "傳聲迴步輦，滿目爛行燈。", "簫鼓千門沸，弓刀萬馬騰。", "詩翁懷盛事，眉雪慘霜棱。"]'),
('b80fafdb-ce74-4081-ae61-36e4008e603a','和景仁元夕  其二','韓維','宋','宋诗','song-poetry','','[]','禁戶千通鼓，天街萬點燈。',48,'全唐诗/poet.song.24000.json','["禁戶千通鼓，天街萬點燈。", "懷君瑩如玉，驅馬不嫌冰。", "樂事看流俗，狂游記舊朋。", "回思真夢幻，不待訪林僧。"]'),
('9a5eb102-afbe-4a9a-80ff-c6aa130f7f38','展江亭看海棠遇風','韓維','宋','宋诗','song-poetry','','[]','少陵昔日富辭華，愁見飄零萬點花。',64,'全唐诗/poet.song.24000.json','["少陵昔日富辭華，愁見飄零萬點花。", "寫物高才從古少，傷春情緒此時加。", "恨無巧語讒風伯，直欲狂圖繫雨車。", "莫怪晚來觴屢釂，白頭判得醉流霞。"]'),
('dc7dc011-5593-4524-850c-55836782c115','送李宣德爲縣太原','韓維','宋','宋诗','song-poetry','','[]','昔叨符守訪鄉評，守節安貧得水名。',64,'全唐诗/poet.song.24000.json','["昔叨符守訪鄉評，守節安貧得水名。", "道在莫嗟爲邑晚，祿微須喜及親榮。", "風吹白菊籬邊別，雨落黄榆塞下行。", "善撫疲羸修分職，邊庭無事正休兵。"]'),
('348bba5e-92be-4e1a-8beb-79a9fd5ebefd','和君俞屬疾見詒','韓維','宋','宋诗','song-poetry','','[]','密桐新篠晝陰陰，獨想禪房燕□□。',64,'全唐诗/poet.song.24000.json','["密桐新篠晝陰陰，獨想禪房燕□□。", "□□□□何者病，一塵不立本來心。", "生涯易足惟高枕，物累難除是苦吟。", "乘興幾時回杖履，後池泉溜有餘音。"]'),
('aa4808ef-9a84-4967-8877-5830bea77401','和太素喜景仁新宅','韓維','宋','宋诗','song-poetry','','[]','處仁由智古常然，賢者寧同聚所寰。',64,'全唐诗/poet.song.24000.json','["處仁由智古常然，賢者寧同聚所寰。", "植木便知如渭水，結茅仍得見箕山。", "杯深不許嘉賓訴，花小須防稚子攀。", "投紱歸來無異事，許公詩酒斷生還。"]'),
('d5ccb706-e277-47b1-96b7-ae04d058428a','况之席上作','韓維','宋','宋诗','song-poetry','','[]','桐葉翻飛荷芰香，好風吹暑作清凉。',64,'全唐诗/poet.song.24000.json','["桐葉翻飛荷芰香，好風吹暑作清凉。", "便驚簾幕生秋氣，徑促金絲盡羽觴。", "浮世已諳身是幻，高歌莫笑老仍狂。", "知君不久還符竹，爛醉猶須教十場。"]'),
('80858ffe-5ac8-429b-a6c0-25f9fae72be7','和昌言謁見景仁所居話及洛事','韓維','宋','宋诗','song-poetry','','[]','重遷豈是賢人累，樂內非期俗子誇。',64,'全唐诗/poet.song.24000.json','["重遷豈是賢人累，樂內非期俗子誇。", "萬瓦生烟新起第，一經消日舊傳家。", "浮舟共愛清湖色，披竹時尋曲水涯。", "未信閑中無事役，隔年貪看別都花。"]'),
('132f835d-47a4-4ab7-aa38-5db6abe8783c','和貢甫','韓維','宋','宋诗','song-poetry','','[]','十年燈翳視浮榮，兀坐翛然槁木形。',64,'全唐诗/poet.song.24000.json','["十年燈翳視浮榮，兀坐翛然槁木形。", "別後情懷非往日，老來光景似流星。", "厚恩未報心徒赤，多病何從髪復青。", "一覽彫章思舊好，忽如醒病得初酲。"]'),
('ae3e72e4-9358-47c7-98c5-c33d191e4d04','賞梅花有懷曼叔','韓維','宋','宋诗','song-poetry','','[]','逍遥堂下去年梅，還向春來撩亂開。',64,'全唐诗/poet.song.24000.json','["逍遥堂下去年梅，還向春來撩亂開。", "白髪每思同泛客，紅芳應怪久停杯。", "鴨頭新浪暌游泛，鷺羽遺民寄剸裁。", "聞說鈴齋多暇豫，何時度曲逐風來。"]'),
('d1afe36f-64ca-4cb7-85a9-6996d13331dc','送曹大夫歸家','韓維','宋','宋诗','song-poetry','','[]','飛盡楊花見綠陰，飄然輕蓋返家林。',64,'全唐诗/poet.song.24000.json','["飛盡楊花見綠陰，飄然輕蓋返家林。", "野堂泥落歸雙燕，紋簟風清戲一禽。", "秀麥柔桑皆有望，高軒華衮久無心。", "知君自得閑中樂，早寄新詩別後吟。"]'),
('061c27dc-d9f2-4385-93b9-53912c6eaf76','寄微之通議','韓維','宋','宋诗','song-poetry','','[]','十五年來自在身，晴天萬里見孤雲。',64,'全唐诗/poet.song.24000.json','["十五年來自在身，晴天萬里見孤雲。", "閑中密迹常同俗，老去忠言尚愛君。", "一坐精神歸素髮，兩行歌舞避紅裙。", "早梅時節華燈夜，日佇車公共醉醺。"]'),
('b1633046-3440-4eb1-9acb-358fa074f850','和宋中散寄題景仁新池','韓維','宋','宋诗','song-poetry','','[]','北顧興王府，東瞻象日畿。',120,'全唐诗/poet.song.24000.json','["北顧興王府，東瞻象日畿。", "稻塍常借潤，黍尺詎能晞。", "鷺浴菖芽短，魚跳荇菜肥。", "樂亭初置酒，試舞旋裁衣。", "逸冀相從老，冥鴻自在飛。", "月游刳小艇，雨釣築新磯。", "栽插期春事，追游惜晚暉。", "氣同均我爾，道勝絕從違。", "安燕興棠棣，艱勤陋采薇。", "如何宋中散，留滯不成歸。"]'),
('53fbad9e-c83b-4454-b82b-86e652cd2248','范公新池','韓維','宋','宋诗','song-poetry','','[]','忘機人似漢川陰，取友從來亦斷金。',64,'全唐诗/poet.song.24000.json','["忘機人似漢川陰，取友從來亦斷金。", "華屋萬楹開里第，清池十頃是家林。", "笙歌喧甚猶能默，觴斝飛餘不廢吟。", "便欲與君從此適，藕花風外一披襟。"]'),
('effd5cb5-04cb-4b03-b076-6e0bd5778caf','和景仁喜晴','韓維','宋','宋诗','song-poetry','','[]','濃陰開積晦，和氣散餘凄。',48,'全唐诗/poet.song.24000.json','["濃陰開積晦，和氣散餘凄。", "碧愛城陰草，紅知花下泥。", "啼鷄一聲盡，歸雁數行低。", "溪路桃爭發，須防去棹迷。"]'),
('47512c5d-7e88-495b-a08c-003cd51cad83','黄葵花  其一','韓維','宋','宋诗','song-poetry','','[]','池上朝來玉露零，檀心先向日邊傾。',64,'全唐诗/poet.song.24000.json','["池上朝來玉露零，檀心先向日邊傾。", "側金巧樣新成盞，蒸栗溫姿始號瓊。", "芍藥未應推艷品，牡丹須合避姚名。", "秋花碎瑣誰能數，醉眼逢君亦自明。"]'),
('5737b30f-601a-4741-af76-44878f405c9e','黄葵花  其二','韓維','宋','宋诗','song-poetry','','[]','春花夏蕊已飄零，秀出秋芳一朵傾。',64,'全唐诗/poet.song.24000.json','["春花夏蕊已飄零，秀出秋芳一朵傾。", "稟賦定應全得土，遮圍須合盡彫瓊。", "鵠衣照水勻顔色，仙袂無塵莫壯名。", "應笑菊花妍意少，籬邊冷落伴淵明。"]'),
('ff334956-b39b-4f26-b70a-31d21d1e0bf7','和微之宴景仁新第','韓維','宋','宋诗','song-poetry','','[]','華構經營不日成，宛如圖畫著丹青。',64,'全唐诗/poet.song.24000.json','["華構經營不日成，宛如圖畫著丹青。", "溫貂密坐浮香篆，綠蟻盈斟照弁星。", "得地新篁皆嫋嫋，凌霜修檜自亭亭。", "祝公眉壽長康樂，不學癡人事醉醒。"]'),
('37a56359-feee-40aa-a1e1-163e8cdc169a','寄侯官知縣呂宣德','韓維','宋','宋诗','song-poetry','','[]','鴨子陂邊昔並遊，別來頻見藕花秋。',64,'全唐诗/poet.song.24000.json','["鴨子陂邊昔並遊，別來頻見藕花秋。", "十年已慣身蕭散，百里空嗟手滯留。", "道在豈常忘塞馬，機閒真可伴沙鷗。", "平時几案應多暇，還有妖歌近耳不。"]'),
('7c7480c7-217f-4963-b16f-133c4b1b7993','和微之宴張大夫家園','韓維','宋','宋诗','song-poetry','','[]','郎官高會一時賢，勝踐幽棲近接聯。',64,'全唐诗/poet.song.24000.json','["郎官高會一時賢，勝踐幽棲近接聯。", "敢論懷黄誇故國，聊欣垂白上華筵。", "同心况是論交舊，二首何疑貴老年。", "東里作詩成故事，明珠當盡落吾前。"]'),
('d7ec7fb8-a1b8-4fbf-a664-ba52a39ad126','和王都尉','韓維','宋','宋诗','song-poetry','','[]','乘槎天上客，脫帽酒中仙。',48,'全唐诗/poet.song.24000.json','["乘槎天上客，脫帽酒中仙。", "談笑非俗韵，歡欣忘我年。", "浩歌輕白雪，密意得青蓮。", "詩就西樓月，留爲好事傳。"]'),
('194941bc-08c8-4b3c-984c-09211d7f1abb','和子華安國明空頌','韓維','宋','宋诗','song-poetry','','[]','欲識真空理，須明動用間。',48,'全唐诗/poet.song.24000.json','["欲識真空理，須明動用間。", "色心全不礙，生死豈相關。", "卷箔凉風動，焚香晝景閒。", "回頭大行路，滿目是青山。"]'),
('f22cfdf2-0ccc-4ea0-bdb3-2158c9f35f29','和三兄晚飲','韓維','宋','宋诗','song-poetry','','[]','乍去炎氛濁暑中，高懷幽事不如窮。',64,'全唐诗/poet.song.24000.json','["乍去炎氛濁暑中，高懷幽事不如窮。", "乍憐老竹梢雲碧，已見新梨著露紅。", "回雪舞腰來洛浦，仰天歌韵有秦風。", "雄圖壯節消磨盡，所得清樽一笑同。"]'),
('aa4bdd66-68a6-4981-842b-d83602a1e67a','送辛十七作尉鹽城','韓維','宋','宋诗','song-poetry','','[]','少年嘉譽冠諸生，白首青衫僅有成。',64,'全唐诗/poet.song.24000.json','["少年嘉譽冠諸生，白首青衫僅有成。", "千里辛勤州縣職，一觴凄慘里閭情。", "家臨潁水花催發，柳繞長堤絮撲行。", "寸祿折腰何必去，道存心在即淵明。"]'),
('e1b0beb7-9b00-4532-ba11-83b13db59fc8','棣華堂','韓維','宋','宋诗','song-poetry','','[]','錦衣齎鉞耀當年，心在王家迹在邊。',64,'全唐诗/poet.song.24000.json','["錦衣齎鉞耀當年，心在王家迹在邊。", "論議每先諸將勇，規模仍襲仲兄賢。", "一朝華棟飛翬動，四坐清觴插羽傳。", "欲賦酬章慚懦武，白頭終日誦塵編。"]'),
('dc69cfd8-c96e-48e8-8a6a-6387ef22b2f8','和十一侍郎','韓維','宋','宋诗','song-poetry','','[]','地傳槐大井泉深，昔侍先庭此鎮臨。',64,'全唐诗/poet.song.24000.json','["地傳槐大井泉深，昔侍先庭此鎮臨。", "奉使共成三世澤，思親還愴百年心。", "懷金豈足驕顔氏，抱甕徒勞拙漢陰。", "抖擻塵中千萬慮，海風高處坐披襟。"]'),
('8fe0aaa3-3158-467b-bc4b-daec2499eeab','送門客李秀才赴省試','韓維','宋','宋诗','song-poetry','','[]','傷思易子聞前戒，務學求師是至言。',64,'全唐诗/poet.song.24000.json','["傷思易子聞前戒，務學求師是至言。", "豈有車魚延上客，欲將詩禮示諸孫。", "青衿散後人千里，黄菊開時酒一尊。", "壯歲雄圖當自勉，未應長嘯入蘇門。"]'),
('02ff689e-d058-4c29-9bc5-b211bcb80e0a','累日不到中園晚步閑咏','韓維','宋','宋诗','song-poetry','','[]','南陌西陂趁物華，歸來扶杖重咨嗟。',64,'全唐诗/poet.song.24000.json','["南陌西陂趁物華，歸來扶杖重咨嗟。", "綠羅淺淡新開葉，紅玉玲瓏半謝花。", "泉溜拍池初跳鯉，柳枝含雨不勝鴉。", "啼禽亦有傷春恨，百種鳴聲到落霞。"]'),
('13361802-cb05-45f2-89de-aed81a0e1705','和子華同程中散燕湖上','韓維','宋','宋诗','song-poetry','','[]','林塘瀟灑夏陰初，翠竇紅芳助燕娛。',64,'全唐诗/poet.song.24000.json','["林塘瀟灑夏陰初，翠竇紅芳助燕娛。", "不用俗音流樂府，自期仙御下蓬壺。", "金跳巨鯉開紋浪，雪灑群鴉度綠梧。", "日落人歸尤勝絕，籃輿回首盡城隅。"]'),
('5af564be-9dc8-4d28-8dc2-6d9cec0b51fd','和景仁寒食','韓維','宋','宋诗','song-poetry','','[]','韶華已過半，感嘆固多同。',48,'全唐诗/poet.song.24000.json','["韶華已過半，感嘆固多同。", "萬室初藏火，千花競笑風。", "林光高藹藹，山氣遠葱葱。", "灑淚松阡里，傷心白髪翁。"]'),
('789d0f25-2f8b-44c8-9a9b-1592dbbb0d19','和景仁同稚卿湖光亭對雪','韓維','宋','宋诗','song-poetry','','[]','共喜忘懷勢利間，每逢嘉景便開顔。',64,'全唐诗/poet.song.24000.json','["共喜忘懷勢利間，每逢嘉景便開顔。", "梅花冒雪輕紅破，湖面先春嫩綠還。", "浮蟻濃來當爲釂，冥鴻高舉不須攀。", "我慚習氣歡狂在，未及仙翁一紀閑。"]'),
('c1c525ff-b354-424b-98cf-6231c7800d8d','和仲巽在高陽日作詩見懷而不見寄','韓維','宋','宋诗','song-poetry','','[]','常記當年并馬鞍，翛然無事世塵間。',64,'全唐诗/poet.song.24000.json','["常記當年并馬鞍，翛然無事世塵間。", "獨憐交契如君少，仍喜官曹共我閑。", "却顧舊遊空歲月，欲傳佳句邈河關。", "從今會合尤須數，此別相看鬢已斑。"]'),
('88d88e4e-862c-44bd-b373-099ab3c5430d','王巖叟招飲南園','韓維','宋','宋诗','song-poetry','','[]','翠木珍叢百畝間，我來雖晚及春殘。',64,'全唐诗/poet.song.24000.json','["翠木珍叢百畝間，我來雖晚及春殘。", "未嗟流景飄蓬疾，猶喜餘芳對酒看。", "斜照舒遲明埤堄，清陰迢遞覆欄干。", "憑君莫剪高花盡，留插遊人醉後冠。"]'),
('ccc5ef2b-2bb8-48fd-bf84-01d7a994a9ea','謝堯夫寄新酒','韓維','宋','宋诗','song-poetry','','[]','故人一別兩重陽，每欲從之道路長。',64,'全唐诗/poet.song.24000.json','["故人一別兩重陽，每欲從之道路長。", "有客忽傳龍坂至，開樽如對馬軍嘗。", "定將瓊液都爲色，疑有金英借密香。", "却笑當年彭澤令，籬邊終日嘆空觴。"]'),
('c480a5ca-b706-4c56-b712-13feb3c41b83','寄致仕李洵大夫','韓維','宋','宋诗','song-poetry','','[]','買得田園便退身，世間今作自由人。',64,'全唐诗/poet.song.24000.json','["買得田園便退身，世間今作自由人。", "不爭路上風波靜，無相光中日月新。", "紅葉委階非異物，碧峰當戶見全真。", "知君未放狂心歇，興在陶公漉酒巾。"]'),
('64a12fa3-893c-4aa5-9d7b-b7f4ede7d605','送海印住香嚴頌','韓維','宋','宋诗','song-poetry','','[]','枕石漱流塵外趣，隨緣應物谷中聲。',64,'全唐诗/poet.song.24000.json','["枕石漱流塵外趣，隨緣應物谷中聲。", "更無賓主能酬對，自有兒孫可使令。", "萬古清風歸法語，一輪明月伴經行。", "鰲山成道知何日，時佇雷音警妄情。"]'),
('8c8e5792-84fb-462e-8959-ca966c7f55be','宴逍遥堂','韓維','宋','宋诗','song-poetry','','[]','朱顔綠鬢盡才良，永日逍遥宴此堂。',64,'全唐诗/poet.song.24000.json','["朱顔綠鬢盡才良，永日逍遥宴此堂。", "樂事已先桃艷動，歡情仍共雪花狂。", "夢中身世知虛實，醉裏光陰任短長。", "榮辱譽非那復問，無何有處是吾鄉。"]'),
('769d2fac-2571-44ad-9249-dd1de4bf68cf','贈香嚴敷老慧照上人','韓維','宋','宋诗','song-poetry','','[]','勝地名藍代有人，惟公傳得國師真。',64,'全唐诗/poet.song.24000.json','["勝地名藍代有人，惟公傳得國師真。", "蒼崖翠壁風流在，傑閣隆樓指顧新。", "半死半生排俗世，一顰一笑是家珍。", "欲知聞法諸天喜，庭下于今有瑞筠。"]'),
('6550a680-1cfa-4ded-b615-030b4d9500c7','公美侍郎賦詩見詒次韵答謝','韓維','宋','宋诗','song-poetry','','[]','哭兄悲友老來情，默默終朝究道精。',64,'全唐诗/poet.song.24000.json','["哭兄悲友老來情，默默終朝究道精。", "雙轂幸回賢者駕，一觴聊展故人誠。", "身隨風力常無住，辯若河源每自傾。", "早晚東城見華屋，與君垂白話無生。"]'),
('6b11791d-eff9-484f-a2e0-c83d0decad30','和三哥立春即事','韓維','宋','宋诗','song-poetry','','[]','青帝收寒歲令回，綵幡今勝下天來。',64,'全唐诗/poet.song.24000.json','["青帝收寒歲令回，綵幡今勝下天來。", "人聲愷樂歸歌缶，風氣恬和拂壽杯。", "髪逐時光明似雪，心諳世味冷于灰。", "西堂梅蕊今年晚，應待安輿到始開。"]'),
('24727432-8ada-46ad-9a6c-5d4c698777ea','和子華見寄','韓維','宋','宋诗','song-poetry','','[]','松柏無心自後凋，此心無物更寥寥。',64,'全唐诗/poet.song.24000.json','["松柏無心自後凋，此心無物更寥寥。", "伯夷豈是歸周晚，孟子空嗟出晝遥。", "談道每嗤猶有待，當官常欲取非招。", "荒園寂寞無誰語，蘭菊幽香沒艾蕭。"]'),
('3e87d8f0-f747-4ca7-9c9c-0496a67bdb7a','和太素大雪苦寒','韓維','宋','宋诗','song-poetry','','[]','晨興出戶望，一色四方齊。',48,'全唐诗/poet.song.24000.json','["晨興出戶望，一色四方齊。", "旋委清池失，偏欺翠竹低。", "杯深憐絕景，毫健得新題。", "麗藻思風絮，衰顔怯凍梨。"]'),
('5bae2088-da4f-44f6-bec2-048cf94eca70','答杜孝錫觀鄉老堂','韓維','宋','宋诗','song-poetry','','[]','華髪蒼然亮直身，誰將綵筆欲傳神。',64,'全唐诗/poet.song.24000.json','["華髪蒼然亮直身，誰將綵筆欲傳神。", "論功顧我常流汗，好事煩君爲拂塵。", "漢閣寂寥班氏贊，伊川瀟灑白公真。", "懷賢却坐酬嘉句，空覺中郎善愧人。"]'),
('dd2b9a28-c9ef-4f0e-b8be-a0663a5c19f9','送太素南遊','韓維','宋','宋诗','song-poetry','','[]','戕性傷生俗所同，人間今見百年翁。',64,'全唐诗/poet.song.24000.json','["戕性傷生俗所同，人間今見百年翁。", "無稽不學公超霧，有待猶嗤禦寇風。", "心到靈源千慮息，氣隨真火百骸通。", "臨觴不用嗟離闊，達者相忘道術中。"]'),
('add1420b-0e58-46dd-920f-7725c1857627','和定國廷評','韓維','宋','宋诗','song-poetry','','[]','孤身萬里逐流人，兩見炎洲末利春。',64,'全唐诗/poet.song.24000.json','["孤身萬里逐流人，兩見炎洲末利春。", "勛族每蒙朝念舊，聖恩方與士更新。", "忘憂自有禪心靜，禦瘴無先道氣醇。", "傅野爲霖非我事，願聞雷雨躍窮鱗。"]'),
('0639d78d-b58d-46f6-b4fe-e8859869ebe4','和昌言喜雪','韓維','宋','宋诗','song-poetry','','[]','萬里多仁德有鄰，故交仍珮左魚新。',64,'全唐诗/poet.song.24000.json','["萬里多仁德有鄰，故交仍珮左魚新。", "歡娛每恨流陰駛，談笑幾還太古淳。", "浮蟻生光盈壽斝，驚鴻取勢落華茵。", "題詩寂寞高眠冷，笑殺尊前起舞人。"]'),
('4b4f2138-b550-4a16-a38e-a73a258ac063','再和昌言喜雪  其一','韓維','宋','宋诗','song-poetry','','[]','精禱潛通上下神，恍然佳氣一朝新。',64,'全唐诗/poet.song.24000.json','["精禱潛通上下神，恍然佳氣一朝新。", "隆樓傑閣偏宜曉，槁木殘荄盡變春。", "有客裁詩傳錦段，誰家度曲試朱唇。", "相思不得相從樂，虛作箕嵩無事人。"]'),
('3636e0f0-63f6-41eb-9a0c-ecc36b91335a','再和昌言喜雪  其二','韓維','宋','宋诗','song-poetry','','[]','愧無奇策輔吾皇，乞得閑官老故鄉。',64,'全唐诗/poet.song.24000.json','["愧無奇策輔吾皇，乞得閑官老故鄉。", "壯志未甘悲白髪，歡情猶看舞紅粧。", "長歌不計閑光景，吟苦難滋舊肺腸。", "多謝同心二三友，每傳佳句挹華觴。"]'),
('898c93da-e1e6-4fe7-86d3-a8e71ecbac6e','玉汝弟創治新居作詩見詒次韵爲答','韓維','宋','宋诗','song-poetry','','[]','止足嘉言每念茲，不應華髪嘆歸遲。',64,'全唐诗/poet.song.24000.json','["止足嘉言每念茲，不應華髪嘆歸遲。", "非關啟第誇三戰，直爲營巢欠一枝。", "盛放清風來北戶，細分鳴溜入西池。", "十年契闊多遺恨，今日欣同仲氏篪。"]'),
('ba2f1d21-74f3-4c26-b7da-151b5d3950f9','次韵玉汝弟乞致仕不允','韓維','宋','宋诗','song-poetry','','[]','人生大節在行藏，七十歸休有舊章。',64,'全唐诗/poet.song.24000.json','["人生大節在行藏，七十歸休有舊章。", "紅旆碧幢雖帝寵，紫嵩清潁是吾鄉。", "老依蓮社心沖寞，夢繞榆關路杳茫。", "何日安車解歸鞅，濁醪鷄黍晏東崗。"]'),
('b332152c-2216-4792-bc94-3a1fbb009131','寄謝師直','韓維','宋','宋诗','song-poetry','','[]','十年三退卧吾廬，解組歸來始定居。',64,'全唐诗/poet.song.24000.json','["十年三退卧吾廬，解組歸來始定居。", "數畝家園荒杞菊，一池秋水拂龜魚。", "臨花對月難忘酒，咏古懷賢不廢書。", "更欲兩忘真俗累，逍遥常御白牛車。"]'),
('b6b6893b-9d09-4ff0-a754-be96188f22e0','送芳公長老歸法雲','韓維','宋','宋诗','song-poetry','','[]','水際茅亭竹下庵，清談竟夕不知厭。',64,'全唐诗/poet.song.24000.json','["水際茅亭竹下庵，清談竟夕不知厭。", "伽佗善巧何能繼，經藏幽深亦許覘。", "額內珠存雖本有，眼中金落復誰拈。", "圓通到日如相問，爲道春來米價添。"]'),
('0c4133e5-3ba6-4787-9f39-7735cf645d6e','送崔朝請通判徐州','韓維','宋','宋诗','song-poetry','','[]','與君仍世接游從，造次相敦德義中。',64,'全唐诗/poet.song.24000.json','["與君仍世接游從，造次相敦德義中。", "善繼家聲名父子，不追時好古人風。", "流光豈受長繩繫，妙道才容一線通。", "待得鈴齋民訟簡，更將此理問龐公。"]'),
('de6cde0c-4eac-4fe5-aee1-a8f8061eac21','送曾通直入京','韓維','宋','宋诗','song-poetry','','[]','敏學高文俊茂身，少年今見魯公孫。',64,'全唐诗/poet.song.24000.json','["敏學高文俊茂身，少年今見魯公孫。", "明心早得無生意，清耳常聞有味言。", "綠鴨陂中春縱棹，芰荷池上雨移樽。", "臨分有贈非他物，聲利精忘道始存。"]'),
('7e27d256-fde1-4a66-9dae-c1be6c1285a2','呈諸先輩','韓維','宋','宋诗','song-poetry','','[]','謝事歸來老白頭，杜門終日絕營求。',64,'全唐诗/poet.song.24000.json','["謝事歸來老白頭，杜門終日絕營求。", "顧慚義禮非先得，竊幸英豪許並游。", "介壽又逢春酒熟，貽詩常駭暗珠投。", "自慚筋力難爲禮，不及低回奉獻酬。"]'),
('c066932b-cc18-4f8f-b852-6df8374d886d','送堯夫知陳州','韓維','宋','宋诗','song-poetry','','[]','亮節金堅氣玉溫，入登廊廟出藩垣。',64,'全唐诗/poet.song.24000.json','["亮節金堅氣玉溫，入登廊廟出藩垣。", "談經每盡先儒意，議政居多長者言。", "恩恤疲羸蠲重賦，禮加耆耄屈常尊。", "白頭但祝公歸早，南陌東陂并短轅。"]'),
('b534542d-43d2-41da-a113-c0031761c0c2','贈實際英上人','呂江','宋','宋诗','song-poetry','','[]','實際即爲誠，中庸說著形。',24,'全唐诗/poet.song.240000.json','["實際即爲誠，中庸說著形。", "曉來雷雨過，七十二峰青。"]'),
('53dc40db-dbde-4074-9dff-8b6a98d87846','棲白庵','呂江','宋','宋诗','song-poetry','','[]','門外竹千箇，崖顛兩徑分。',48,'全唐诗/poet.song.240000.json','["門外竹千箇，崖顛兩徑分。", "奔泉流碎月，高樹礙行雲。", "游客倦欲卧，道人言少文。", "但云秦學士，曾此遇茅君。"]'),
('2587a9cc-5f76-4706-9747-75a70cb3daab','遊鼓山','張鎮初','宋','宋诗','song-poetry','','[]','籠翎圈裏著禪關，頂有奇峰蹬可攀。',64,'全唐诗/poet.song.240000.json','["籠翎圈裏著禪關，頂有奇峰蹬可攀。", "上下乾坤大千界，東西陸海兩三山。", "臨滄霧向風前解，喝水泉因雨後潺。", "一宿迷歸山莫哂，小窗經日對孱顔。"]'),
('45959539-b9e7-4403-9adb-3dc987ce3601','寄張道洽','蔣芸','宋','宋诗','song-poetry','','[]','衰柳疏松對夕陽，老來秋思倍堪傷。',64,'全唐诗/poet.song.240000.json','["衰柳疏松對夕陽，老來秋思倍堪傷。", "已無上苑千葩秀，僅有東籬一捻黄。", "細誦佳章排宿恨，旋呼村酒縱詩狂。", "西風策馬能過我，老圃餘蔬尚未荒。"]'),
('1496039a-2c9f-41b2-974a-19924167614f','寄張霖溪','蔣芸','宋','宋诗','song-poetry','','[]','漫向潭源晦此身，自嗟無地可投明。',64,'全唐诗/poet.song.240000.json','["漫向潭源晦此身，自嗟無地可投明。", "栽培勁節依巖翠，採擷香芹遶澗清。", "避亂遣懷聊圃治，論交且喜傍山行。", "何時並轡臨溪上，靜聽飛泉萬壑聲。"]'),
('8cc4a370-aa55-4f25-934f-4a5fa9dad932','辭薦呈余廉訪','蔣芸','宋','宋诗','song-poetry','','[]','耒耜生涯遠俗囂，年來無夢到金貂。',64,'全唐诗/poet.song.240000.json','["耒耜生涯遠俗囂，年來無夢到金貂。", "一池皓月□詩骨，滿圃春風長藥苗。", "愧不漆身吞豫炭，聊將洗耳棄由瓢。", "分甘投老潭源地，爲謝雲箋莫見招。"]'),
('4f25c2c7-168f-4e85-b7e2-d1ec8857d991','答蔣解元芸','張汝勤','宋','宋诗','song-poetry','','[]','翛然風月一閒身，健在何妨白髮明。',64,'全唐诗/poet.song.240000.json','["翛然風月一閒身，健在何妨白髮明。", "徑竹操如人不老，澗芹香與水俱清。", "傳家老硯孫携去，落筆新詩僧带行。", "那得胡床兩相對，青燈影裏聽秋聲。"]'),
('38612a44-0fdd-4979-bcb4-1c156889b1e8','寄徐秋澗  其一','張汝勤','宋','宋诗','song-poetry','','[]','年來觸事絕塵想，夜夢有時緣故人。',32,'全唐诗/poet.song.240000.json','["年來觸事絕塵想，夜夢有時緣故人。", "何日秋風歸興動，桂花香裏著吟身。"]'),
('aa64d58e-9299-4659-96c7-f74c3ec4e254','寄徐秋澗  其二','張汝勤','宋','宋诗','song-poetry','','[]','懷人渺渺數重山，風月將秋入夢寒。',32,'全唐诗/poet.song.240000.json','["懷人渺渺數重山，風月將秋入夢寒。", "疑有清風生羽翼，去隨明月倚欄干。"]'),
('a6ccd0ab-4da6-475e-b137-07efa15a95a5','懷繆竹林','張汝勤','宋','宋诗','song-poetry','','[]','東風日日惱吟魂，相與論心客在門。',64,'全唐诗/poet.song.240000.json','["東風日日惱吟魂，相與論心客在門。", "雨洗花光紅透骨，風摇野燒翠留痕。", "榮枯過眼歸春夢，醒醉從人付酒尊。", "輸與先生專一壑，閒來得看竹生孫。"]'),
('947fe98d-1ca6-4e02-a34b-88634376439b','戲徐觀空','張汝勤','宋','宋诗','song-poetry','','[]','學詩如學禪，所貴在觀妙。',84,'全唐诗/poet.song.240000.json','["學詩如學禪，所貴在觀妙。", "肺肝劇雕鏤，乃自鑿其竅。", "冥心遊象外，何物可供眺。", "空山散雲霧，仰避日初照。", "曠觀宇宙間，璀璨同暉曜。", "但以此理參，而自足詩料。", "持以問觀空，無言但一笑。"]'),
('f2852bbf-3133-4978-8e8a-2ab91c2a69d4','幽居','王先莘','宋','宋诗','song-poetry','','[]','斗室依山曲，如巢伴鶴棲。',48,'全唐诗/poet.song.240000.json','["斗室依山曲，如巢伴鶴棲。", "風鳴窗紙破，雨濕爨烟低。", "古致巖松外，秋聲野竹西。", "潺湲聽澗響，流不出橫溪。"]'),
('4cfafa16-4fa0-4382-b475-6593c1267ed0','璜源宗人玨壽慶樓','吳浩','宋','宋诗','song-poetry','','[]','吾宗培世德，盛事褒一門。',204,'全唐诗/poet.song.240000.json','["吾宗培世德，盛事褒一門。", "仰顔有壽母，俛目見子孫。", "平生青雲器，威鳳宜孤鶱。", "脫然舍榮爵，回車息深村。", "服勤養堂中，身已大父尊。", "戲綵時趨庭，奉輿日涉園。", "所至疇接武，顧見貽厥繁。", "今年結高樓，長少數憑軒。", "羣星環婺女，列象如可捫。", "雲傍檐楹飛，山鄰窗几蹲。", "往來烏鵲喜，迴互竹木蕃。", "良辰風日佳，容與同芳樽。", "循陔度雅樂，清響聞天閽。", "男兒貴恢豁，樓記聆緒言。", "穀共里人飽，書從寒士繙。", "善源深復深，河流出崑崙。", "吾頌殊未艾，玄來更瑶琨。"]'),
('64e83925-b291-47da-93e6-24aa8c7e83de','正月五日漫興','余芑舒','宋','宋诗','song-poetry','','[]','雪簷晴作雨，道空日如年。',24,'全唐诗/poet.song.240000.json','["雪簷晴作雨，道空日如年。", "燕坐無餘事，牀頭易一編。"]'),
('ba311c8f-2a9c-4510-8c34-93ba3c908db3','南軒獨坐','余芑舒','宋','宋诗','song-poetry','','[]','往來都是由天造，妙處何須更我爲。',32,'全唐诗/poet.song.240000.json','["往來都是由天造，妙處何須更我爲。", "但向物初看老子，恍然身外有嬰兒。"]'),
('088f9ea3-fd12-4d99-b950-6321979df7d4','九月二十四日','余芑舒','宋','宋诗','song-poetry','','[]','蝶翅平沉疑墜葉，蟬聲孤起在高枝。',32,'全唐诗/poet.song.240000.json','["蝶翅平沉疑墜葉，蟬聲孤起在高枝。", "空庭秋意無人會，月轉西樓淡淡時。"]'),
('edf4bb95-0259-409f-95b7-3f0207795f4f','天門山','余芑舒','宋','宋诗','song-poetry','','["\u5929\u95e8\u5c71"]','誰將嘉號標奇觀，山鳥山花第一重。',64,'全唐诗/poet.song.240000.json','["誰將嘉號標奇觀，山鳥山花第一重。", "天闕常時瞻北極，縣圖此處數西峰。", "景雲百戰猶遺址，當日諸公幾瘦筇。", "定有英靈來訪舊，夜聞嘶馬曉無蹤。"]'),
('24b1ddb3-8403-429b-a356-47056eb44e61','歲寒山','余芑舒','宋','宋诗','song-poetry','','[]','歲寒老石尚干霄，松柏摧殘只艾蕭。',64,'全唐诗/poet.song.240000.json','["歲寒老石尚干霄，松柏摧殘只艾蕭。", "岣嶁字昏烟漠漠，空同人去夜寥寥。", "凉蟬高挂千尋壁，斷澗閒浮五石瓢。", "不信渠儂呼不醒，倘逢歸鶴試招邀。"]'),
('3ec40832-5d45-44f8-ad2e-45911a1f4f83','悟道','余芑舒','宋','宋诗','song-poetry','','[]','何人解管身中事，今我纔知學有源。',32,'全唐诗/poet.song.240000.json','["何人解管身中事，今我纔知學有源。", "養得心源身事畢，春花秋月共忘言。"]'),
('8935e1bc-0bad-45a1-be9d-54cb42e3518b','楊梅','余萼舒','宋','宋诗','song-poetry','','[]','摘來鶴頂珠猶濕，點出龍睛淚未乾。',32,'全唐诗/poet.song.240000.json','["摘來鶴頂珠猶濕，點出龍睛淚未乾。", "若使太真知此味，荔支應不到長安。"]'),
('2ab5879a-7320-4ea5-8306-41209c2efe33','送藍峰赴南泉教','王希旦','宋','宋诗','song-poetry','','[]','君去清源第一州，鱠魚沽酒有人留。',32,'全唐诗/poet.song.240000.json','["君去清源第一州，鱠魚沽酒有人留。", "泉山紫帽登臨處，還有高人寄我不。"]'),
('b531baa3-dc1f-426c-bc4a-1ad35f0ab04f','送南浦明公歸日本','釋道東','宋','宋诗','song-poetry','','[]','十幅蒲帆萬里風，來無蹤跡去還同。',32,'全唐诗/poet.song.240000.json','["十幅蒲帆萬里風，來無蹤跡去還同。", "擡眸錯認雲山處，人在水天一色中。"]'),
('3519c7d8-3172-495b-a102-8eba82429b7b','聖小兒詩','賀德英','宋','宋诗','song-poetry','','[]','英秀鍾河岳，生來號聖兒。',72,'全唐诗/poet.song.240000.json','["英秀鍾河岳，生來號聖兒。", "雖云年尚小，不待學而知。", "博古通今識，超羣邁秀姿。", "浩然食牛氣，非若聚魚嬉。", "祖瑩耽書日，甘羅入相時。", "看看頭角長，身到鳳凰池。"]'),
('02eab89e-d4f8-4805-8dbf-37c063bd75fb','賦雪','賀德英','宋','宋诗','song-poetry','','[]','誰翦銀河水，飛花出漢霾。',24,'全唐诗/poet.song.240000.json','["誰翦銀河水，飛花出漢霾。", "月明人競往，踏破水晶街。"]'),
('75384248-36cc-4a9e-9cbd-8aa20973dd19','題縣廳壁','賀德英','宋','宋诗','song-poetry','','[]','昆明池裏躍金鱗，怒目揚鬐不露身。',32,'全唐诗/poet.song.240000.json','["昆明池裏躍金鱗，怒目揚鬐不露身。", "想是龍門曾點額，至今羞見釣鼇人。"]'),
('227f3eac-5af4-46a8-84fb-b73842ed499d','句  其一','賀德英','宋','宋诗','song-poetry','','[]','易描通臂狀，難寫斷腸聲。',12,'全唐诗/poet.song.240000.json','["易描通臂狀，難寫斷腸聲。"]'),
('07bbc581-214e-4ac5-9355-9711276216c2','句  其二','賀德英','宋','宋诗','song-poetry','','[]','只因錯寫天文表，流落人間一紀零。',16,'全唐诗/poet.song.240000.json','["只因錯寫天文表，流落人間一紀零。"]'),
('cb8af9bd-0e1d-497d-b087-0280ed3f8fe7','鶴林寺','陸秀夫','宋','宋诗','song-poetry','','[]','歲月未可盡，朝昏屢不眠。',48,'全唐诗/poet.song.240000.json','["歲月未可盡，朝昏屢不眠。", "窗前多古木，牀上半殘編。", "放犢飲溪水，助僧耕種田。", "寺門久斷掃，分食愧農賢。"]'),
('a1aacc90-37d9-4f2f-8590-6e64ac7d4765','句','陸秀夫','宋','宋诗','song-poetry','','[]','曾聞海上鐵斗膽，猶見雲中金甲神。',16,'全唐诗/poet.song.240000.json','["曾聞海上鐵斗膽，猶見雲中金甲神。"]'),
('1f863f75-bda3-4a02-9ae4-466fca996dac','輓陸君實  其一','尹應許','宋','宋诗','song-poetry','','[]','誰使權奸釀禍深，末流無復救危枰。',64,'全唐诗/poet.song.240000.json','["誰使權奸釀禍深，末流無復救危枰。", "君臣霄壤難同死，社稷丘墟可再生。", "叔寶井中空大辱，魯連海上特虛名。", "一家骨肉俱魚腹，留得丹心萬古明。"]'),
('c3c1cafe-6cd2-414f-bfec-06cb695f2675','輓陸君實  其二','尹應許','宋','宋诗','song-poetry','','[]','古今忠義獨斯人，危在須臾見益真。',64,'全唐诗/poet.song.240000.json','["古今忠義獨斯人，危在須臾見益真。", "身不遠亡憂喪節，君非同逝慮蒙塵。", "平時誰執朝廷柄，末路方知社稷臣。", "楚些欲招招不得，滄溟南望浩無津。"]'),
('78921a43-406d-4b43-94a6-f90ac03f82a7','感興','孫嵩','宋','宋诗','song-poetry','','[]','清風有佳意，逢者爲一娛。',252,'全唐诗/poet.song.240000.json','["清風有佳意，逢者爲一娛。", "曾不救饑渴，政爾飄襟裾。", "凡物貴有用，論詩用則無。", "詩成亦自詠，侘傺或昭蘇。", "身名不相涉，二者如參商。", "遲其議論公，曠越百世長。", "于人已無益，離離墳草荒。", "不知史冊上，更是誰芬芳。", "猶足厲世俗，曰此有耿光。", "生前文字冗，寸札蓐荑稂。", "及後乃大行，家有星河章。", "君欲知其人，近世蘇與黄。", "夫有酷吏事，良不爲奇屯。", "俗子來吾前，有語無由伸。", "其愚正可置，而又何爲嗔。", "勿如孤竹子，宇宙生涯垠。", "匪惟狎樵牧，浩浩冥疏親。", "鳥故不亂行，獸故不亂群。", "在山爲遠志，出山爲小草。", "不足凋謝安，適可謂殷浩。", "夫亦有所懷，非必著枯槁。"]'),
('eb240e07-3343-4296-b876-6fc7b293363d','冬初雜興  其一','孫嵩','宋','宋诗','song-poetry','','[]','今晨霜露肅，愛此群山秋。',72,'全唐诗/poet.song.240000.json','["今晨霜露肅，愛此群山秋。", "夭桃薄照日，乃是丹楓稠。", "草花無名字，正類黄菊幽。", "一筇步澗阿，聊復舒我眸。", "雁聲一何高，渺渺關山愁。", "林間有橡栗，歲晚行可收。"]'),
('5aeca3bf-b437-49b4-a9d1-e42eb6d52f1f','冬初雜興  其二','孫嵩','宋','宋诗','song-poetry','','[]','牧童與樵叟，共載牛背歸。',60,'全唐诗/poet.song.240000.json','["牧童與樵叟，共載牛背歸。", "我無薪蒸計，南山松櫟稀。", "寒風昨日至，須用葺我扉。", "故園或可廢，亦以完我衣。", "人生有定分，勿怪生理微。"]'),
('811f3966-0b9e-4b28-b392-66a4c3414da7','冬初雜興  其三','孫嵩','宋','宋诗','song-poetry','','[]','鐘聲烟外寺，報我明朝霜。',48,'全唐诗/poet.song.240000.json','["鐘聲烟外寺，報我明朝霜。", "籬落暝雀驚，原野昏鴉翔。", "杖策歸茅茨，偶一歌慨慷。", "千載有我輩，感念行斜陽。"]'),
('a4aad8c1-72d0-4b02-9a5e-bb3499bce855','冬初雜興  其四','孫嵩','宋','宋诗','song-poetry','','[]','齋中乃無紙，柿葉平籬根。',72,'全唐诗/poet.song.240000.json','["齋中乃無紙，柿葉平籬根。", "稍取書點畫，带此朝露痕。", "識字有何補，隨爾憂患繁。", "姓名總不記，適有古意存。", "惜哉結繩後，事始於乾坤。", "先生晚始悟，無術鳩田園。"]'),
('3a9bcabd-a765-480b-94c2-b742b092b221','冬初雜興  其五','孫嵩','宋','宋诗','song-poetry','','[]','殘花與新蕊，不共橫斜枝。',120,'全唐诗/poet.song.240000.json','["殘花與新蕊，不共橫斜枝。", "摧謝得清峭，獨照冰霜時。", "寒梅正如此，他木乃變衰。", "此由觀世物，特以厄見奇。", "古云桑落節，當有新醪篘。", "得秫釀幾何，撥甕香浮浮。", "醇熟不足計，醒醉亦自籌。", "得酒乃逕飲，無酒亦可休。", "絕憐未知道，顛倒阮與劉。", "百年有事業，遑云逃糟丘。"]'),
('4df9044d-8b0b-48a7-b82e-7808cfd7d139','冬初雜興  其六','孫嵩','宋','宋诗','song-poetry','','[]','秋晚種麰麥，覆塊青茸茸。',84,'全唐诗/poet.song.240000.json','["秋晚種麰麥，覆塊青茸茸。", "茲物乃畏濕，溝作棋道通。", "江南地力瘠，百穀勞農工。", "秔稌蓄堘上，麰麥藏溝中。", "從今防蹂嚙，早晚觀麥叢。", "須縱牛羊食，勿信東坡翁。", "吾詩乃農譜，亦著江南風。"]'),
('3314a258-19a7-477d-9596-59978af35e6f','立春日','孫嵩','宋','宋诗','song-poetry','','[]','殘冬初曦巧弄頻，輕澌片片動遊鱗。',64,'全唐诗/poet.song.240000.json','["殘冬初曦巧弄頻，輕澌片片動遊鱗。", "土牛不報窮居暖，星鳥非司退士春。", "門帖廢忘梅柳句，鄉儺倚閣鼓鼙人。", "愁多酒淺知何那，太息年光草草新。"]'),
('b02d020a-e9b8-4ce2-bc62-8d3a8c5b6b10','送年寓歎','孫嵩','宋','宋诗','song-poetry','','[]','歲事分携作逕歸，清愁環守有重圍。',64,'全唐诗/poet.song.240000.json','["歲事分携作逕歸，清愁環守有重圍。", "預供除日先人祭，次拂元朝道士衣。", "狂似嵇康今盡嬾，覺如蘧瑗昔皆非。", "新春未識耕耘地，當卜何如買釣磯。"]'),
('fe101163-bf4b-4e6f-bb52-561fbc3d179e','開歲連日有陰雨  其一','孫嵩','宋','宋诗','song-poetry','','[]','老杜詩章五百年，爲吾替寫早春篇。',32,'全唐诗/poet.song.240000.json','["老杜詩章五百年，爲吾替寫早春篇。", "恰從元日踰人日，重有陰陰冷落天。"]'),
('78a9e90b-9b7d-4e5c-90ff-ce2666725748','開歲連日有陰雨  其二','孫嵩','宋','宋诗','song-poetry','','[]','日日嵐陰守翠微，清溪平沒釣魚磯。',32,'全唐诗/poet.song.240000.json','["日日嵐陰守翠微，清溪平沒釣魚磯。", "流鶑一任無來意，直恐梅花半樹稀。"]'),
('43994f89-a287-4637-9669-67ea1198150d','開歲連日有陰雨  其三','孫嵩','宋','宋诗','song-poetry','','[]','新草天涯入斷魂，若爲有意眺郊原。',32,'全唐诗/poet.song.240000.json','["新草天涯入斷魂，若爲有意眺郊原。", "只因老子春愁少，須著蕭蕭雨暗村。"]'),
('524cb4ca-2619-40d8-b946-343cae176ef5','又書畫船五首  其一','孫嵩','宋','宋诗','song-poetry','','[]','足踏江陵一舸空，襄陽親手結孤蓬。',32,'全唐诗/poet.song.240000.json','["足踏江陵一舸空，襄陽親手結孤蓬。", "流傳別有黔川樣，安穩舲齋不軃風。"]'),
('61d8910b-0298-4aeb-8ec9-15668a254cb7','又書畫船五首  其二','孫嵩','宋','宋诗','song-poetry','','[]','書畫生憎世上塵，不嫌蓑笠渺無津。',32,'全唐诗/poet.song.240000.json','["書畫生憎世上塵，不嫌蓑笠渺無津。", "扁舟去住渾林間，了是江湖舊散人。"]'),
('dd6527fe-5f3f-47b1-8710-a74c52ec3914','又書畫船五首  其三','孫嵩','宋','宋诗','song-poetry','','[]','幸自消除長物緣，尚留遮眼卷三千。',32,'全唐诗/poet.song.240000.json','["幸自消除長物緣，尚留遮眼卷三千。", "分明更有江湖債，搬入人家贋釣船。"]'),
('3768ae3a-45ea-408b-a48f-f7b8cf6600c2','又書畫船五首  其四','孫嵩','宋','宋诗','song-poetry','','[]','不聽挐音分外閑，穩裝書畫一蓬間。',32,'全唐诗/poet.song.240000.json','["不聽挐音分外閑，穩裝書畫一蓬間。", "今朝風雨苕川上，扑灑沙鷗第幾灣。"]'),
('9b42d641-e326-4686-bc6e-1ce3e8d2ce1f','又書畫船五首  其五','孫嵩','宋','宋诗','song-poetry','','[]','切莫清狂更隠淪，浮家泛宅斷知聞。',32,'全唐诗/poet.song.240000.json','["切莫清狂更隠淪，浮家泛宅斷知聞。", "明朝我欲觀書畫，何處將詩寄水雲。"]'),
('de7a7f54-4bf0-4264-936f-1f6cc1a61773','覓佳山水遷居未能又力役不休','孫嵩','宋','宋诗','song-poetry','','[]','微吟清嘯有孤懷，歷落嶔崎已大乖。',64,'全唐诗/poet.song.240000.json','["微吟清嘯有孤懷，歷落嶔崎已大乖。", "芳草何心知世事，閑雲肆意繞天涯。", "前時絕喜王官谷，此去聊堪阿里街。", "一語作銘君記取，騰騰任運莫安排。"]'),
('a8a0e271-4c26-4aef-adb4-8159c0ea7e8c','生日  其一','孫嵩','宋','宋诗','song-poetry','','[]','雲外荒村半掩扉，門孤事業與心違。',32,'全唐诗/poet.song.240000.json','["雲外荒村半掩扉，門孤事業與心違。", "悠悠歲月山林老，納納乾坤道路非。"]'),
('afb93102-f324-4ee7-8427-35868f559f45','生日  其二','孫嵩','宋','宋诗','song-poetry','','[]','鴻雁關河秋滿眼，梧桐風雨冷吹衣。',32,'全唐诗/poet.song.240000.json','["鴻雁關河秋滿眼，梧桐風雨冷吹衣。", "蓼莪自是長休廢，獨立蒼苔一歎欷。"]'),
('d5b16b96-2116-4ee9-ac19-679be9aa06fb','竹枝歌  其一','孫嵩','宋','宋诗','song-poetry','','[]','灧澦灘頭君莫行，瞿塘峽裏不論程。',32,'全唐诗/poet.song.240000.json','["灧澦灘頭君莫行，瞿塘峽裏不論程。", "龍吟小雨蜀天黑，等有明朝春水生。"]'),
('0062cb54-de30-4bdc-a90f-65739494473e','竹枝歌  其二','孫嵩','宋','宋诗','song-poetry','','[]','行盡三巴三曲頭，一灘自有一生愁。',32,'全唐诗/poet.song.240000.json','["行盡三巴三曲頭，一灘自有一生愁。", "明朝已過巴陵岸，更宿江陵漁笛洲。"]'),
('01280f43-0640-488c-96dd-594d23e9f451','竹枝歌  其三','孫嵩','宋','宋诗','song-poetry','','[]','雲外猩猩何處聲，終朝出沒只深菁。',32,'全唐诗/poet.song.240000.json','["雲外猩猩何處聲，終朝出沒只深菁。", "前有懸崖菁幾里，行人到此古今情。"]'),
('0039433e-fcb5-4c55-805a-70884aa9eec3','竹枝歌  其四','孫嵩','宋','宋诗','song-poetry','','[]','洶浪砰雷蛇飲溪，陰崖天暗虎丘泥。',32,'全唐诗/poet.song.240000.json','["洶浪砰雷蛇飲溪，陰崖天暗虎丘泥。", "萬里中原那有此，憐君更過鬼門西。"]'),
('09aa81cb-9e44-4946-9d99-52c039078972','竹枝歌  其五','孫嵩','宋','宋诗','song-poetry','','[]','峽路陰陰無四時，寒雲鳥道挂天危。',32,'全唐诗/poet.song.240000.json','["峽路陰陰無四時，寒雲鳥道挂天危。", "荒亭敗驛此何處，望帝江山號子規。"]'),
('a338bfe8-08bb-4e98-869c-4003969f6c07','竹枝歌  其六','孫嵩','宋','宋诗','song-poetry','','[]','巴子城荒非昔人，公孫何處問遺民。',32,'全唐诗/poet.song.240000.json','["巴子城荒非昔人，公孫何處問遺民。", "千年惟有武侯磧，留與踏歌行早春。"]'),
('0f939a97-cf32-48f0-a588-78aeb7730bf8','竹枝歌  其七','孫嵩','宋','宋诗','song-poetry','','[]','漢世明妃猶有村，荒祠歌舞與招魂。',32,'全唐诗/poet.song.240000.json','["漢世明妃猶有村，荒祠歌舞與招魂。", "胡琴好入巴渝曲，萬里還鄉釃酒罇。"]'),
('34cab01b-e1e5-4496-854f-da240dd2e604','竹枝歌  其八','孫嵩','宋','宋诗','song-poetry','','[]','黄牛廟前鴉鸛棲，黄魔宮外梟鵩啼。',32,'全唐诗/poet.song.240000.json','["黄牛廟前鴉鸛棲，黄魔宮外梟鵩啼。", "估客酹神巫嫗醉，青林日轉風凄凄。"]'),
('803e5005-b7f6-4b6d-be7b-ef66316c65fa','竹枝歌  其九','孫嵩','宋','宋诗','song-poetry','','[]','峽山削出青嵯峨，峽水勻成綠不波。',32,'全唐诗/poet.song.240000.json','["峽山削出青嵯峨，峽水勻成綠不波。", "頓平山林未能得，奈此猿聲朝夕何。"]'),
('92668707-e36f-46ba-9d6c-f340fe77f4eb','春夏之交四首  其一','孫嵩','宋','宋诗','song-poetry','','[]','江花江水意，春色爲誰多。',24,'全唐诗/poet.song.240000.json','["江花江水意，春色爲誰多。", "極目天涯草，淒淒奈爾何。"]'),
('2f8bc1ea-2dce-4022-b57d-c36fbb450385','春夏之交四首  其二','孫嵩','宋','宋诗','song-poetry','','[]','悄悄瞻青壁，悠悠矚翠林。',24,'全唐诗/poet.song.240000.json','["悄悄瞻青壁，悠悠矚翠林。", "流鶑無一事，聲遠薜蘿陰。"]'),
('2f93bbd0-8197-497a-ba0d-6789f47505ad','春夏之交四首  其三','孫嵩','宋','宋诗','song-poetry','','[]','村落頳桐日，茅茨白楝風。',24,'全唐诗/poet.song.240000.json','["村落頳桐日，茅茨白楝風。", "閑階沾雨菊，又綠去年叢。"]'),
('96920a12-6fe0-45ea-b27a-b7cab405500b','春夏之交四首  其四','孫嵩','宋','宋诗','song-poetry','','[]','拂檻逍遥絮，浮空自在絲。',24,'全唐诗/poet.song.240000.json','["拂檻逍遥絮，浮空自在絲。", "幽香來遠近，山側有酴釄。"]'),
('e386cf39-d939-40a1-a9b6-cae9ce5bbf48','霜曉早行','孫嵩','宋','宋诗','song-poetry','','[]','三兩殘星龍𦜩雲，人烟山色曉初分。',32,'全唐诗/poet.song.240000.json','["三兩殘星龍𦜩雲，人烟山色曉初分。", "西風一夜吹黄葉，不計霜晨客子聞。"]'),
('f58c54d7-9497-4a48-9cdc-69045d9768a6','哭程晦夫  其一','孫嵩','宋','宋诗','song-poetry','','[]','握手論交意氣真，舊遊四顧暗傷神。',32,'全唐诗/poet.song.240000.json','["握手論交意氣真，舊遊四顧暗傷神。", "陪從金馬門中客，和唱銅駝陌上春。"]'),
('b93d6e3a-edcd-4bd0-b401-7f1a41f4096a','哭程晦夫  其二','孫嵩','宋','宋诗','song-poetry','','[]','尚謂鄉邦離有合，忍聞丘壟夜無晨。',32,'全唐诗/poet.song.240000.json','["尚謂鄉邦離有合，忍聞丘壟夜無晨。", "夕陽古道曾經別，腸斷西風淚滿巾。"]'),
('4cc2ef90-5d65-4277-9887-c1d1d941d04d','和謝虛谷  其一','孫嵩','宋','宋诗','song-poetry','','[]','文章琬琰盛鎸磨，乞與丹青侈若何。',64,'全唐诗/poet.song.240000.json','["文章琬琰盛鎸磨，乞與丹青侈若何。", "已是追隨名世晚，敢言步驟古人多。", "未同子美投三賦，且爲靈均釋九歌。", "怎有農謠又漁曲，稍談釣笠與耕簑。"]'),
('eff21f8b-ea53-437f-bb67-c1725c6a9719','和謝虛谷  其二','孫嵩','宋','宋诗','song-poetry','','[]','窮愁幽思或成時，畦逕荒蕪失自治。',64,'全唐诗/poet.song.240000.json','["窮愁幽思或成時，畦逕荒蕪失自治。", "秋氣居然寒宋玉，土風猶爾操鍾儀。", "安能跛鼈從天馬，正擬長松引菟絲。", "啟以新篇新繩削，元和直至建安時。"]'),
('60a6d07d-7576-4cc6-89da-d807f13c3960','夜泊垂虹','孫嵩','宋','宋诗','song-poetry','','[]','螮蝀無晴雨，橫空不計年。',48,'全唐诗/poet.song.240000.json','["螮蝀無晴雨，橫空不計年。", "長身欺浪渺，鉅力厭風顛。", "懷古方聞笛，題詩且住船。", "飛鳴中夜雁，何處得洲眠。"]'),
('6ad0b3b5-e122-42bc-a63f-fa5def4c87d7','明妃引','孫嵩','宋','宋诗','song-poetry','','[]','明妃如花顔，高出漢宮右。',127,'全唐诗/poet.song.240000.json','["明妃如花顔，高出漢宮右。", "可憐君王目，但寄丹青手。", "寂寂保孤妍，悠悠成僞醜。", "坐此嫁穹廬，流落無時回。", "無時回，琵琶未闋邊笳催。", "哀絃流入千家譜，明妃只作閼支舞。", "年年猶借南來風，吹得青青一抔土。", "君不見漢家嫁得幾娉婷，不聞一一琵琶聲。", "禍起當年婁敬謬，後人獨恨毛延壽。"]'),
('3f130f84-739a-4ae0-a2b7-64943725f31f','曲江頭','孫嵩','宋','宋诗','song-poetry','','[]','君不見曲江頭，離離衰草寒雲秋。',93,'全唐诗/poet.song.240000.json','["君不見曲江頭，離離衰草寒雲秋。", "今人不見昔人遊，昔人不見今人愁。", "欲談往事無耆舊，沉吟千載空搔首，盛衰倚伏如寒暄。", "秦時宜春苑，漢世樂遊園，更復唐人宮殿擁千門。", "往古來今但如此，同一溶溶曲江水。"]'),
('ec3aa17f-3e23-4eaf-a426-1e6fcb30513a','公無渡河','孫嵩','宋','宋诗','song-poetry','','[]','公乎渡河不可航，年既老，智則童。',244,'全唐诗/poet.song.240000.json','["公乎渡河不可航，年既老，智則童。", "臨流徑渡何倀倀，夫豈有急須自亡。", "前無掣，後無擠，且無跡捕至爾門，未至東市之誅磔死如牛羊。", "河流在前白日光，誰以錦覆河流黄。", "公不見河源夭矯落崑崙，懸天注地千里强。", "飛奔突入中原疆，一擊無有完堤防。", "跳蹴后土舂穹蒼，公懵視之行康莊。", "掉臂而往無褰裳，不能馭風騎氣奚爲狂。", "河之流湯湯，鯤鯨之惡未可量。", "長戈爲鰭鋸爲尾，刀崖斧窟鑱牙張。", "公其以身委饑腸，人生無難死足傷。", "以饑寒死骨猶藏，棺槨送爾松柏岡。", "何必爲河之鬼馮夷鄉，其下濁泥出無梁。", "何不相蹙公自僵，奈何乎箜篌之音河水旁。"]'),
('5a6aa7dc-fc5f-426b-94f6-faa64a043860','秋懷五首  其一','孫嵩','宋','宋诗','song-poetry','','[]','秋蟲日以喧，秋樹日以疏。',36,'全唐诗/poet.song.240000.json','["秋蟲日以喧，秋樹日以疏。", "君聽草根蛩，泣弔風中梧。", "壯士秋懷涕，及此清霜初。"]'),
('d6a80f50-6152-4c91-9353-f6f861ec133f','秋懷五首  其二','孫嵩','宋','宋诗','song-poetry','','[]','從來感秋人，一例皆楚聲。',36,'全唐诗/poet.song.240000.json','["從來感秋人，一例皆楚聲。", "吾聞古燕趙，慷慨多不平。", "惜哉宋玉辭，不使荆軻聽。"]'),
('d9c18de5-964d-4c42-9a75-562dbddc0552','秋懷五首  其三','孫嵩','宋','宋诗','song-poetry','','[]','何處秋聲多，竹外聲歷歷。',36,'全唐诗/poet.song.240000.json','["何處秋聲多，竹外聲歷歷。", "凄切不禁寒，蕭蕭舊時碧。", "此中白髮愁，餉與秋風客。"]'),
('78c2a515-ca4d-4bdc-b71c-d90d96c96c5d','秋懷五首  其四','孫嵩','宋','宋诗','song-poetry','','[]','疇昔旅江湖，夜夜南飛雁。',36,'全唐诗/poet.song.240000.json','["疇昔旅江湖，夜夜南飛雁。", "山園柿栗秋，出戶望河漢。", "袛今寒雁時，中夕起三歎。"]'),
('fbd5ea7e-18b1-4cdf-8f8d-b6a3b4c2dcd3','秋懷五首  其五','孫嵩','宋','宋诗','song-poetry','','[]','黄山秋雕鎪，風露洗崖崿。',36,'全唐诗/poet.song.240000.json','["黄山秋雕鎪，風露洗崖崿。", "行行聽清猿，處處采靈藥。", "秋雲老石牀，已後十年約。"]'),
('5e4292bd-1ddf-4a80-80f4-331f4286c824','畫猿','孫嵩','宋','宋诗','song-poetry','','[]','客子平生三峽遊，青猿樹樹懸高秋。',48,'全唐诗/poet.song.240000.json','["客子平生三峽遊，青猿樹樹懸高秋。", "歸來落筆成天趣，中傳蜀月巴雲意。", "如何猿叫驛邊時，只欠行人唱竹枝。"]'),
('43d55135-10d2-49e7-93ee-178c8e45b121','戲嘲二子','孫嵩','宋','宋诗','song-poetry','','[]','攻爲樂府作，吟盡樂府題。',60,'全唐诗/poet.song.240000.json','["攻爲樂府作，吟盡樂府題。", "不曉張籍與王建，筆端欲攬風凄凄。", "大半閑愁生浪語，十九他人無與汝。", "擊轅撫缶何如聲，奈此瀾翻兩吻鳴。"]'),
('a0935761-3d71-41b5-a057-4029c6224c9a','行都餞歲','孫嵩','宋','宋诗','song-poetry','','[]','插架餘殘歷，挑燈憶故鄉。',48,'全唐诗/poet.song.240000.json','["插架餘殘歷，挑燈憶故鄉。", "年光蛇赴壑，羈旅雁隨陽。", "禁闕迎儺鼓，鄰街祭竈香。", "英雄須自力，容易鬢毛蒼。"]'),
('8d0418e1-221a-4202-b97c-485b6dc4b851','臨安錢武肅廟','孫嵩','宋','宋诗','song-poetry','','[]','吳越歸旗纛，風雲助鼓鼙。',48,'全唐诗/poet.song.240000.json','["吳越歸旗纛，風雲助鼓鼙。", "錦蒙山樹遍，弩射海潮低。", "龍鳳城葱鬰，牛羊墓慘悽。", "古祠存故里，秋草廡東西。"]'),
('cce0f5f7-bf85-4e58-84a8-78b706f71682','倦客','孫嵩','宋','宋诗','song-poetry','','[]','倦客江湖返，書生畎畝思。',48,'全唐诗/poet.song.240000.json','["倦客江湖返，書生畎畝思。", "古來惟即墨，世上幾仇池。", "八表烟霾隔，三春草木衰。", "交游消息斷，存沒杳難知。"]'),
('0574a9d0-39c5-4540-bda7-a21653c77517','遣懷雜賦','孫嵩','宋','宋诗','song-poetry','','[]','宇宙迂疏一布衣，謀身畢竟是邪非。',64,'全唐诗/poet.song.240000.json','["宇宙迂疏一布衣，謀身畢竟是邪非。", "能知道義丘山重，定看榮華草芥微。", "世事悠悠蝴蝶夢，人情擾擾桔槹機。", "英雄不是違流俗，白雪陽春和自稀。"]'),
('3915fcf1-c8a2-4ab4-97f7-e8c0378cdc4f','春日武康遊望過孟東野故居','孫嵩','宋','宋诗','song-poetry','','[]','殘靄初收半在沙，一川芳草趁溪斜。',64,'全唐诗/poet.song.240000.json','["殘靄初收半在沙，一川芳草趁溪斜。", "羣峰古意汪芒國，廢地詩情正曜家。", "天末淒迷浮野色，柳邊駘蕩受春華。", "更携尊酒看修竹，不爲前坡得意花。"]'),
('ca1a521b-a495-4c44-925e-b5098eca5751','愍歎','孫嵩','宋','宋诗','song-poetry','','[]','救地扶天力不支，猶爲落落怪男兒。',64,'全唐诗/poet.song.240000.json','["救地扶天力不支，猶爲落落怪男兒。", "泥中龍逝江神駭，波際鯨枯海若悲。", "恨入烟雲連漢縣，魂隨霜雪薄燕垂。", "可憐傲兀南冠在，吟盡關山慟絕詩。"]'),
('57fad617-d0cf-43da-a837-8016d1242964','還鄧覺民詩卷','孫嵩','宋','宋诗','song-poetry','','[]','南山竹可笛，北山桐可琴。',24,'全唐诗/poet.song.240000.json','["南山竹可笛，北山桐可琴。", "得如聽松風，中有太古音。"]'),
('de0213b7-1210-4ad0-ab68-eb50c8b4dd18','閲秦紀二首  其一','孫嵩','宋','宋诗','song-poetry','','[]','初逃揕未亡，又遇朴無傷。',24,'全唐诗/poet.song.240000.json','["初逃揕未亡，又遇朴無傷。", "如何博浪禍，更使副車當。"]'),
('d69c424d-837f-44b1-9a1f-ded150bd2ccf','閲秦紀二首  其二','孫嵩','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','泰嶽聊逃雨，湘山偶阻風。',24,'全唐诗/poet.song.240000.json','["泰嶽聊逃雨，湘山偶阻風。", "伐樹仍封樹，元無罪與功。"]'),
('c0276c25-bded-4b5a-8a74-0c75fff27716','邵康節','孫嵩','宋','宋诗','song-poetry','','[]','真隠由中土，行窩賞太平。',24,'全唐诗/poet.song.240000.json','["真隠由中土，行窩賞太平。", "生無皺眉事，單爲杜鵑聲。"]'),
('a6dbaed8-b6d8-44de-8595-6746fa843185','紫陽夜坐','孫嵩','宋','宋诗','song-poetry','','[]','一夜燈前白紵單，沉吟有此夏初寒。',32,'全唐诗/poet.song.240000.json','["一夜燈前白紵單，沉吟有此夏初寒。", "露零若與人相語，松杪瀟瀟下石壇。"]'),
('ed4c67d5-b632-4ba4-aaef-c0f7090b86e7','偶作','孫嵩','宋','宋诗','song-poetry','','[]','更勿窮通算此生，文章玄白付誰評。',32,'全唐诗/poet.song.240000.json','["更勿窮通算此生，文章玄白付誰評。", "凄凉例薄佳人命，邂逅多成豎子名。"]'),
('f8f7feda-3cbf-4bfc-9b16-33b9635a8546','書雨','孫嵩','宋','宋诗','song-poetry','','[]','陰谷幽林熱似焚，阿香鳴鼓驟殷殷。',32,'全唐诗/poet.song.240000.json','["陰谷幽林熱似焚，阿香鳴鼓驟殷殷。", "天公作雨須臾事，用得東山一片雲。"]'),
('8316b279-2508-4920-87a8-c233eeaf7719','歸途旅思','孫嵩','宋','宋诗','song-poetry','','[]','虛市斜陽早掩門，蕭條州縣抵深村。',32,'全唐诗/poet.song.240000.json','["虛市斜陽早掩門，蕭條州縣抵深村。", "殘梅與客迎新歲，明月隨人作上元。"]'),
('40c746ec-5930-4e73-82a6-091b8296e404','姑蘇元夕','孫嵩','宋','宋诗','song-poetry','','[]','茂苑長洲滿地春，吳兒歌舞逐時新。',32,'全唐诗/poet.song.240000.json','["茂苑長洲滿地春，吳兒歌舞逐時新。", "風流百巧花燈手，猶是夫差國裏人。"]'),
('d46b8a85-b047-4204-a839-2195b9aa83fc','偈頌六十七首  其一','釋原妙','宋','宋诗','song-poetry','','[]','談玄談妙，說性說心。',66,'全唐诗/poet.song.240000.json','["談玄談妙，說性說心。", "攢花簇錦，巧妙尖新。", "如麻似粟，從古至今。", "莫不皆是乘虛接響底漢，倚草附木精靈。", "山僧雖是他家種草，决定不向遮裏藏身。"]'),
('d661dc57-85e9-445b-a7b8-033a776609cc','偈頌六十七首  其二','釋原妙','宋','宋诗','song-poetry','','[]','有一物，明歷歷。',44,'全唐诗/poet.song.240000.json','["有一物，明歷歷。", "佛祖覷不破，大地無人識。", "常在舌頭尖，盡力吐不出。", "吐得出，也是胡餠裏呷汁。"]'),
('cb08b4a1-76ec-4598-886c-f40647887e26','偈頌六十七首  其三','釋原妙','宋','宋诗','song-poetry','','[]','有句無句，金烏吞玉兔。',69,'全唐诗/poet.song.240000.json','["有句無句，金烏吞玉兔。", "如藤倚樹，癩馬繫枯椿。", "樹倒藤解，一冬燒不盡。", "句歸何處，石虎當途踞。", "呵呵大笑，龍頭蛇尾。", "捺倒爛泥裏，剛刀不斬無罪之人。"]'),
('1d6826cd-ecab-47ba-874b-5e0a70c91d43','偈頌六十七首  其四','釋原妙','宋','宋诗','song-poetry','','[]','千嶺萬山雪，五湖四海冰。',24,'全唐诗/poet.song.240000.json','["千嶺萬山雪，五湖四海冰。", "清光成一片，物物盡皆明。"]'),
('9119412b-231a-4199-974d-beb843c37d67','偈頌六十七首  其五','釋原妙','宋','宋诗','song-poetry','','[]','百年難遇歲朝春，姹女梳粧越樣新。',32,'全唐诗/poet.song.240000.json','["百年難遇歲朝春，姹女梳粧越樣新。", "惟有東村王大姐，依前滿面是埃塵。"]'),
('8c246137-df9e-4115-ac2d-5871709c03bd','偈頌六十七首  其六','釋原妙','宋','宋诗','song-poetry','','[]','萬里不挂片雲，虛空突出一竅。',54,'全唐诗/poet.song.240000.json','["萬里不挂片雲，虛空突出一竅。", "雙髻峰𨁝跳上三十三天，拄杖子向十字街頭揚聲大叫。", "炎炎六月火生冰，夜半日輪當午照。"]'),
('7a4847cb-322a-443b-a016-15ae602f9caf','偈頌六十七首  其七','釋原妙','宋','宋诗','song-poetry','','[]','一夏九十日，看看又將半。',64,'全唐诗/poet.song.240000.json','["一夏九十日，看看又將半。", "面門無位人，急著眼睛看。", "冷地驀相逢，脚跟紅線斷。", "掌內握乾坤，翻身遊碧漢。", "堪笑當年老瑞巖，惺惺石上重呼喚。"]'),
('02a69ad8-f89a-4247-b3e2-4bd7535ed6a4','偈頌六十七首  其八','釋原妙','宋','宋诗','song-poetry','','[]','五湖春色十分肥，正是功圓果滿時。',64,'全唐诗/poet.song.240000.json','["五湖春色十分肥，正是功圓果滿時。", "玉蝶穿花零碎錦，黄鶑擲柳亂垂絲。", "靈雲打失娘生眼，備老重添八字眉。", "無限水邊林下客，謾將竹杖度須彌。"]'),
('7b9edc9e-1c45-4627-a938-d6ed95419f51','偈頌六十七首  其九','釋原妙','宋','宋诗','song-poetry','','[]','歸宗拭却眼睛，二祖安心斷臂。',51,'全唐诗/poet.song.240000.json','["歸宗拭却眼睛，二祖安心斷臂。", "雲門拶折一足，玄沙𡎺破脚指。", "遮一夥隨摟搜漢，蚤知有遮般消息，免見血淋滿地。"]'),
('095bd711-8fdb-40f8-8416-33d8477c9a68','偈頌六十七首  其一○','釋原妙','宋','宋诗','song-poetry','','[]','新年頭，行新令。',62,'全唐诗/poet.song.240000.json','["新年頭，行新令。", "露柱燈籠，急著眼聽。", "竈頭西南角有片方磚，惺惺伶俐，伶俐惺惺。", "念茲在茲，必恭必敬。", "因甚如此，徐十三郎行年本命。"]'),
('d7d14354-d442-4967-a52c-b5c1c90490df','偈頌六十七首  其一一','釋原妙','宋','宋诗','song-poetry','','[]','愛之欲其生，惡之欲其死。',48,'全唐诗/poet.song.240000.json','["愛之欲其生，惡之欲其死。", "愛惡兩重關，總向遮裏起。", "直饒識得根源，更買草鞋行脚三十年，何曾踏著遮裏。"]'),
('4a3be4cb-41b9-401c-97a2-dadac049bfae','偈頌六十七首  其一二','釋原妙','宋','宋诗','song-poetry','','[]','師子窟，師子吼。',30,'全唐诗/poet.song.240000.json','["師子窟，師子吼。", "師子兒，無前後。", "驀然直下翻身，便解人前開口。"]'),
('499737de-1d35-4dfc-8e09-b9095b3a5c2c','偈頌六十七首  其一三','釋原妙','宋','宋诗','song-poetry','','[]','大限九旬，小限七日。',125,'全唐诗/poet.song.240000.json','["大限九旬，小限七日。", "粗中有細，細中有密。", "密密無間，纖塵不立。", "正恁麽時，銀山鐵壁。", "進則無門，退之則失。", "如墮萬丈深坑，四面懸崖荆棘。", "切須猛烈英雄，直要翻身跳出。", "若還一念遲疑，佛亦救你不得。", "此是最上玄門，普請大家著力。", "山僧雖則不管閒非，越例與諸人通箇消息。"]'),
('71dce57a-76a1-41b9-a0c6-1beecc66c643','偈頌六十七首  其一四','釋原妙','宋','宋诗','song-poetry','','[]','指天指地展戈矛，直至如今戰不休。',32,'全唐诗/poet.song.240000.json','["指天指地展戈矛，直至如今戰不休。", "假使羣靈都殺盡，一身還有一身愁。"]'),
('0fde72c7-8df4-4445-946f-c59282a2c8bb','偈頌六十七首  其一五','釋原妙','宋','宋诗','song-poetry','','[]','天關久鎖不開容，日夜滂沱鼓黑風。',32,'全唐诗/poet.song.240000.json','["天關久鎖不開容，日夜滂沱鼓黑風。", "憤性一槌俱擊碎，頂門迸出一輪紅。"]'),
('c86a92e0-da6b-4984-a88e-9dbe0a55e235','偈頌六十七首  其一六','釋原妙','宋','宋诗','song-poetry','','[]','忘却當年密授句，枉教一衆喫辛苦。',32,'全唐诗/poet.song.240000.json','["忘却當年密授句，枉教一衆喫辛苦。", "夜來枕上忽憶著，年年五月黄梅雨。"]'),
('e6db4da0-b1bf-4da7-ba3f-c891b1658492','偈頌六十七首  其一七','釋原妙','宋','宋诗','song-poetry','','[]','一葉落，天下秋。',32,'全唐诗/poet.song.240000.json','["一葉落，天下秋。", "一塵起，大地收。", "有意氣時添意氣，不風流處也風流。"]'),
('1d109dd1-39d7-4117-841b-931d8afb0b50','偈頌六十七首  其一八','釋原妙','宋','宋诗','song-poetry','','[]','海底泥牛銜月走，巖前石虎抱兒眠。',32,'全唐诗/poet.song.240000.json','["海底泥牛銜月走，巖前石虎抱兒眠。", "鐵蛇鑽入金剛眼，崑崙騎象鷺鷥牽。"]'),
('ad825d88-84c5-4726-bc69-0f7284b8d68a','偈頌六十七首  其一九','釋原妙','宋','宋诗','song-poetry','','[]','陰向鼻端滅，陽從眼裏生。',24,'全唐诗/poet.song.240000.json','["陰向鼻端滅，陽從眼裏生。", "會得箇中意，更參三十年。"]'),
('988428a7-4acb-4db4-ab0c-6dca996e937c','偈頌六十七首  其二○','釋原妙','宋','宋诗','song-poetry','','[]','禪不在參，道不須悟。',38,'全唐诗/poet.song.240000.json','["禪不在參，道不須悟。", "動轉施爲，山嶽鼓舞。", "孟八郎漢便恁麽去，爭似西峰搬石運土。"]'),
('7c95a1c9-cd49-4f5d-8d16-70408b929b93','偈頌六十七首  其二一','釋原妙','宋','宋诗','song-poetry','','[]','水中鹹味，色裏膠青。',34,'全唐诗/poet.song.240000.json','["水中鹹味，色裏膠青。", "决定是有，不見其形。", "見其形，失却山前一村人眼睛。"]'),
('8d295084-964a-48b2-8b8c-ac0be9984199','偈頌六十七首  其二二','釋原妙','宋','宋诗','song-poetry','','[]','八十日中，千說萬喻。',66,'全唐诗/poet.song.240000.json','["八十日中，千說萬喻。", "說也說到無說時，聞也聞到無聞處。", "既是無說又無聞，功成果滿憑何舉。", "吹龍笛，擊鼉鼓。", "皓齒歌，細腰舞。", "桃花亂落如紅雨。"]'),
('5422ddf3-6dd6-4f73-9eeb-03d0dda5d6c3','偈頌六十七首  其二三','釋原妙','宋','宋诗','song-poetry','','[]','大海無魚，大地無草。',20,'全唐诗/poet.song.240000.json','["大海無魚，大地無草。", "大富無糧，大悟無道。"]'),
('d86c1827-b929-452c-9e96-53d96b475fa1','偈頌六十七首  其二四','釋原妙','宋','宋诗','song-poetry','','["\u897f\u6e56"]','布袋頭開，餧馿餧馬。',43,'全唐诗/poet.song.240000.json','["布袋頭開，餧馿餧馬。", "要騎便騎，要下便下。", "若到江西湖南，撞著焦尾大蟲，切莫道在西峰度夏。"]'),
('fcf204dc-e91d-4766-a6bc-d7a80467acdc','偈頌六十七首  其二五','釋原妙','宋','宋诗','song-poetry','','[]','喫粥了也，洗鉢盂去。',39,'全唐诗/poet.song.240000.json','["喫粥了也，洗鉢盂去。", "矢上加尖，一場敗露。", "西峰今日忍俊不禁，却要向鷺鷥腿上割股。"]'),
('8c7da046-7a5c-4644-91d8-0f6669568668','偈頌六十七首  其二六','釋原妙','宋','宋诗','song-poetry','','[]','一陽來復，萬物咸新。',37,'全唐诗/poet.song.240000.json','["一陽來復，萬物咸新。", "恭惟盲龜跛鼈，鬼怪妖精。", "莫問前長後短，大家扶起破沙盆。"]'),
('2f1ee53b-6710-4884-8a3a-aa3875a24af2','偈頌六十七首  其二七','釋原妙','宋','宋诗','song-poetry','','[]','黄面瞿曇，夜半成道。',38,'全唐诗/poet.song.240000.json','["黄面瞿曇，夜半成道。", "正是喚奴作郎，贏得一場好笑。", "山僧恁麽告報，也是細姑嫌嫂。"]'),
('ba5ecf4b-0d90-4caf-874c-5d90ce0a10f5','偈頌六十七首  其二八','釋原妙','宋','宋诗','song-poetry','','[]','參須實參，悟須實悟。',58,'全唐诗/poet.song.240000.json','["參須實參，悟須實悟。", "動轉施爲，輝今耀古。", "若是操心不正，悟處不真，粧粧點點，鬭鬭釘釘，被人輕輕拶著，未免喚燈籠作露柱。"]'),
('57381fc8-a1ba-49e0-9d79-edfc6001f210','偈頌六十七首  其二九','釋原妙','宋','宋诗','song-poetry','','[]','低頭覓天，仰面尋地。',57,'全唐诗/poet.song.240000.json','["低頭覓天，仰面尋地。", "波波挈挈，遠之遠矣。", "驀然撞著徐十三郎，嗄，元來只在遮裏。", "在遮裏，臘月三十日到來，也是開眼見鬼。"]'),
('19430dbe-d2b8-4340-847e-7bfc554ecd69','偈頌六十七首  其三○','釋原妙','宋','宋诗','song-poetry','','[]','洞徹是非如夢幻，轉身未免墮深坑。',32,'全唐诗/poet.song.240000.json','["洞徹是非如夢幻，轉身未免墮深坑。", "須知別有通霄路，不許時人造次行。"]'),
('6b057f59-fc51-46a0-ab39-7b007eae095b','偈頌六十七首  其三一','釋原妙','宋','宋诗','song-poetry','','[]','昔年瞎却我眼，今朝穿却你鼻。',42,'全唐诗/poet.song.240000.json','["昔年瞎却我眼，今朝穿却你鼻。", "冤冤相報無休，莫若克己復禮。", "非惟和尚同塵，免得遞相鈍置。"]'),
('3b8a17c3-fb65-437f-b1ac-6e387586fed1','偈頌六十七首  其三二','釋原妙','宋','宋诗','song-poetry','','[]','一年已減五日，光影如駒過隙。',44,'全唐诗/poet.song.240000.json','["一年已減五日，光影如駒過隙。", "直須如救頭然，切莫隨情放逸。", "夜來一雨雪消鎔，萬疊青山如洗出。"]'),
('e1d6f232-e564-47e1-8fb1-f4302aba1b16','偈頌六十七首  其三三','釋原妙','宋','宋诗','song-poetry','','[]','參禪須是鐵漢，著手心頭便判。',39,'全唐诗/poet.song.240000.json','["參禪須是鐵漢，著手心頭便判。", "只如雪覆千山，孤峰不白，作麽生判。", "上元定是正月半。"]'),
('c3902f3a-b3fd-4fe7-80e5-3d8590e0f4da','偈頌六十七首  其三四','釋原妙','宋','宋诗','song-poetry','','[]','周行七步猶成跡，槨示雙趺豈易收。',32,'全唐诗/poet.song.240000.json','["周行七步猶成跡，槨示雙趺豈易收。", "微雨灑花千點泪，淡烟籠竹一堆愁。"]'),
('b8d01b35-2289-44eb-abbe-b2fb83069251','偈頌六十七首  其三五','釋原妙','宋','宋诗','song-poetry','','[]','身貧道貧，無法可親。',42,'全唐诗/poet.song.240000.json','["身貧道貧，無法可親。", "一味盲枷瞎棒，聞者見者莫不生嗔。", "黄金自有黄金價，終不和沙賣與人。"]'),
('d7d96901-047f-4c99-9a20-b09acc9b0683','偈頌六十七首  其三六','釋原妙','宋','宋诗','song-poetry','','[]','西峰今年結夏，全然不成保社。',49,'全唐诗/poet.song.240000.json','["西峰今年結夏，全然不成保社。", "一日兩頭薄粥，大家忍饑無暇。", "雖有真如佛性，菩提涅槃，權且颺在師子巖下。"]'),
('3ca6a9fc-0531-4762-9fe1-c2d55708d224','偈頌六十七首  其三七','釋原妙','宋','宋诗','song-poetry','','[]','日正暄，春已暮，落花片片隨流去。',32,'全唐诗/poet.song.240000.json','["日正暄，春已暮，落花片片隨流去。", "拄杖枝頭一點紅，馨香徧界無人顧。"]'),
('4d17456d-7464-40be-8c89-84393ddc4229','偈頌六十七首  其三八','釋原妙','宋','宋诗','song-poetry','','[]','一夏以來，諸人懡㦬，山僧亦懡㦬。',67,'全唐诗/poet.song.240000.json','["一夏以來，諸人懡㦬，山僧亦懡㦬。", "懡㦬逢懡㦬，彼此無空過。", "今朝聖制告圓，不免更說些懡㦬禪，贏得大家俱懡㦬。", "如何是懡㦬禪，咄，猛火著油煎。"]'),
('4c00709d-28f1-4ed7-a2c0-f4906a58b9b2','偈頌六十七首  其三九','釋原妙','宋','宋诗','song-poetry','','[]','一年三百六十日，看看逗到今宵畢。',54,'全唐诗/poet.song.240000.json','["一年三百六十日，看看逗到今宵畢。", "十箇有五雙，參禪禪又不知，學道道亦不識。", "只遮不知不識四字，正是三世諸佛骨髓。"]'),
('79ad6bed-61e2-4418-a2c9-3d297fec2603','偈頌六十七首  其四○','釋原妙','宋','宋诗','song-poetry','','[]','封却拄杖頭，結却布袋頭。',42,'全唐诗/poet.song.240000.json','["封却拄杖頭，結却布袋頭。", "大家團欒頭，赤眼火柴頭。", "嗄，正是冤家共聚頭，不妨頭上更安頭。"]'),
('cdedf2b7-54da-4e24-9557-c88582b3d863','偈頌六十七首  其四一','釋原妙','宋','宋诗','song-poetry','','[]','前四十五日何處去，焦尾大蟲入閙市。',52,'全唐诗/poet.song.240000.json','["前四十五日何處去，焦尾大蟲入閙市。", "後四十五日何處來，三脚馿子上高臺。", "俊鷹快鷂便合乘時，跛鼈盲龜徒勞𨁝跳。"]'),
('7555853b-31da-426f-bbad-cd59d1f2ab10','偈頌六十七首  其四二','釋原妙','宋','宋诗','song-poetry','','[]','巴陵設忌三轉語，西峰單單只一句。',25,'全唐诗/poet.song.240000.json','["巴陵設忌三轉語，西峰單單只一句。", "聻，逢人切忌錯舉。"]'),
('2e6608e7-f773-4ca0-aea4-cddad5477dbb','偈頌六十七首  其四三','釋原妙','宋','宋诗','song-poetry','','[]','指天指地，一棒打殺。',36,'全唐诗/poet.song.240000.json','["指天指地，一棒打殺。", "鴆屎砒霜，合造毒藥。", "颺在三千世界中，不知那箇親遭著。"]'),
('903ff745-4b6a-4650-8b81-6613f13e6179','偈頌六十七首  其四四','釋原妙','宋','宋诗','song-poetry','','[]','西峰結制不尋常，穀滿倉兮僧滿堂。',32,'全唐诗/poet.song.240000.json','["西峰結制不尋常，穀滿倉兮僧滿堂。", "既得遮些根蒂固，大家摇扇取風凉。"]'),
('e18d1e4f-6555-41a0-83ce-56e89068b73e','偈頌六十七首  其四五','釋原妙','宋','宋诗','song-poetry','','[]','三千世界作爐，百億須彌爲炭。',28,'全唐诗/poet.song.240000.json','["三千世界作爐，百億須彌爲炭。", "生鐵鑄就禪和，炙得通身紅爛。"]'),
('0063b9ca-4088-4c2c-a7dd-3ecd6239f562','偈頌六十七首  其四六','釋原妙','宋','宋诗','song-poetry','','[]','十五日已前，{毛畏}{毛畏}𣯧𣯧，魍魍魎魎。',80,'全唐诗/poet.song.240000.json','["十五日已前，{毛畏}{毛畏}𣯧𣯧，魍魍魎魎。", "十五日已後，巍巍堂堂，煒煒煌煌。", "正當十五日，虛空爲鼓。", "須彌爲槌，輕輕擊動，佛祖攢眉。", "若將耳聽應難會，眼處聞聲方始知。"]'),
('47a3f7d6-66b5-4d5a-b60b-72346ba46c9d','偈頌六十七首  其四七','釋原妙','宋','宋诗','song-poetry','','[]','入我法中，不論凡聖。',20,'全唐诗/poet.song.240000.json','["入我法中，不論凡聖。", "動轉施爲，咸遵舊令。"]'),
('db9d9769-3c2d-4303-8d35-a69f6ccad81c','偈頌六十七首  其四八','釋原妙','宋','宋诗','song-poetry','','[]','九旬把定重關，今朝放開一線。',35,'全唐诗/poet.song.240000.json','["九旬把定重關，今朝放開一線。", "頂門具眼衲僧，自合知機識變。", "依舊平分局面。"]'),
('8e2b7374-1583-4791-a6d0-9b49dff38b4b','偈頌六十七首  其四九','釋原妙','宋','宋诗','song-poetry','','[]','一不成，二不是。',41,'全唐诗/poet.song.240000.json','["一不成，二不是。", "紅底桃，白底李。", "紅紅白白不相瞞，因甚達磨大師被流支三藏打落當門齒。"]'),
('50b7f2b9-7b00-42c8-acf4-27c087a9804f','偈頌六十七首  其五○','釋原妙','宋','宋诗','song-poetry','','[]','裁蜀錦，翦吳綾。',54,'全唐诗/poet.song.240000.json','["裁蜀錦，翦吳綾。", "披白玉，間黄金。", "打成一片時，針劄不入。", "羅紋結角處，線路難尋。", "天香影散莓苔石，五葉花開薝蔔林。"]'),
('ff4a9e5d-0f9a-4946-abf4-18de4aa35229','偈頌六十七首  其五一','釋原妙','宋','宋诗','song-poetry','','[]','一百禪和三十州，無繩自縛萬山頭。',32,'全唐诗/poet.song.240000.json','["一百禪和三十州，無繩自縛萬山頭。", "誰是護生誰是殺，白雲影裏鐵船浮。"]'),
('81f638d9-ee7d-4b7e-a325-bc60a3c5576d','偈頌六十七首  其五二','釋原妙','宋','宋诗','song-poetry','','[]','萬法歸一，一歸何處。',34,'全唐诗/poet.song.240000.json','["萬法歸一，一歸何處。", "狹路相逢，兩手分付。", "逴得便行，黄河三千年一度清。"]'),
('dffa038b-d445-4212-bb92-52b2fc4f262c','偈頌六十七首  其五三','釋原妙','宋','宋诗','song-poetry','','[]','意句不到，宗說不通，盲龜跛鼈。',30,'全唐诗/poet.song.240000.json','["意句不到，宗說不通，盲龜跛鼈。", "意句俱到，宗說俱通，盲龜跛鼈。"]'),
('ff889342-90c7-46a6-bde7-5e9b9d541f56','偈頌六十七首  其五四','釋原妙','宋','宋诗','song-poetry','','[]','呱聲未絕便稱尊，攪得三千海嶽昏。',32,'全唐诗/poet.song.240000.json','["呱聲未絕便稱尊，攪得三千海嶽昏。", "惡水一年澆一度，知他雪屈是酬恩。"]'),
('8caaba00-ca62-490e-8538-ddb310150061','偈頌六十七首  其五五','釋原妙','宋','宋诗','song-poetry','','[]','工夫不到不方圓，寬著程途急著鞭。',32,'全唐诗/poet.song.240000.json','["工夫不到不方圓，寬著程途急著鞭。", "但得此心常不昧，從教滄海變桑田。"]'),
('c1299006-f002-43ad-b7fe-f1f74b801421','偈頌六十七首  其五六','釋原妙','宋','宋诗','song-poetry','','[]','識得拄杖子，被拄杖子縛。',37,'全唐诗/poet.song.240000.json','["識得拄杖子，被拄杖子縛。", "不識拄杖子，亦被拄杖子縛。", "不是弄潮人，徒勞遭點額。"]'),
('629f3e0e-faf7-415e-b0ff-ecce810c390c','偈頌六十七首  其五七','釋原妙','宋','宋诗','song-poetry','','[]','咄哉老賊，偷心未息。',48,'全唐诗/poet.song.240000.json','["咄哉老賊，偷心未息。", "石灰布袋，到處成跡。", "若謂子爲父隠，畢竟曲不藏直。", "今日因齋慶讚，未免乘時拈出。"]'),
('e4eb78b4-3579-4d1c-b86c-010fcb1ad93b','偈頌六十七首  其五八','釋原妙','宋','宋诗','song-poetry','','[]','一年又過一月，今日又從頭起。',55,'全唐诗/poet.song.240000.json','["一年又過一月，今日又從頭起。", "循環烏兔如梭，百年光陰有幾。", "諸上座，休瞌睡。", "直饒火急翻身，四大海水早已傾在汝耳裏。"]'),
('dc2c55de-cf66-4a9b-b1cf-c7153b174f98','偈頌六十七首  其五九','釋原妙','宋','宋诗','song-poetry','','[]','今年龍象頗多，權作三堂結夏。',28,'全唐诗/poet.song.240000.json','["今年龍象頗多，權作三堂結夏。", "雖然名字不同，是法本無高下。"]'),
('7ce44ea2-720e-4db0-ad3a-7967057d1d09','偈頌六十七首  其六○','釋原妙','宋','宋诗','song-poetry','','[]','資生貴圖求富，參禪貴圖求悟。',42,'全唐诗/poet.song.240000.json','["資生貴圖求富，參禪貴圖求悟。", "求悟若學資生，箇箇成佛作祖。", "咄，甜瓜徹蒂甜，苦瓠連根苦。"]'),
('3b32a638-4476-4303-9467-799680f8c387','偈頌六十七首  其六一','釋原妙','宋','宋诗','song-poetry','','[]','千疑萬疑，祇是一疑。',24,'全唐诗/poet.song.240000.json','["千疑萬疑，祇是一疑。", "若能决此一疑，免教節上生枝。"]'),
('b73b4f8d-81f0-4a82-bbb4-c81431c6bd7a','偈頌六十七首  其六二','釋原妙','宋','宋诗','song-poetry','','[]','打開布袋頭，放出百千牛。',40,'全唐诗/poet.song.240000.json','["打開布袋頭，放出百千牛。", "縱隨芳草去，終不被人收。", "一日歸來重會面，半含容笑半含羞。"]'),
('6f91f490-230c-46a9-a0c3-4cdc4b7407a3','偈頌六十七首  其六三','釋原妙','宋','宋诗','song-poetry','','[]','今朝八月一，行脚禪和出。',74,'全唐诗/poet.song.240000.json','["今朝八月一，行脚禪和出。", "不識自家珍，却向途中覓。", "直饒走徧一百一十城，參見五十三善知識，功超十地三乘，位等釋迦彌勒。", "若還來到西峰，未免一棒打折你馿脊。"]'),
('74d43842-d520-46a9-9513-5eb6d4bc5dc2','偈頌六十七首  其六四','釋原妙','宋','宋诗','song-poetry','','[]','急水灘頭泊小舟，切須牢把遮繩頭。',32,'全唐诗/poet.song.240000.json','["急水灘頭泊小舟，切須牢把遮繩頭。", "驀然繩斷難迴避，直到通身血迸流。"]'),
('9f531fc8-672f-42e4-b8ed-2ec985268d2f','偈頌六十七首  其六五','釋原妙','宋','宋诗','song-poetry','','[]','參禪一著莫遲疑，念念如同救火時。',48,'全唐诗/poet.song.240000.json','["參禪一著莫遲疑，念念如同救火時。", "烈燄亙天渾不顧，翻身直造萬重圍。", "一朝火滅烟消後，鼻孔依前向下垂。"]'),
('42304028-88f1-4025-a26a-19a948e0992c','偈頌六十七首  其六六','釋原妙','宋','宋诗','song-poetry','','[]','萬法歸一一何歸，只貴惺惺著意疑。',32,'全唐诗/poet.song.240000.json','["萬法歸一一何歸，只貴惺惺著意疑。", "疑到情忘心絕處，金烏夜半徹天飛。"]'),
('258c28f7-b855-47c7-8da4-757a7491e91c','偈頌六十七首  其六七','釋原妙','宋','宋诗','song-poetry','','[]','紅塵堆裏學山居，寂滅身心道有餘。',32,'全唐诗/poet.song.240000.json','["紅塵堆裏學山居，寂滅身心道有餘。", "但得胸中憎愛盡，不參禪亦是工夫。"]'),
('48f29fc1-aeed-4592-a9d3-4a91510f94f5','頌古三十一首  其一','釋原妙','宋','宋诗','song-poetry','','[]','靈山拈出一枝花，百萬都來是作家。',32,'全唐诗/poet.song.240000.json','["靈山拈出一枝花，百萬都來是作家。", "惟有飲光猶未瞥，那堪眼裏又添沙。"]'),
('df0b8d67-ab0f-4e97-97f4-bfa4431fe7da','頌古三十一首  其二','釋原妙','宋','宋诗','song-poetry','','[]','兩兩成羣罪莫窮，謾將鼠伎逞英雄。',32,'全唐诗/poet.song.240000.json','["兩兩成羣罪莫窮，謾將鼠伎逞英雄。", "當時若作今時世，縱使瞿曇也不中。"]'),
('64bc7087-faf6-4881-84b5-ce1022f43efd','頌古三十一首  其三','釋原妙','宋','宋诗','song-poetry','','[]','死款都來一口供，情窮理極卒難容。',32,'全唐诗/poet.song.240000.json','["死款都來一口供，情窮理極卒難容。", "若將皮髓論高下，爭見花開五葉紅。"]'),
('d7f66315-23ec-49d1-b231-ddcdcbceb802','頌古三十一首  其四','釋原妙','宋','宋诗','song-poetry','','[]','祖師不會禪，夫子不識字。',24,'全唐诗/poet.song.240000.json','["祖師不會禪，夫子不識字。", "棒打石人頭，嚗嚗論實事。"]'),
('e39f8f2f-2d97-449e-8919-2dbb4fc570e8','頌古三十一首  其五','釋原妙','宋','宋诗','song-poetry','','[]','攢花簇錦絕纖塵，一度拈來一度新。',32,'全唐诗/poet.song.240000.json','["攢花簇錦絕纖塵，一度拈來一度新。", "啼得血流無用處，不如緘口過殘春。"]'),
('026b9261-856a-4ce2-ab2d-f181a18e16ea','頌古三十一首  其六','釋原妙','宋','宋诗','song-poetry','','[]','殺人猶可恕，再犯豈能容。',24,'全唐诗/poet.song.240000.json','["殺人猶可恕，再犯豈能容。", "貶向無生國，千聖不知蹤。"]'),
('f8aca2d5-1468-44c1-a820-0d40a605567c','頌古三十一首  其七','釋原妙','宋','宋诗','song-poetry','','[]','眉毛罅裏積山嶽，鼻孔中藏師子兒。',32,'全唐诗/poet.song.240000.json','["眉毛罅裏積山嶽，鼻孔中藏師子兒。", "南北東西無限意，此心能有幾人知。"]'),
('4ac977e0-a33e-41d8-a4db-9ba2764f0bd1','頌古三十一首  其八','釋原妙','宋','宋诗','song-poetry','','["\u590f\u5929", "\u5199\u666f"]','綠樹陰濃夏日長，樓臺倒影入池塘。',32,'全唐诗/poet.song.240000.json','["綠樹陰濃夏日長，樓臺倒影入池塘。", "水晶簾動微風起，滿架薔薇一院香。"]'),
('445f4225-6d06-41c6-9e96-53495ec33aa0','頌古三十一首  其九','釋原妙','宋','宋诗','song-poetry','','[]','幸然無事鼓風濤，激起洪波萬丈高。',32,'全唐诗/poet.song.240000.json','["幸然無事鼓風濤，激起洪波萬丈高。", "直得渾家都浸殺，至今平地浪滔滔。"]'),
('79e632fc-5904-4cd8-964d-dc66587ee9df','頌古三十一首  其一○','釋原妙','宋','宋诗','song-poetry','','[]','自小丹青畫不成，年來始覺藝方精。',32,'全唐诗/poet.song.240000.json','["自小丹青畫不成，年來始覺藝方精。", "等閑擲筆成龍去，換却時人眼裏睛。"]'),
('4aee154a-aaca-49b7-af72-74d2b128e804','頌古三十一首  其一一','釋原妙','宋','宋诗','song-poetry','','[]','泥佛不度水，毗嵐風忽起。',24,'全唐诗/poet.song.240000.json','["泥佛不度水，毗嵐風忽起。", "大地黑漫漫，衲僧爭敢視。"]'),
('f5b37f47-8d47-484e-abec-8ec93234f498','頌古三十一首  其一二','釋原妙','宋','宋诗','song-poetry','','[]','金佛不度爐，鐵裹夜明珠。',24,'全唐诗/poet.song.240000.json','["金佛不度爐，鐵裹夜明珠。", "一槌俱粉碎，清光何處無。"]'),
('df84ae53-6fa4-4e68-a5ea-83ba7bc63fc5','頌古三十一首  其一三','釋原妙','宋','宋诗','song-poetry','','[]','木佛不度火，掣開金殿鎖。',24,'全唐诗/poet.song.240000.json','["木佛不度火，掣開金殿鎖。", "內外絕遮欄，時人猶懡㦬。"]'),
('be1de7cb-b4ae-4122-9f9f-c39947fcc976','頌古三十一首  其一四','釋原妙','宋','宋诗','song-poetry','','[]','趙州狗子佛性無，十分春色播江湖。',32,'全唐诗/poet.song.240000.json','["趙州狗子佛性無，十分春色播江湖。", "幾多摘葉尋枝客，空使洛陽花滿途。"]'),
('866b79a6-4f22-4a1c-b783-572cff6c693e','頌古三十一首  其一五','釋原妙','宋','宋诗','song-poetry','','[]','禮佛修行不較多，何須特地起干戈。',32,'全唐诗/poet.song.240000.json','["禮佛修行不較多，何須特地起干戈。", "直饒打得回頭後，兔子何曾離得窠。"]'),
('5040d401-ede4-4e20-b977-d72224339d8b','頌古三十一首  其一六','釋原妙','宋','宋诗','song-poetry','','[]','四面洪波萬丈深，上天無路地無門。',32,'全唐诗/poet.song.240000.json','["四面洪波萬丈深，上天無路地無門。", "箇中有理應難訴，不是愁人也斷魂。"]'),
('ff9a08d7-6254-4b42-b9c8-34b34e8c906e','頌古三十一首  其一七','釋原妙','宋','宋诗','song-poetry','','[]','吞而復吐冷烟浮，月落寒山猶未休。',32,'全唐诗/poet.song.240000.json','["吞而復吐冷烟浮，月落寒山猶未休。", "重把絲綸輕一掣，豈知元只在鈎頭。"]'),
('e598a182-fc8d-412e-a3cd-7242c5e42348','頌古三十一首  其一八','釋原妙','宋','宋诗','song-poetry','','[]','猛虎深藏淺草窠，幾回明月入烟蘿。',32,'全唐诗/poet.song.240000.json','["猛虎深藏淺草窠，幾回明月入烟蘿。", "頂門縱有金剛眼，未免當頭蹉過他。"]'),
('bd4868ca-8eb6-4584-a8ec-2bfbde41fb4f','頌古三十一首  其一九','釋原妙','宋','宋诗','song-poetry','','[]','颯颯秋風滿院凉，芬芳籬菊半經霜。',32,'全唐诗/poet.song.240000.json','["颯颯秋風滿院凉，芬芳籬菊半經霜。", "可憐不遇攀花手，狼籍枝頭多少香。"]'),
('95c35fa2-38a2-442d-961c-f85fbff3b13b','頌古三十一首  其二○','釋原妙','宋','宋诗','song-poetry','','[]','饑火炎炎燒斷腸，親逢王膳不能嘗。',32,'全唐诗/poet.song.240000.json','["饑火炎炎燒斷腸，親逢王膳不能嘗。", "可憐併逐溪流去，百億滄溟透底香。"]'),
('20301d9f-be98-40e3-8f71-cdbe64052a8b','頌古三十一首  其二一','釋原妙','宋','宋诗','song-poetry','','[]','國師塔樣最尖新，覿面拈來不露文。',32,'全唐诗/poet.song.240000.json','["國師塔樣最尖新，覿面拈來不露文。", "却被耽源添一線，至今描邈亂紛紛。"]'),
('9e29d0cd-a2d8-40f1-b966-cec3dfc433c5','頌古三十一首  其二二','釋原妙','宋','宋诗','song-poetry','','[]','楊柳溪邊垂綠線，黄鶑枝上聲聲囀。',32,'全唐诗/poet.song.240000.json','["楊柳溪邊垂綠線，黄鶑枝上聲聲囀。", "幾多貪玩不知春，空使落花千萬片。"]'),
('dde891e7-7583-4f94-b0d6-f2cb602ad384','頌古三十一首  其二三','釋原妙','宋','宋诗','song-poetry','','[]','三十年來在夢中，生涯喪盡絕行蹤。',32,'全唐诗/poet.song.240000.json','["三十年來在夢中，生涯喪盡絕行蹤。", "自慚一見桃花後，依舊漫天鼓黑風。"]'),
('f6844f4a-c026-4503-a6d5-4d1fdcab58b9','頌古三十一首  其二四','釋原妙','宋','宋诗','song-poetry','','[]','落花臺上重鋪錦，瑪瑙階前布赤沙。',32,'全唐诗/poet.song.240000.json','["落花臺上重鋪錦，瑪瑙階前布赤沙。", "情義盡從貧處斷，世人偏向有錢家。"]'),
('e168def5-af05-454a-8023-5d696de6ce5e','頌古三十一首  其二五','釋原妙','宋','宋诗','song-poetry','','[]','紅輪杲杲正當空，昨日今朝事不同。',32,'全唐诗/poet.song.240000.json','["紅輪杲杲正當空，昨日今朝事不同。", "盡謂古今都坐斷，誰知賊過後張弓。"]'),
('abbb86ee-ce49-4348-a9ea-602437c2d268','頌古三十一首  其二六','釋原妙','宋','宋诗','song-poetry','','[]','滯貨多年要脫身，巧粧綺語說諸人。',32,'全唐诗/poet.song.240000.json','["滯貨多年要脫身，巧粧綺語說諸人。", "及乎拈出當場賣，索價遼天誰敢親。"]'),
('fb791f05-0bb1-44ec-abad-bbc5ab60ab1f','頌古三十一首  其二七','釋原妙','宋','宋诗','song-poetry','','[]','弓絃走馬驀相逢，覿面全提未見功。',32,'全唐诗/poet.song.240000.json','["弓絃走馬驀相逢，覿面全提未見功。", "拈出輪王三寸鐵，直教血濺梵天紅。"]'),
('82863c6b-fb2c-4fe2-86f6-3adc5803b26d','頌古三十一首  其二八','釋原妙','宋','宋诗','song-poetry','','[]','銀蟾出海照無私，處處分明是阿誰。',32,'全唐诗/poet.song.240000.json','["銀蟾出海照無私，處處分明是阿誰。", "見面不須重問訊，從教日炙與風吹。"]'),
('2b0c157b-13d9-40dc-b61a-2ab02c8a0ac2','頌古三十一首  其二九','釋原妙','宋','宋诗','song-poetry','','[]','不動尊，提不起，茫茫宇宙誰能委。',32,'全唐诗/poet.song.240000.json','["不動尊，提不起，茫茫宇宙誰能委。", "秋江清夜月澄輝，鷺鷥飛入蘆花裏。"]'),
('c6b9bbe3-1fd2-443a-a9be-9232a5cb60ea','頌古三十一首  其三○','釋原妙','宋','宋诗','song-poetry','','[]','逆風吹又順風吹，鐵眼銅睛爭敢窺。',32,'全唐诗/poet.song.240000.json','["逆風吹又順風吹，鐵眼銅睛爭敢窺。", "萬古碧潭空界月，再三撈摝始應知。"]'),
('62216bf4-606b-4847-993d-561e794ac04e','頌古三十一首  其三一','釋原妙','宋','宋诗','song-poetry','','[]','佛手馿脚與生緣，鬼面人頭有許般。',32,'全唐诗/poet.song.240000.json','["佛手馿脚與生緣，鬼面人頭有許般。", "雲散碧天孤月朗，澄潭徹底影團團。"]'),
('beb3ea8e-2226-4b97-a3af-c0f1a375c693','頌古三十一首  其三二','釋原妙','宋','宋诗','song-poetry','','[]','無端平地起干戈，爭似屬牛人更多。',32,'全唐诗/poet.song.240000.json','["無端平地起干戈，爭似屬牛人更多。", "滿面慚惶無著處，低頭依舊入烟蘿。"]'),
('3bbd94e3-7d1d-4ea6-8a53-a0d890851d1a','頌古三十一首  其三三','釋原妙','宋','宋诗','song-poetry','','[]','一二三四五六圈，心肝粉碎髑髏穿。',32,'全唐诗/poet.song.240000.json','["一二三四五六圈，心肝粉碎髑髏穿。", "若將方木投圓竅，醜姥爭教得少年。"]'),
('afad141d-b435-4c93-883a-6a14ae0e9ea4','頌趙州無字示陳太尉','釋原妙','宋','宋诗','song-poetry','','[]','澄潭千載毒龍蟠，倒嶽傾湫誰解看。',32,'全唐诗/poet.song.240000.json','["澄潭千載毒龍蟠，倒嶽傾湫誰解看。", "直下一刀成兩段，虛空粉碎髑髏乾。"]'),
('96fb6de0-5ec4-439a-b0b0-6d816a88be7e','示如法禪人  其一','釋原妙','宋','宋诗','song-poetry','','[]','識得根源認得伊，全身猶墮在塵圍。',32,'全唐诗/poet.song.240000.json','["識得根源認得伊，全身猶墮在塵圍。", "縱然和座都掀倒，尚有烟霞遶翠微。"]'),
('70a62f83-f92a-4502-b623-2b2ebcce2072','示如法禪人  其二','釋原妙','宋','宋诗','song-poetry','','[]','直造懸崖上上關，白雲影裏轉身難。',32,'全唐诗/poet.song.240000.json','["直造懸崖上上關，白雲影裏轉身難。", "箇中若使能通變，奪食驅耕總是閒。"]'),
('3dc9e7c9-8bae-41f2-9de2-4001079baec1','示如法禪人  其三','釋原妙','宋','宋诗','song-poetry','','[]','如如不動法中王，舉足無非是道場。',32,'全唐诗/poet.song.240000.json','["如如不動法中王，舉足無非是道場。", "不到水窮雲盡處，爭知覿面是檀郎。"]'),
('ee6988be-0945-4694-999f-d87a3d740d40','示如夢禪人行脚','釋原妙','宋','宋诗','song-poetry','','[]','閒處休居靜莫住，轉入轉深轉幽固。',64,'全唐诗/poet.song.240000.json','["閒處休居靜莫住，轉入轉深轉幽固。", "縱至深深盡底時，更須知有那一步。", "昔日曹溪親到來，今時往往多差互。", "若非喪盡目前機，倒嶽傾湫無覓處。"]'),
('dc873543-a7a8-42a7-b1bd-341bf5b1c8ec','山中四威儀供佛鑑師翁韻  其一','釋原妙','宋','宋诗','song-poetry','','[]','山中行，步高身儘輕。',20,'全唐诗/poet.song.240000.json','["山中行，步高身儘輕。", "擬飛去，惟恐世人驚。"]'),
('8a8ee13c-6128-4f31-be72-b4bffa78fbf4','山中四威儀供佛鑑師翁韻  其二','釋原妙','宋','宋诗','song-poetry','','[]','山中住，黯淡雲無數。',20,'全唐诗/poet.song.240000.json','["山中住，黯淡雲無數。", "誓相期，共守無生路。"]'),
('8f5f5a04-db73-4774-8776-ba713e89758d','山中四威儀供佛鑑師翁韻  其三','釋原妙','宋','宋诗','song-poetry','','[]','山中坐，靜看空花墮。',20,'全唐诗/poet.song.240000.json','["山中坐，靜看空花墮。", "問何爲，待結團欒果。"]'),
('d8ade8f4-7767-4501-a7d4-cb65274abf43','山中四威儀供佛鑑師翁韻  其四','釋原妙','宋','宋诗','song-poetry','','[]','山中卧，月落猿啼過。',20,'全唐诗/poet.song.240000.json','["山中卧，月落猿啼過。", "正堪眠，石定從教破。"]'),
('6cf7a70d-79e2-47bd-af44-330d95b69a1e','雲庵','釋原妙','宋','宋诗','song-poetry','','[]','或淡或濃拖雨去，半舒半捲逆風來。',32,'全唐诗/poet.song.240000.json','["或淡或濃拖雨去，半舒半捲逆風來。", "爲憐途路無棲泊，却把柴扉永夜開。"]'),
('aabbf46f-58df-49b5-8224-a70c24519a75','示徒  其一','釋原妙','宋','宋诗','song-poetry','','[]','學道如初莫變心，千魔萬難愈惺惺。',32,'全唐诗/poet.song.240000.json','["學道如初莫變心，千魔萬難愈惺惺。", "直須敲出虛空髓，拔却金剛腦後釘。"]'),
('9b43607f-0eca-4727-a140-d2fbdaab86ab','示徒  其二','釋原妙','宋','宋诗','song-poetry','','[]','學道之心似鏡明，纖塵纔染便忘形。',32,'全唐诗/poet.song.240000.json','["學道之心似鏡明，纖塵纔染便忘形。", "廓然照出娘生面，一簇青烟鎖翠屏。"]'),
('f008542a-23fc-43d0-a8c3-ccb1a5094061','示徒  其三','釋原妙','宋','宋诗','song-poetry','','[]','學道如撐逆水舟，篙篙著力莫隨流。',32,'全唐诗/poet.song.240000.json','["學道如撐逆水舟，篙篙著力莫隨流。", "忽然失脚翻身去，踏斷寒江月一鈎。"]'),
('49c1073a-ff4a-44cc-aabd-8ded2f8eb1e3','又示徒','釋原妙','宋','宋诗','song-poetry','','[]','工夫果的有真疑，動靜寒暄總不知。',32,'全唐诗/poet.song.240000.json','["工夫果的有真疑，動靜寒暄總不知。", "枕子驀然開口笑，鉢盂𨁝跳上須彌。"]'),
('a75fb2b1-bc63-4611-af3d-e328c1d642e2','示淳謙首座持鉢','釋原妙','宋','宋诗','song-poetry','','[]','千家萬家，總是維摩丈室。',61,'全唐诗/poet.song.240000.json','["千家萬家，總是維摩丈室。", "十斛百斛，無非達磨眼睛。", "若向遮裏會得，何勞向外經營。", "其或未然，咄，酒肆淫坊休放過，龍宮虎穴要親臨。"]'),
('f66ce6e0-814a-48d2-bd4e-1cdbd1b98e28','示徒三戒  其一','釋原妙','宋','宋诗','song-poetry','','[]','開口動舌，無益於人，戒之莫言。',15,'全唐诗/poet.song.240000.json','["開口動舌，無益於人，戒之莫言。"]'),
('d6ab3b9e-09c4-4460-8805-93d33baadafe','示徒三戒  其二','釋原妙','宋','宋诗','song-poetry','','[]','舉心動念，無益於人，戒之莫起。',15,'全唐诗/poet.song.240000.json','["舉心動念，無益於人，戒之莫起。"]'),
('a014cd8d-4f5e-4f92-98fd-fee72ca4c596','示徒三戒  其三','釋原妙','宋','宋诗','song-poetry','','[]','舉足動步，無益於人，戒之莫行。',15,'全唐诗/poet.song.240000.json','["舉足動步，無益於人，戒之莫行。"]'),
('cf20d89c-9844-4b2b-a818-4761266fc157','辭世','釋原妙','宋','宋诗','song-poetry','','[]','來不入死關，去不出死關。',24,'全唐诗/poet.song.240000.json','["來不入死關，去不出死關。", "鐵蛇鑽入海，撞倒須彌山。"]'),
('c3444ee5-e8b9-4afa-9691-e194730fb8ed','觀音大士贊','釋原妙','宋','宋诗','song-poetry','','[]','大海波心，磐陀石上。',47,'全唐诗/poet.song.240000.json','["大海波心，磐陀石上。", "真觀浄觀，是相非相。", "如月在天，無水不現。", "水月俱捐，如何瞻仰。", "咄，切忌妄想。"]'),
('82420552-d598-46dd-89c6-a84a71fa9f0b','達磨祖師贊  其一','釋原妙','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','開旗展陣入梁邦，未覩天顔早已降。',32,'全唐诗/poet.song.240000.json','["開旗展陣入梁邦，未覩天顔早已降。", "縱有神通難轉款，翩翩一葦渡長江。"]'),
('a51c518c-ab82-4af0-9183-4806bf8e79e8','達磨祖師贊  其二','釋原妙','宋','宋诗','song-poetry','','[]','未離西乾，惡聲已布。',40,'全唐诗/poet.song.240000.json','["未離西乾，惡聲已布。", "面壁九年，一場敗露。", "咦，不知賺却多少兒孫，直至如今釘樁摇櫓。"]'),
('9dbee42d-4294-479e-b380-b6db25fe70d1','師子院明初院主請','釋原妙','宋','宋诗','song-poetry','','[]','鼻無兩竅，眼露雙睛。',90,'全唐诗/poet.song.240000.json','["鼻無兩竅，眼露雙睛。", "十分無面目，一味得人憎。", "將正續三世之業，等閒籍沒。", "向白雲千峰之上，特地掀騰。", "坐斷死關，幸自惡聲難掩。", "那更被伊描邈，轉見可憐生。", "呵呵呵，三十年後，寧無人路見不平。"]'),
('6712f419-c7b6-41fe-ab18-762a66a6ebd1','大覺禪師祖雍長老請','釋原妙','宋','宋诗','song-poetry','','[]','中大仰毒，奮師子威。',71,'全唐诗/poet.song.240000.json','["中大仰毒，奮師子威。", "平生負重病，舉世無良醫。", "向蓮峰插一莖草，爲少室發千鈞機。", "舌頭無骨，額下生眉。", "喚作開山即錯，不喚作開山猶非，從教後代亂針錐。"]'),
('946a2c1a-ab34-46ee-9593-f8c86cc147d3','西隠接待師立山主請','釋原妙','宋','宋诗','song-poetry','','[]','烏豆眼睛生鐵面，直向孤峰頂上。',63,'全唐诗/poet.song.240000.json','["烏豆眼睛生鐵面，直向孤峰頂上。", "將無米飯塞斷天下衲子咽喉，固是家常，因甚更教人參箇一歸何處。", "吽，憶著江南三月天，馬塍西畔春無數。"]'),
('a9e2e58f-88e9-4434-abb9-74e0043de5a9','雙髻禪庵請','釋原妙','宋','宋诗','song-poetry','','[]','恣無明，逞人我。',43,'全唐诗/poet.song.240000.json','["恣無明，逞人我。", "誹釋迦，駡達磨。", "雖是赤心，返成話墮。", "六年坐鋪賣不行，至今被人喚作滯貨。"]'),
('dc3583f7-6615-4c90-9af3-a86c7d5b8f35','禪人請贊  其一','釋原妙','宋','宋诗','song-poetry','','[]','遮箇村僧，只好聞名。',20,'全唐诗/poet.song.240000.json','["遮箇村僧，只好聞名。", "尾巴纔露，天下人憎。"]'),
('72e78c19-8ef7-4bdf-b766-78580bee22b9','禪人請贊  其二','釋原妙','宋','宋诗','song-poetry','','[]','不識巖頭密啟處，剛言悟得仰山禪。',32,'全唐诗/poet.song.240000.json','["不識巖頭密啟處，剛言悟得仰山禪。", "遮場敗露難遮蓋，留與兒孫萬世傳。"]'),
('72b79157-0fd2-4d6e-9285-0fcb6283ad99','偈頌十二首  其一','釋原妙','宋','宋诗','song-poetry','','[]','欲明種子因，熟讀上大人。',24,'全唐诗/poet.song.240000.json','["欲明種子因，熟讀上大人。", "若到可知禮，盲龜跛鼈親。"]'),
('40510dee-526f-49de-a0d3-680e918f0ac5','偈頌十二首  其二','釋原妙','宋','宋诗','song-poetry','','[]','皮穿肉爛，筋斷骨折。',68,'全唐诗/poet.song.240000.json','["皮穿肉爛，筋斷骨折。", "具無礙辯，橫說豎說。", "若謂向上一關，敢保老兄未徹。", "直須虛空粉碎，大海枯竭。", "透頂透底，內外澄澈。", "正恁麽時，猶是眼中著屑。"]'),
('1483aef9-3a71-48cd-a33c-97f680711983','偈頌十二首  其三','釋原妙','宋','宋诗','song-poetry','','[]','此心清凈本無瑕，只爲貪求被物遮。',32,'全唐诗/poet.song.240000.json','["此心清凈本無瑕，只爲貪求被物遮。", "突出眼睛全體露，山河大地是空華。"]'),
('228aabeb-5c3e-4f2e-81f7-3ef6a3a6e7b4','偈頌十二首  其四','釋原妙','宋','宋诗','song-poetry','','[]','東西十萬，南北八千。',72,'全唐诗/poet.song.240000.json','["東西十萬，南北八千。", "纖塵不立，寸草不生。", "往來無礙，妙用縱橫。", "直饒親到者裏，正是棄本逐末，引禍招殃。", "且道如何是本，拋出輪王三寸鐵，分明遍界是刀鎗。"]'),
('0b5d058a-f455-4bd3-9ea7-2d8e3176f2d4','偈頌十二首  其五','釋原妙','宋','宋诗','song-poetry','','[]','五陰山中，魔强法弱。',50,'全唐诗/poet.song.240000.json','["五陰山中，魔强法弱。", "戰之不勝，休擬議著。", "寶劍全提，莫問生殺。", "奮不顧身，星飛火撒。", "有功者賞，無功者罰。"]'),
('bc857e84-77d5-44fa-ba00-c29f1e0a144b','偈頌十二首  其六','釋原妙','宋','宋诗','song-poetry','','[]','有時熱鬨鬨，有時冷冰冰。',28,'全唐诗/poet.song.240000.json','["有時熱鬨鬨，有時冷冰冰。", "有時如牽馿入井，有時如順水張帆。"]'),
('6f8a761a-f6a4-4458-bc60-8e5d4232bba5','偈頌十二首  其七','釋原妙','宋','宋诗','song-poetry','','[]','一二三四，四三二一。',64,'全唐诗/poet.song.240000.json','["一二三四，四三二一。", "鈎鎖連環，銀山鐵壁。", "覷得破，跳得出。", "大千沙界海中漚，一切聖賢如電拂。", "若是覷不破跳不出，切須翻天覆地離巢越窟。"]'),
('07c259ff-a8d4-4c06-9f14-f6b8c836b65f','偈頌十二首  其八','釋原妙','宋','宋诗','song-poetry','','[]','臘月三十日，時節看看至。',51,'全唐诗/poet.song.240000.json','["臘月三十日，時節看看至。", "露柱與燈籠，休更打瞌睡。", "覿面當機提，當機覿面覷。", "驀然觸瞎眼睛，照顧爛泥裏有刺。"]'),
('cb0a45b9-c765-422f-92b5-37a2279512aa','偈頌十二首  其九','釋原妙','宋','宋诗','song-poetry','','[]','封却拄杖頭，結却布袋口。',48,'全唐诗/poet.song.240000.json','["封却拄杖頭，結却布袋口。", "禁在鐵圍山，枷上重增杻。", "有中拷出無，無中拷出有。", "痛楚百千般，不離者窠臼。"]'),
('09a9cf3b-96dc-46da-88c7-06f924ce3d26','偈頌十二首  其一○','釋原妙','宋','宋诗','song-poetry','','[]','若論此事，正如傍牆逼狗。',33,'全唐诗/poet.song.240000.json','["若論此事，正如傍牆逼狗。", "逼來逼去，逼至尖角落頭，未免翻身遭他一口。"]'),
('9ce58cf7-3c2a-4faf-bb56-f0bd4ff3ae14','偈頌十二首  其一一','釋原妙','宋','宋诗','song-poetry','','[]','學道如初不變心，千魔萬難愈惺惺。',32,'全唐诗/poet.song.240000.json','["學道如初不變心，千魔萬難愈惺惺。", "直須敲出虛空髓，拔却金剛腦後釘。"]'),
('9c876353-b268-4abe-a3b2-d378ca0e1826','偈頌十二首  其一二','釋原妙','宋','宋诗','song-poetry','','[]','不得者箇，爭得那箇。',20,'全唐诗/poet.song.240000.json','["不得者箇，爭得那箇。", "既得那箇，忘却者箇。"]'),
('e1f1f95f-83aa-40c7-945f-6424341e089c','室中三關  其一','釋原妙','宋','宋诗','song-poetry','','[]','杲日當空，無所不照，因甚被片雲遮却。',18,'全唐诗/poet.song.240000.json','["杲日當空，無所不照，因甚被片雲遮却。"]'),
('fe99b860-de6e-46f5-86e1-5691b77cfb87','室中三關  其二','釋原妙','宋','宋诗','song-poetry','','[]','人人有箇影子，寸步不離，因甚踏不著。',18,'全唐诗/poet.song.240000.json','["人人有箇影子，寸步不離，因甚踏不著。"]'),
('65f44bb5-aadd-43b4-b2f2-210a1d51004b','室中三關  其三','釋原妙','宋','宋诗','song-poetry','','[]','盡大地是箇火坑，得何三昧，不被燒却。',18,'全唐诗/poet.song.240000.json','["盡大地是箇火坑，得何三昧，不被燒却。"]'),
('7e85ccd5-fb92-40a5-9aec-f99d03e66ee4','頌古五首  其一','釋原妙','宋','宋诗','song-poetry','','[]','涅槃地獄本無差，只爲從來被眼遮。',32,'全唐诗/poet.song.240000.json','["涅槃地獄本無差，只爲從來被眼遮。", "三脚瞎馿纔𨁝跳，鑊湯罏炭即吾家。"]'),
('feddab79-3659-4f28-a283-7148760ad877','頌古五首  其二','釋原妙','宋','宋诗','song-poetry','','[]','剖盡枯腸喪盡機，通身不掛一毫絲。',32,'全唐诗/poet.song.240000.json','["剖盡枯腸喪盡機，通身不掛一毫絲。", "清風步步隨身轉，明月誰分上下池。"]'),
('0b9e40be-41a0-43bc-94dd-16c1849caa31','頌古五首  其三','釋原妙','宋','宋诗','song-poetry','','[]','滴滴通身是爛膿，更無一點落西東。',32,'全唐诗/poet.song.240000.json','["滴滴通身是爛膿，更無一點落西東。", "若言不是知音者，未免風吹別調中。"]'),
('737870f6-557a-4e28-af1d-6ccaa79ebc29','頌古五首  其四','釋原妙','宋','宋诗','song-poetry','','[]','水出高原浪拍天，四維上下絕塵烟。',32,'全唐诗/poet.song.240000.json','["水出高原浪拍天，四維上下絕塵烟。", "分明好箇真消息，未必時人到那邊。"]'),
('136adf76-6c88-4229-afa7-1153ea0fbfac','頌古五首  其五','釋原妙','宋','宋诗','song-poetry','','[]','等閑放出這牛兒，頭角分明舉似誰。',32,'全唐诗/poet.song.240000.json','["等閑放出這牛兒，頭角分明舉似誰。", "若向尾巴尖上會，新羅鷂子過多時。"]'),
('88737540-688b-4ed7-98ff-928e25e91397','題鹿苑寺壁間記魯簡肅公羅漢見夢事','吳思齊','宋','宋诗','song-poetry','','[]','是法本平等，無怠亦無敬。',24,'全唐诗/poet.song.240000.json','["是法本平等，無怠亦無敬。", "如何證無生，却來見參政。"]'),
('88555edd-f41a-45f3-a01b-727f11a3f951','擬古','吳思齊','宋','宋诗','song-poetry','','[]','平原一遺老，九重未知名。',108,'全唐诗/poet.song.240000.json','["平原一遺老，九重未知名。", "臨危觀勁節，相視膽爲驚。", "折陊猶舉手，籲天閔無成。", "九隕期報國，萬古猶光晶。", "亦有布衣人，烈烈死彌貞。", "回風惜往日，輝映豈獨清。", "滔滔肉食輩，泚顙徒吞聲。", "我聞同志士，野祭激高情。", "配享遺斯人，憂心每如酲。"]'),
('beb079e6-bda4-4988-a50f-bbfa3bee18c1','次韻趙繡使題金鰲穩處','艾可叔','宋','宋诗','song-poetry','','[]','突兀霜崖俯雪洲，時時登覽喚漁舟。',64,'全唐诗/poet.song.240000.json','["突兀霜崖俯雪洲，時時登覽喚漁舟。", "溪分南北地初合，月在山間天共流。", "三兩可人曾此會，百千年後復誰遊。", "桑田不變金鰲健，祇恐吟翁白盡頭。"]'),
('c2a02160-9cf5-4567-a9d4-38b74758ff57','浮梁金鰲山','艾可叔','宋','宋诗','song-poetry','','[]','鰲骨分明露淺洲，登臨幾度泛虛舟。',64,'全唐诗/poet.song.240000.json','["鰲骨分明露淺洲，登臨幾度泛虛舟。", "人生天地蜉蝣寄，世事江河日夜流。", "前後朗吟坡老賦，逍遥終羨漆園遊。", "子真谷口今成趣，不爲紅塵枉白頭。"]'),
('8c37f701-22c5-482d-972e-1edce5ff0263','晚秋歸自京','艾可叔','宋','宋诗','song-poetry','','[]','紅塵兩脚幾時休，此度真成浪漫遊。',64,'全唐诗/poet.song.240000.json','["紅塵兩脚幾時休，此度真成浪漫遊。", "倦買夜船過釣瀨，渴呼臘盞試龍游。", "菊前疏雨重陽信，天際孤雲萬里愁。", "昨夜江頭鄉國夢，已隨明月度西樓。"]'),
('972b0d80-601f-4551-9c52-72a4e4e29814','樟鎮夜泊','艾可叔','宋','宋诗','song-poetry','','[]','醉却長年懶著篙，聊依山市泊江臯。',64,'全唐诗/poet.song.240000.json','["醉却長年懶著篙，聊依山市泊江臯。", "船收蒲席風初定，人卧蘆花月正高。", "時有沙禽驚客夢，厭聽櫪馬齕空槽。", "曉來細雨秋烟濕，意思三分是楚騷。"]'),
('1b63bc1a-734d-466b-bc5a-4782295e156a','臨江褒忠廟題','艾可叔','宋','宋诗','song-poetry','','[]','憶昔狼烽諜報忙，空拳支敵出倉惶。',64,'全唐诗/poet.song.240000.json','["憶昔狼烽諜報忙，空拳支敵出倉惶。", "齒寒誰解嬰城守，舌在公還駡賊亡。", "秦伯早能憐楚使，張君未必死睢陽。", "西風吹起英雄恨，斷礎凄烟淚兩行。"]'),
('cacc48ff-190b-4eed-ba76-6850278868e2','金陵晚眺','艾可叔','宋','宋诗','song-poetry','','[]','星移物換千年事，虎踞龍蟠萬雉城。',64,'全唐诗/poet.song.240000.json','["星移物換千年事，虎踞龍蟠萬雉城。", "歸巷烏衣秋縹緲，點州白鷺雪分明。", "江分南北天爲限，淮接東西地最平。", "目斷青峰是何處，單于吹角莫雲橫。"]'),
('7b0bdf3b-d9a9-404c-9a17-3f7ceb63a7ac','正月晦日西歸舟中作','艾可叔','宋','宋诗','song-poetry','','[]','宦情一片莫雲浮，歸興雙溪春水流。',64,'全唐诗/poet.song.240000.json','["宦情一片莫雲浮，歸興雙溪春水流。", "惜別長官携酒盞，送行詩友候津頭。", "人方挾彈窺黄雀，我不知機愧白鷗。", "數夕打篷風更雨，併無明月載空舟。"]'),
('83a07604-5326-49f0-ada7-26dcb3f7ac17','中秋風雨','艾可叔','宋','宋诗','song-poetry','','[]','一年佳節又虛逢，惱殺江湖白髮翁。',64,'全唐诗/poet.song.240000.json','["一年佳節又虛逢，惱殺江湖白髮翁。", "滴夢欲殘蕉葉雨，吹愁不斷蓼花風。", "陰晴明晦天無準，離合悲歡態不同。", "聊買香醪作清賞，燭光閒對木犀紅。"]'),
('c061bfdb-ba66-455b-8585-ac56954735e0','江南歸附後不仕述懷','艾可叔','宋','宋诗','song-poetry','','[]','舟在中流進退難，髮雖種種此心丹。',64,'全唐诗/poet.song.240000.json','["舟在中流進退難，髮雖種種此心丹。", "死爲元亮終書晉，生是留侯本事韓。", "貧賤不憂知有道，亂離最幸是無官。", "歲寒誰似東籬菊，禁得投簪日日看。"]'),
('3f532d97-abeb-47a6-a055-4aedfb6a3046','整裘袍','艾可叔','宋','宋诗','song-poetry','','[]','袍剪新藍襯淡黄，官宣粲粲照巾箱。',64,'全唐诗/poet.song.240000.json','["袍剪新藍襯淡黄，官宣粲粲照巾箱。", "倩人細熨波濤皺，爲我重縫雲霧香。", "入手雖輕榮賜重，此身差短感恩長。", "微忱稱報慚無路，空把山龍補舜裳。"]'),
('2d169367-413c-4082-a4b9-388cb70a328a','東上拜羅首墓','艾可叔','宋','宋诗','song-poetry','','[]','驛道百年墓，征衣四世孫。',48,'全唐诗/poet.song.240000.json','["驛道百年墓，征衣四世孫。", "衝風行木葉，藉雪拜松根。", "老覺貂裘敝，貧惟鐵硯存。", "倘徼先世福，猶足醉丘原。"]'),
('a79bf3a8-14c0-4034-9cbc-e0d53522248b','窮達','艾可叔','宋','宋诗','song-poetry','','[]','窮達寧無分，逢迎費折腰。',48,'全唐诗/poet.song.240000.json','["窮達寧無分，逢迎費折腰。", "人情剡溪紙，世事浙江潮。", "凍井和冰汲，寒山带雪樵。", "子雲雖寂寞，莊叟得逍遥。"]'),
('1b1ff35b-0974-4f9d-804b-f53ea411fc07','木棉','艾可叔','宋','宋诗','song-poetry','','[]','收來老繭倍三春，匹似真棉白一分。',64,'全唐诗/poet.song.240000.json','["收來老繭倍三春，匹似真棉白一分。", "車轉輕雷秋紡雪，弓彎半月夜彈雲。", "衣裘卒歲吟翁暖，機杼終年織婦勤。", "聞得上方存節儉，區區欲獻野人芹。"]'),
('58161f44-9427-4b2a-9fd1-17c7e0fb7b9f','渡鑑潭望鄭宜之白雪別墅','艾可叔','宋','宋诗','song-poetry','','[]','小驅滿砄是塵埃，逢好江山眼爲開。',64,'全唐诗/poet.song.240000.json','["小驅滿砄是塵埃，逢好江山眼爲開。", "賀老生涯鑑湖曲，希夷別墅白雲堆。", "欲尋溪叟挐舟去，却被山靈勒駕回。", "憶共吟邊曾有約，夜深應晤抱琴來。"]'),
('5d95b9a5-30c4-4891-95d8-ad6415e2ede5','山居雜興  其一','艾可翁','宋','宋诗','song-poetry','','[]','老夫晨沐罷，還卧看雲行。',48,'全唐诗/poet.song.240000.json','["老夫晨沐罷，還卧看雲行。", "髮短便巾小，衰容怯鏡明。", "空林存竹意，破屋带泉聲。", "自喜詩棋外，無營夢亦清。"]'),
('89bc8675-31eb-4565-9fd3-14ad5d07b09e','山居雜興  其二','艾可翁','宋','宋诗','song-poetry','','[]','青山意自足，擾擾復何之。',48,'全唐诗/poet.song.240000.json','["青山意自足，擾擾復何之。", "見客從衣破，哦詩任飯遲。", "蔬畦耕犢草，匏架落蟬枝。", "逆境偷貧樂，休兵未可期。"]'),
('2ca8d4cb-6dec-4c69-9eb0-ccbac538d507','山居雜興  其三','艾可翁','宋','宋诗','song-poetry','','[]','村落兵戈後，江湖几杖前。',48,'全唐诗/poet.song.240000.json','["村落兵戈後，江湖几杖前。", "索居兼屏燕，幽夢反宜蟬。", "茅舍分炊火，苔磚出釀泉。", "家貧思辟穀，非是博長年。"]'),
('50bbd500-1f46-4ba3-a261-fe6b1618c45c','家兄有和再用韵  其一','艾可翁','宋','宋诗','song-poetry','','[]','隔林看日落，出戶對天行。',48,'全唐诗/poet.song.240000.json','["隔林看日落，出戶對天行。", "久亂人情變，長貧心事明。", "虹拖城郭勢，河瀉甲兵聲。", "誰似秋來水，能於濁世清。"]'),
('458a8de3-cee7-4dda-9304-a2692bb56de5','家兄有和再用韵  其二','艾可翁','宋','宋诗','song-poetry','','[]','故人在何處，清夢或逢之。',48,'全唐诗/poet.song.240000.json','["故人在何處，清夢或逢之。", "老樹秋聲早，深窗曙色遲。", "濕螢粘露草，驚鳥徙風枝。", "琴破才支卧，知無鍾子期。"]'),
('222ed8d0-26f5-4148-b107-e9b4b5424ad2','家兄有和再用韵  其三','艾可翁','宋','宋诗','song-poetry','','[]','亂離生世晚，衰白在人前。',48,'全唐诗/poet.song.240000.json','["亂離生世晚，衰白在人前。", "雲水飛饑鶴，山林付亂蟬。", "日今行黑道，人有隔黄泉。", "晷漸秋來短，愁長亦敵年。"]'),
('a35069e7-5121-4f06-b3de-b1069360bb13','舟中','艾可翁','宋','宋诗','song-poetry','','[]','水月長依夢，江天半入詩。',48,'全唐诗/poet.song.240000.json','["水月長依夢，江天半入詩。", "斷崖雲欲落，危岸樹多欹。", "天曉雁先起，舟行客未知。", "雪霜篷隔斷，何得上吟髭。"]'),
('9db08c14-bc26-4432-9602-f76ee0e71e54','屢庸軍馬後相過','艾可翁','宋','宋诗','song-poetry','','[]','相疏憐各病，相見賀更生。',48,'全唐诗/poet.song.240000.json','["相疏憐各病，相見賀更生。", "久亂詩書廢，長貧門戶清。", "晨炊才脫粟，夜卧亦班荆。", "祇有悲秋卷，多於未受兵。"]'),
('a2723728-5f0e-438b-a016-98750d7bfb74','番陽道中','艾可翁','宋','宋诗','song-poetry','','[]','督府春移檄，江城晝撤花。',48,'全唐诗/poet.song.240000.json','["督府春移檄，江城晝撤花。", "好書如隔世，久客似無家。", "畏路多言虎，荒村半是鴉。", "道逢西北客，揮淚問京華。"]'),
('ad78ab14-5511-4a57-ab1e-19258c45bc92','兵火後野望  其一','艾可翁','宋','宋诗','song-poetry','','[]','干戈連萬國，丘壑卧三年。',48,'全唐诗/poet.song.240000.json','["干戈連萬國，丘壑卧三年。", "虎嘯黄茅地，鴉屯白骨田。", "渴虹疑竭海，腥霧欲沈天。", "摇落前朝老，長懷魯仲連。"]'),
('03958fb2-c683-4fda-94f7-e9d222f41f1b','兵火後野望  其二','艾可翁','宋','宋诗','song-poetry','','[]','江村兵火後，月色似長淮。',48,'全唐诗/poet.song.240000.json','["江村兵火後，月色似長淮。", "鼓角連秋思，風塵带客懷。", "諸公朝漠北，一老哭天涯。", "猶幸舂陵夜，葱葱氣尚佳。"]'),
('33ef76d1-4959-47e4-8efc-a29dbee68f0d','漢陽城','艾可翁','宋','宋诗','song-poetry','','[]','漢陽城上望，天色欲蒼黄。',48,'全唐诗/poet.song.240000.json','["漢陽城上望，天色欲蒼黄。", "雲去仍清野，人稀半戰場。", "江分青草斷，山接白雲長。", "一掬中原淚，凄凉對夕陽。"]'),
('f5eb9c1e-24a5-4c88-b162-2777d466a77d','釣臺  其一','艾可翁','宋','宋诗','song-poetry','','[]','歸去江頭伸脚眠，不煩太史驗星躔。',32,'全唐诗/poet.song.240000.json','["歸去江頭伸脚眠，不煩太史驗星躔。", "一絲千古經綸在，不爲東都二百年。"]'),
('05603114-ddbf-418a-89ac-c2397c339b8b','釣臺  其二','艾可翁','宋','宋诗','song-poetry','','[]','雲臺歷歷紀功臣，底事中間有子陵。',32,'全唐诗/poet.song.240000.json','["雲臺歷歷紀功臣，底事中間有子陵。", "未必故人同卧處，了無一語及中興。"]'),
('e4bcccd3-c764-4355-b687-20ce818a2efd','子規','艾可翁','宋','宋诗','song-poetry','','[]','舉目山河惱客懷，百年前事總塵埃。',32,'全唐诗/poet.song.240000.json','["舉目山河惱客懷，百年前事總塵埃。", "如何愛勸人歸去，倒引南人入汴來。"]'),
('da1b8ded-43d0-46ad-aaa0-f2f6d49156ba','傳聞','艾可翁','宋','宋诗','song-poetry','','[]','力戰奚憂曳落河，可憐重閫亦投戈。',32,'全唐诗/poet.song.240000.json','["力戰奚憂曳落河，可憐重閫亦投戈。", "後來未可輕東晉，雖是清談死節多。"]'),
('8294fd3a-0e9b-43da-a27a-de3029837809','題淵明像  其一','艾可翁','宋','宋诗','song-poetry','','[]','漉酒不孤頭上巾，醉來萬事等浮塵。',32,'全唐诗/poet.song.240000.json','["漉酒不孤頭上巾，醉來萬事等浮塵。", "誰家三徑無松竹，肯說昨非能幾人。"]'),
('96fedbe4-054b-430f-b93a-8ef4974eac4b','題淵明像  其二','艾可翁','宋','宋诗','song-poetry','','[]','仕晉何心更仕劉，知幾聞早去來休。',32,'全唐诗/poet.song.240000.json','["仕晉何心更仕劉，知幾聞早去來休。", "多君不肯腰輕折，非爲區區縣督郵。"]'),
('e84327ab-c3c3-451d-874d-633458448b46','書羅公碑陰','艾可翁','宋','宋诗','song-poetry','','[]','人家落落墮荒丘，碑带苔痕獨字留。',64,'全唐诗/poet.song.240000.json','["人家落落墮荒丘，碑带苔痕獨字留。", "博陸脊梁扶日月，中郎名筆法春秋。", "一抔誰下尋墳馬，片石今供礪角牛。", "惟有斜陽閑照管，肯隨鴉影上螭頭。"]'),
('e6f2cc1c-05c1-420f-8eda-86fca78d96b5','次韵臞山順處齋','艾可翁','宋','宋诗','song-poetry','','[]','喪亂踰三載，孤高配九秋。',48,'全唐诗/poet.song.240000.json','["喪亂踰三載，孤高配九秋。", "日方行北陸，江不改東流。", "詩入中年老，官逢世變休。", "仲將頭雪白，摇落更多愁。"]'),
('aef47af9-2b13-4ccb-9a87-996ecd64afdc','春夜','艾可翁','宋','宋诗','song-poetry','','[]','雨浥梨花粉淚香，一痕淡月照修廊。',32,'全唐诗/poet.song.240000.json','["雨浥梨花粉淚香，一痕淡月照修廊。", "春來只是尋常夜，惟有杜鵑添覺長。"]'),
('02f44a42-2fe8-45e8-b795-97eb1cc739b7','君馬黄','艾可翁','宋','宋诗','song-poetry','','[]','君馬黄，我馬驪。',64,'全唐诗/poet.song.240000.json','["君馬黄，我馬驪。", "白玉爲勒絡青絲，與君並轡河水湄。", "河上撲撲楊花飛，楊花飛飛送客人。", "生別離，良可惜。", "願君鞭影去遲遲，莫學楊花各南北。"]'),
('06c94065-142e-487a-a9e6-7ae69a09e468','元宵','艾可翁','宋','宋诗','song-poetry','','[]','偶然散策無尋訪，何限傷心强笑歌。',64,'全唐诗/poet.song.240000.json','["偶然散策無尋訪，何限傷心强笑歌。", "世味正如春酒淡，市燈不及月華多。", "人生只合且如此，國勢遂成無奈何。", "年少尚裝胡旋舞，不知舞破幾山河。"]'),
('514f281e-e505-494a-addc-f8ea702dc6d0','次韵徐君載見寄','艾可翁','宋','宋诗','song-poetry','','[]','不必相逢嘯語春，本然心跡自相親。',64,'全唐诗/poet.song.240000.json','["不必相逢嘯語春，本然心跡自相親。", "青山我已卧三載，白社君今與一人。", "亂後事非京國舊，雨餘秋共客愁新。", "躬耕谷口雲應滿，何處堪尋鄭子真。"]'),
('0426fa93-650d-444e-bc5a-1b343d3c0b2c','淡圃兄生辰有詩次韵  其一','艾可翁','宋','宋诗','song-poetry','','[]','來壽吾兄玉局仙，郎君亦自醉頹然。',64,'全唐诗/poet.song.240000.json','["來壽吾兄玉局仙，郎君亦自醉頹然。", "亂離難得團圞日，清健何須少壯年。", "投老宦情雲在壑，憂時心事日行天。", "遐齡此去應如鶴，蕙帳月寒相對眠。"]'),
('c154ce96-884c-429b-af4f-b38d1fc69341','淡圃兄生辰有詩次韵  其二','艾可翁','宋','宋诗','song-poetry','','[]','時危安樂是神仙，默有扶持豈偶然。',64,'全唐诗/poet.song.240000.json','["時危安樂是神仙，默有扶持豈偶然。", "林下且須堅晚節，尊前未用說明年。", "窮通莫計惟期壽，興廢難言頼有天。", "恨殺飄蓬白頭弟，十年風雨別州眠。"]'),
('a2e0d8f7-ad9d-4dfd-be53-a6b409e89519','金山寺前泛舟西下','艾可翁','宋','宋诗','song-poetry','','[]','機舂坎坎水潺潺，曲折舟行亂石間。',32,'全唐诗/poet.song.240000.json','["機舂坎坎水潺潺，曲折舟行亂石間。", "無數水禽飛不起，杜鵑花滿夕陽山。"]'),
('cb4f9651-ae44-4a1e-a481-fbc67ff6eae7','九日止諸少登高','艾可翁','宋','宋诗','song-poetry','','[]','塵埃漠漠一千里，風雨瀟瀟十四陵。',32,'全唐诗/poet.song.240000.json','["塵埃漠漠一千里，風雨瀟瀟十四陵。", "立得身高愁轉甚，龍山從此不須登。"]'),
('a5709677-46ab-4104-907f-72efe7206b12','空明洞','王玨','宋','宋诗','song-poetry','','[]','瑶草琪花半已空，洞門寂寂自春風。',32,'全唐诗/poet.song.240000.json','["瑶草琪花半已空，洞門寂寂自春風。", "千秋隻鶴無時返，安得蓬萊有路通。"]'),
('77c278a5-696c-4da2-a8f6-7abd850231dd','田母拒金圖','丁易東','宋','宋诗','song-poetry','','[]','噫噓嚱，人奔奔，皆爲名利之所役，賢反愚兮明反昏。',214,'全唐诗/poet.song.240000.json','["噫噓嚱，人奔奔，皆爲名利之所役，賢反愚兮明反昏。", "夜却金兮尚高潔，擇一錢兮義同頡。", "萊蕪甑中塵撲飛，懸魚老子肝似鐵。", "四公皦皦何不墨，圖中但見齊田稷。", "蠹吏虧綱勿足誇，特貌慈闈耀貞德。", "奉君本欲娛親喜，阿母怒兮驚且愧。", "若使當年一納間，那得芳名播青史。", "主聖親賢臣滌衷，公金賜嫗恩愛隆。", "非獨舍之罪不誅，昭昭淳化揚仁風。", "我披此傳重踟躕，豈獨田卿貪若斯。", "謂語今人知不知，偷安苟富誠何如。", "老萬翁，志不渝，費千金，畜此圖。", "此圖傳後世，後世重義輕金與。"]'),
('711f30ed-039d-4e22-8b3c-6708beaecc33','碧山  其一','姚雲','宋','宋诗','song-poetry','','[]','彭祖嶺頭春草生，逍遥洞口暮烟橫。',32,'全唐诗/poet.song.240000.json','["彭祖嶺頭春草生，逍遥洞口暮烟橫。", "分明半幅著色畫，何許黄鸝聞一聲。"]'),
('a9f0550c-04f3-4dba-ba56-8b8949b127e7','碧山  其二','姚雲','宋','宋诗','song-poetry','','[]','青蓮山下玉泉寒，蒼耳香中養白鷳。',32,'全唐诗/poet.song.240000.json','["青蓮山下玉泉寒，蒼耳香中養白鷳。", "浪說來仙天地外，桃花流水只人間。"]'),
('ef6dc815-64d2-46d3-9736-1695770e2918','九日','李希周','宋','宋诗','song-poetry','','[]','醺醺終日醉酕醄，一陣西風解濁醪。',32,'全唐诗/poet.song.240000.json','["醺醺終日醉酕醄，一陣西風解濁醪。", "歸去來辭吟未足，倚門還仰二山高。"]'),
('811cad23-e6a7-4d56-85f8-f245027b9e78','游虎丘','范宜','宋','宋诗','song-poetry','','[]','山奇水秀碧交加，倚遍闌干眼力賒。',64,'全唐诗/poet.song.240000.json','["山奇水秀碧交加，倚遍闌干眼力賒。", "閣跨劍池飛突兀，路盤石壁轉欹斜。", "日移高塔橋邊影，風送疏鐘嶺外家。", "傑出人間清勝地，老僧終日卧烟霞。"]'),
('2aa6bbcb-11dd-47d2-ba61-d8cdcdf413a4','慈相寺','鄧德秀','宋','宋诗','song-poetry','','[]','小橋橫過一溪長，因訪梅花到上方。',64,'全唐诗/poet.song.240000.json','["小橋橫過一溪長，因訪梅花到上方。", "山到盡時逢怪石，樓於高處带斜陽。", "殿經幾劫壁多壞，碑刻前賢詩數章。", "三百年前鐘尚在，可憐閲遍幾興亡。"]'),
('29118fcd-84f5-49d9-9ae5-546a4135ba58','句  其一','牟及','宋','宋诗','song-poetry','','[]','何日脊令還並影，舊時豚犬已成空。',16,'全唐诗/poet.song.240000.json','["何日脊令還並影，舊時豚犬已成空。"]'),
('5c6e263c-b239-47f6-b39a-6bb3dc7b050e','句  其二','牟及','宋','宋诗','song-poetry','','[]','困雨葵心終向日，隨風柳絮慢漫天。',16,'全唐诗/poet.song.240000.json','["困雨葵心終向日，隨風柳絮慢漫天。"]'),
('be3c954b-d6aa-4475-9c4a-b9ed2f9fa046','城山拜林艾軒','方公權','宋','宋诗','song-poetry','','[]','履齋早歲及朱門，末後通家得艾軒。',64,'全唐诗/poet.song.240000.json','["履齋早歲及朱門，末後通家得艾軒。", "德義遠從王父父，典刑愧忝外孫孫。", "世無前輩吾安仰，師有傳人道始尊。", "欲問先生游歷處，庭前老樹或能言。"]'),
('5f50537c-d764-4a43-b3ae-39d870cdc7f5','句','方公權','宋','宋诗','song-poetry','','[]','一身擔得烏山起，雙手拿將龍□歸。',16,'全唐诗/poet.song.240000.json','["一身擔得烏山起，雙手拿將龍□歸。"]'),
('cb784ad4-eab5-42fb-a6de-2ef938e6d158','姜林居別業','柴元彪','宋','宋诗','song-poetry','','[]','結廬塵外境，流水繞平田。',48,'全唐诗/poet.song.240000.json','["結廬塵外境，流水繞平田。", "三逕故人菊，一池君子蓮。", "塔懸當戶月，鐘翳隔溪烟。", "自得平生趣，漁竿老渭川。"]'),
('bfb1ad3d-9131-4987-8a90-b349e9d454ec','錢塘懷古','柴元彪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','百年朝市舊，登覽若爲情。',48,'全唐诗/poet.song.240000.json','["百年朝市舊，登覽若爲情。", "落日銅駝陌，東風夾馬營。", "路隨荆刺斷，城與黍離平。", "可惜西湖月，燒燈兩度晴。"]'),
('2709b449-cd4c-452a-86fa-4de9e7b55df8','丁丑偶成','柴元彪','宋','宋诗','song-poetry','','[]','燕山形勢地，從古是京師。',48,'全唐诗/poet.song.240000.json','["燕山形勢地，從古是京師。", "宇宙人俱換，山川影不移。", "馬諳朝北路，梅報向南枝。", "臘盡春來候，榮枯各有時。"]'),
('1c916d36-092a-4d2f-85b7-02b275522bbb','別江湖友人','柴元彪','宋','宋诗','song-poetry','','[]','相見還相別，相逢未有期。',48,'全唐诗/poet.song.240000.json','["相見還相別，相逢未有期。", "田園歸去日，風雨正來時。", "算驛客程遠，牽帆峽路危。", "寄書難到處，明月兩天涯。"]'),
('989b4e5f-83a8-427d-bb56-d2f703433147','僧房夜冷','柴元彪','宋','宋诗','song-poetry','','[]','山冷沒禁當，那堪更漏長。',48,'全唐诗/poet.song.240000.json','["山冷沒禁當，那堪更漏長。", "寒欺秋後扇，風試夜來霜。", "茭白心如墨，冬青子亦黄。", "袛宜煨芋栗，嚙引對緇郎。"]'),
('6defc976-d2ad-43be-9cad-74d247dd5722','游江郎山','柴元彪','宋','宋诗','song-poetry','','[]','世事無情幾變遷，郎峰萬古只依然。',64,'全唐诗/poet.song.240000.json','["世事無情幾變遷，郎峰萬古只依然。", "移來渤海三山石，界斷銀河一字天。", "雲捲前川龍挂雨，風生陰洞虎跑泉。", "羣仙縹緲來笙鶴，石頂天香墮玉蓮。"]'),
('e7f87718-9263-4acd-8f6c-984a1aedbd0a','及第留吳門訪史君黄松岡','柴元彪','宋','宋诗','song-poetry','','[]','西江草木轉精神，山谷松岡一樣清。',64,'全唐诗/poet.song.240000.json','["西江草木轉精神，山谷松岡一樣清。", "東海拾遺來汲黯，道州諫議得陽城。", "棠開春雨花千里，角動姑蘇月五更。", "笑指齊雲天已近，金鑾又聽玉珂聲。"]'),
('b5d14e88-2951-4fc0-8923-da516ee57e9f','登衡山宿上封寺祝融峰','柴元彪','宋','宋诗','song-poetry','','["\u8861\u5c71"]','歷井捫參上祝融，半空烟靄數聲鐘。',64,'全唐诗/poet.song.240000.json','["歷井捫參上祝融，半空烟靄數聲鐘。", "地連雲漢九千丈，天柱東南七十重。", "石磴懸崖翻瀑布，海門碾日上高峰。", "翛然身世青冥表，俯立雷池看玉龍。"]'),
('eb15935d-be37-41a5-b2c5-75bb5aa69f45','別茶陵士友','柴元彪','宋','宋诗','song-poetry','','[]','自來承檄到雲州，恰恰星霜又一周。',64,'全唐诗/poet.song.240000.json','["自來承檄到雲州，恰恰星霜又一周。", "握手心知千里月，滿懷詩思一江秋。", "每慙鑄錯傷完錦，多謝銜杯送別舟。", "未說河陽花滿縣，夜來風雨打田疇。"]'),
('239bd0ee-17e2-480a-97b7-1538541b7e33','勉制幹姪克家歸鄉','柴元彪','宋','宋诗','song-poetry','','[]','五年不得共團欒，放浪東吳一葦間。',64,'全唐诗/poet.song.240000.json','["五年不得共團欒，放浪東吳一葦間。", "客路風波如蹈海，人心劍戟甚於山。", "逢春回雁南應北，到海歸潮去復還。", "今是昨非渾一夢，庭柯園菊可怡顔。"]'),
('e4496c78-38ab-41c1-b43e-657f4b05989e','秋日江郎道中','柴元彪','宋','宋诗','song-poetry','','[]','豆花疏雨浥輕埃，野店新凉入酒杯。',64,'全唐诗/poet.song.240000.json','["豆花疏雨浥輕埃，野店新凉入酒杯。", "草带淡烟棲古道，樹含斷靄翳荒臺。", "湖光隠見萍分合，山色有無雲去來。", "滿眼秋光無盡意，三峰萬古碧崔嵬。"]'),
('c7dcad05-4a36-4fbc-93f0-541a256f3039','和同年徐清溪韻','柴元彪','宋','宋诗','song-poetry','','[]','深隠柯雲第幾峰，一庭春草綠叢叢。',64,'全唐诗/poet.song.240000.json','["深隠柯雲第幾峰，一庭春草綠叢叢。", "西風白髮催人老，少日青袍與子同。", "買犢只因耕犖确，拂龜何必問窮通。", "蔗漿一洗相如渴，頼有新詩送遠鴻。"]'),
('7f1edff8-b1b9-4d38-9ed3-cdcee9c5f993','寄括蒼李察院','柴元彪','宋','宋诗','song-poetry','','[]','武夷山下棹歸舠，九曲縈紆漲碧桃。',64,'全唐诗/poet.song.240000.json','["武夷山下棹歸舠，九曲縈紆漲碧桃。", "兩字功名如草芥，十年身世付蓬蒿。", "廣陵古調知音少，柯洞殘棋不著高。", "今日孤忠在何許，挑燈自讀楚人騷。"]'),
('f2b8f96c-8ac0-444a-920d-50db8a3505f2','和僧嘯雲雙插法藏寺韻','柴元彪','宋','宋诗','song-poetry','','[]','我來扣角二峰前，此寺因知五百年。',64,'全唐诗/poet.song.240000.json','["我來扣角二峰前，此寺因知五百年。", "草木尚涵唐雨露，鐘魚猶鎮宋山川。", "世情蒼狗浮雲外，客思孤鴻落日邊。", "閒拂舊題追往事，我鬚僧髮兩皤然。"]'),
('560d9cf0-eed8-46a4-aba4-3e1b18339e9b','和僧彰無文送蘭花韻','柴元彪','宋','宋诗','song-poetry','','[]','脫簪歸隠白雲深，不逐時芳事枉尋。',64,'全唐诗/poet.song.240000.json','["脫簪歸隠白雲深，不逐時芳事枉尋。", "閒向草亭圖太極，重盟蓮社續東林。", "春風分到靈均種，臭味如同惠遠心。", "一卷離騷清徹骨，跫然空谷足徽音。"]'),
('690c0081-3b59-4131-a385-090a3b125944','和克家姪謝周鳳隠雪中留宿韻','柴元彪','宋','宋诗','song-poetry','','[]','遥指龜峰擬問津，芒鞋踏碎玉嶙峋。',64,'全唐诗/poet.song.240000.json','["遥指龜峰擬問津，芒鞋踏碎玉嶙峋。", "去程暮雪留行客，回首春風有故人。", "三酌茅柴斟白墮，一爐榾柮當烏薪。", "饒他勢利相傾絕，管鮑交情正在貧。"]'),
('98b5c06e-5c14-4285-a0f9-25d78d829606','和姜元哲中秋有感韻','柴元彪','宋','宋诗','song-poetry','','[]','烏飛兔走兩悠悠，世事驚心易白頭。',64,'全唐诗/poet.song.240000.json','["烏飛兔走兩悠悠，世事驚心易白頭。", "月影空餘圓缺恨，人心不盡古今愁。", "江流東去波濤險，王氣南收草樹秋。", "回首夕陽亭上望，青山一髮渺神州。"]'),
('39a85205-b4a2-473a-8bbb-a28b98c8386f','游璩源寺和韻','柴元彪','宋','宋诗','song-poetry','','[]','游人剔蘚認堅珉，誰是開山第一人。',64,'全唐诗/poet.song.240000.json','["游人剔蘚認堅珉，誰是開山第一人。", "知有法諲留虎錫，元來璩叟是龍神。", "雲屏翠列懸崖樹，雪瀑聲飛斷壑津。", "又見生公重說法，祖師巖下草長春。"]'),
('099f9647-6bf0-47a5-95d9-7c9f151997e1','送剛中兄之官山陰','柴元彪','宋','宋诗','song-poetry','','[]','爲愛鵝池可禊蘭，朅來松下駐吟鞍。',64,'全唐诗/poet.song.240000.json','["爲愛鵝池可禊蘭，朅來松下駐吟鞍。", "一家昆弟皆臺憲，兩世翁孫此縣官。", "風渡潮聲來海口，雁將秋色下長安。", "白雲凝竚山陰近，笑策潘輿奉母歡。"]'),
('24ecf3f4-4eac-46a7-917d-1230cd69bf19','餞吉甫弟之維揚別駕','柴元彪','宋','宋诗','song-poetry','','[]','風檣留燕暮呢喃，行李催程春又三。',64,'全唐诗/poet.song.240000.json','["風檣留燕暮呢喃，行李催程春又三。", "幕府來迎晁別駕，油幢曾識李淮南。", "江都今古英雄會，宇宙中間化育參。", "見說監州簪芍藥，早乘華步趣朝驂。"]'),
('fc43f339-2b96-458b-b984-75ba45a27471','觀梅','柴元彪','宋','宋诗','song-poetry','','[]','冷蘂疏花带曉寒，騷翁白首淡相看。',32,'全唐诗/poet.song.240000.json','["冷蘂疏花带曉寒，騷翁白首淡相看。", "風饕雪虐天地閉，皦皦孤芳良獨難。"]'),
('e6ad1f14-e593-49d9-9d07-161d94cb1668','漚麻','柴元彪','宋','宋诗','song-poetry','','[]','金鞍玉勒綺羅茵，夢寐何緣到老身。',32,'全唐诗/poet.song.240000.json','["金鞍玉勒綺羅茵，夢寐何緣到老身。", "辛苦漚麻補衾鐵，誰知布縷又頻征。"]'),
('f21132c1-d717-46b6-9fbd-553a2a9c7012','灌花','柴元彪','宋','宋诗','song-poetry','','[]','小圃辛勤植衆芳，年年雨露借恩光。',32,'全唐诗/poet.song.240000.json','["小圃辛勤植衆芳，年年雨露借恩光。", "近來天意高難問，抱甕從朝到夕陽。"]'),
('858ff7c2-1d85-4a10-97bd-173dba341861','里社','柴元彪','宋','宋诗','song-poetry','','[]','滌竈炮牲獻腯肥，一巵滴酹紙錢飛。',32,'全唐诗/poet.song.240000.json','["滌竈炮牲獻腯肥，一巵滴酹紙錢飛。", "提壺挈饁分肴酒，村北村南祭社歸。"]'),
('0e7568eb-ab35-4c6c-aafb-e1b6e6fb6ce5','上中齋相公','柴元彪','宋','宋诗','song-poetry','','[]','年年長是客天涯，幾向天涯夢到家。',32,'全唐诗/poet.song.240000.json','["年年長是客天涯，幾向天涯夢到家。", "歸到故家無一字，兔葵鶑粟正開花。"]'),
('c0747caa-267b-4328-abbc-fece3af9e99f','和周鳳隠止酒韻','柴元彪','宋','宋诗','song-poetry','','[]','邃古奠堪輿，狉狉羣鹿豕。',240,'全唐诗/poet.song.240000.json','["邃古奠堪輿，狉狉羣鹿豕。", "由蒙以至需，生人飲食始。", "世值勳華初，人文日以起。", "民用非酒醴，無以供祭祀。", "遡求飲之源，日星著經史。", "禮樂所以興，寓意乎樽簋。", "不講鄉飲儀，孰序燕毛齒。", "不歌既醉篇，孰頌太平美。", "時哉世味醇，泰和其在是。", "人情縱則流，此弊何涯涘。", "魯薄攻邯鄲，商湎禍妲己。", "歌沈玉樹荒，舞罷花鈿委。", "鴆毒死宴安，惜不慎坤履。", "繁華有憔悴，高臺倏荆杞。", "恭惟崇伯子，垂訓在惡旨。", "戒荒明聖事，榷酤非所弛。", "再挽澆漓俗，追軼鴻濛軌。", "宴樂止汙杯，熙熙大庭氏。", "展也漉酒人，賦詩聊自止。", "千古獨醒魂，撫掌汨羅水。"]'),
('21373273-7548-4c6e-b8da-d058eec40a7c','紙帳吟','柴元彪','宋','宋诗','song-poetry','','[]','有斐楮先生，覆冒逈襟度。',120,'全唐诗/poet.song.240000.json','["有斐楮先生，覆冒逈襟度。", "澡身清泚泉，被世軼於布。", "置之山齋中，朔風歲云暮。", "無分媚其奢，可寶色惟素。", "愧彼錦步障，榮華塵一聚。", "永此雪霜潔，不識羔羊汙。", "影橫月窗梅，香透地爐芋。", "道人何太寂，新故謾納吐。", "勿爲袁卧高，勿爲莊夢栩。", "願均燠寒心，以散隆寒沍。"]'),
('27840c7a-bf0a-4a8f-a23a-aeecdda686f8','同朱山長游江郎','柴元彪','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','屭贔開天風，三峰互參峙。',276,'全唐诗/poet.song.240000.json','["屭贔開天風，三峰互參峙。", "一如植躬圭，兩峰拱而侍。", "削玉石爲筆，書空雲作紙。", "嵐光動九天，翠色照千里。", "上有碧玉蓮，中有黄金鯉。", "壁界一字天，松老千年乳。", "鷹旋磨雲根，虎跑流石髓。", "禪師久入定，色相如不死。", "靈石剖鴻荒，開山自晉始。", "威顯三直神，肸蠁百世祀。", "劫風俄扇揚，梵宇忽頹圮。", "僧來自懷玉，被荆營故址。", "笙鶴宴羣仙，鐘魚飯德士。", "佳客賁而思，空谷跫然喜。", "一筇事幽討，萬象歸俯視。", "山茗澹以清，村醪薄而旨。", "對弈覆危枰，投壺響飛矢。", "盤桓蒼翠間，酬酢笑談裏。", "欹枕自逍遥，憑闌時徙倚。", "泉琴浣我心，松箏清我耳。", "廬山樂天翁，敬亭謫仙子。", "今昔雖殊時，其樂亦如此。", "留爲他日觀，歲月端可紀。"]'),
('463e3f5e-65b2-476f-8dd2-a91ffeec0f0e','人心吟','柴元彪','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江萬頃深，風靜波自止。',48,'全唐诗/poet.song.240000.json','["長江萬頃深，風靜波自止。", "人心僅一寸，日夜風波起。", "桑田倏滄海，汩沒勢未已。", "安得今人心，常如古井水。"]'),
('9488735c-f4e3-492e-8893-ed3485db1a0f','老農吟','柴元彪','宋','宋诗','song-poetry','','[]','襏襫田家翁，矍鑠鬚眉白。',220,'全唐诗/poet.song.240000.json','["襏襫田家翁，矍鑠鬚眉白。", "問渠年幾許，不記年庚甲。", "自言身世居此村，三十得兒兒復孫。", "傷哉兒孫已露電，朝昏隻影空斷魂。", "生來只是種田土，田土祇今易幾主。", "鄉村成敗歷能言，英雄磨滅不知數。", "盡日壟畝力耕耘，餉饁炊舂倩比鄰。", "歸來薄暮飯牛罷，索綯織屨宵猶勤。", "吁嗟兮，既絕望乎鳩杖與糜粥，曾不見富人之哀我煢獨。", "但願年豐醉雞豚，重見太平死亦足。", "縱如顔都尉、馬伏波，老來恩寵成蹉跎。", "蟻穴一夢今如何，貧富夭壽總如此。", "我莫愁，君莫喜，好將榮辱哀樂、是非得失付與東流水。"]'),
('09118b09-d978-45c9-bada-6ce22549757c','寶鏡吟','柴元彪','宋','宋诗','song-poetry','','[]','荆山已童若耶涸，若耶可採山可鑿。',192,'全唐诗/poet.song.240000.json','["荆山已童若耶涸，若耶可採山可鑿。", "金精少皡不敢秘，鑑坏飛就歐冶錯。", "祝融煽焰千丈芒，玄冥洗光萬里爍。", "冷侵鸞鏡影自舞，泓澈鬼神膽欲落。", "圓象曜靈絳氣浮，玉臺懸處風颼颼。", "山人一玩一心駭，毛骨竦豎難竚留。", "直徵千金就我賣，拂拭高堂向人挂。", "我行鏡中人亦行，我拜鏡中人亦拜。", "向前試問鏡中人，一我何緣有兩身。", "知是傍人知是我，一笑問君誰假真。", "人在鏡中亦一笑，惟我與君同一照。", "照人照我休照形，照出人心方是明。"]'),
('9d1d5a27-b358-438b-871c-b6a8851f56c5','擊壤歌','柴元彪','宋','宋诗','song-poetry','','[]','擊壤歌，擊壤歌，仰觀俯察如吾何。',401,'全唐诗/poet.song.240000.json','["擊壤歌，擊壤歌，仰觀俯察如吾何。", "西海摩月鏡，東海弄日珠。", "一聲長嘯天地老，請君聽我歌何如。", "君不見丹溪牧羊兒，服苓餐松入金華。", "又不見武陵捕魚者，艤舟綠岸訪桃花。", "高人一去世運傾，或者附勢類饑鷹。", "况是東方天未白，非雞之鳴蒼蠅聲。", "朝集金張暮許史，蠛蠓鏡裏寄死生。", "犀渠象弧諧時好，干將鏌鋣埋豐城。", "失固不足悲，得亦不足驚。", "秋花落後春花發，世間何物無枯榮。", "十年漂泊到如今，一窮殆盡猿投林。", "平生舒卷雲無心，儀舌縱存甘喑喑。", "噫吁嘻！豪豬靴，青兕裘，一談笑頃即封侯。", "後魚纔得泣前魚，予之非恩奪非讎。", "眼前富貴須年少，吾將老矣行且休。", "休休休，俯視八尺軀，滄海渺一粟。", "憶昔垂九齡，牽衣覓李栗。", "回頭華髮何蕭蕭，百年光陰如轉燭。", "乃歌曰：不編茅兮住白雲，不脫蓑兮卧黄犢。", "仰天拊缶兮呼烏烏，手持鴟夷兮薦醽醁。", "乃賡載歌曰：招夷齊兮採薇，拉園綺兮茹芝。", "折簡子陵兮羊裘披，移文靈均兮佩瓊枝。", "敢問諸君若處廟廊時，食前方丈、侍妾數百得志爲之而弗爲。"]'),
('c301df73-5468-4cab-abfa-bed485abe167','送姪一齋游武林','柴元彪','宋','宋诗','song-poetry','','["\u897f\u6e56"]','舸鷁退飛杭不魚，滄海翻覆桑田墟。',250,'全唐诗/poet.song.240000.json','["舸鷁退飛杭不魚，滄海翻覆桑田墟。", "長安草木成焦枯，黯黯落日栖平蕪。", "凄凉往事增欷歔，子長一部太史書。", "寄在名山大澤區，之子安肯侶樵漁。", "有琴一張酒一壺，胸中雲夢八九潴。", "齧雪奔電千里途，大鵬擊水九萬圖。", "十年騎鶴來上都，宮鶑陌燕相喧呼。", "回首一夢今何如，太行羊腸九折迂。", "出門欲往如攣拘，顧予老矣僕馬痡。", "甘心首陽採薇夫，之子春風曳長裾。", "西湖爲我問訊學士蘇，孤山爲我起居處士逋。", "二仙笑我猶故吾，楊柳黯淡梅花癯。", "之子此行出有車，抱材珍重如璠璵。", "青萍出匣蛟可屠，白髮倚門望不孤。", "不妨早賦歸來乎，歸來兮，老萊斑衣膝下相歡娛。"]'),
('b275c7e6-abde-461e-885d-7c92fe763d8c','別虞君集','王鎡','宋','宋诗','song-poetry','','[]','瓦瓶擔酒去，送客石橋東。',48,'全唐诗/poet.song.240000.json','["瓦瓶擔酒去，送客石橋東。", "潮過汀沙上，船迴島樹中。", "桃花三月雨，楊柳五更風。", "明日思君處，渡頭烟水空。"]'),
('0760ab2a-2fa9-4dde-9847-a13ad3fe1720','送默然上人歸天台','王鎡','宋','宋诗','song-poetry','','[]','孤雲不定心，持缽度寒林。',48,'全唐诗/poet.song.240000.json','["孤雲不定心，持缽度寒林。", "野飯青蒲潔，秋程黄葉深。", "海風潮水發，山雨曉烟沉。", "歸到石橋日，應看瀑布吟。"]'),
('559e78ae-c2d4-43bb-bfd1-e9add8c04a40','錢塘江','王鎡','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','凉絲疏柳條，秋滿石闌橋。',48,'全唐诗/poet.song.240000.json','["凉絲疏柳條，秋滿石闌橋。", "吳越興亡事，晨昏來去潮。", "雲開天日近，水接海山遥。", "望到西陵渡，風帆影自飄。"]'),
('148ac550-d6d1-4c21-acfe-3246363d3898','別黄吟隠','王鎡','宋','宋诗','song-poetry','','[]','飲乾分別酒，話久未移舟。',48,'全唐诗/poet.song.240000.json','["飲乾分別酒，話久未移舟。", "潮水催行客，海山生遠愁。", "蟬聲秋岸樹，雁影夕陽樓。", "今夜相思夢，蘆花第幾洲。"]'),
('896fa0bd-8321-40b7-95ea-0e6c23c1ceaf','塞上曲','王鎡','宋','宋诗','song-poetry','','["\u8fb9\u585e"]','黄雲連白草，萬里有無間。',48,'全唐诗/poet.song.240000.json','["黄雲連白草，萬里有無間。", "霜冷髑髏哭，天寒甲胄閑。", "馬嘶經戰地，鵰認打圍山。", "移戍腰金印，將軍度玉關。"]'),
('2c1a8f5d-40c6-4b83-93ec-576f7590dce8','買舟','王鎡','宋','宋诗','song-poetry','','[]','赤闌橋上路，幾度卜歸期。',48,'全唐诗/poet.song.240000.json','["赤闌橋上路，幾度卜歸期。", "流水無休日，行人有老時。", "潮來江勢逆，月出海門遲。", "風順輕舟快，蒲帆盡夜吹。"]'),
('28baab79-4afb-498f-8bc4-8e91e9da86ce','赤城李丹士','王鎡','宋','宋诗','song-poetry','','[]','頻年游嶽洞，靈跡記無差。',48,'全唐诗/poet.song.240000.json','["頻年游嶽洞，靈跡記無差。", "學得長生術，常留鍛死砂。", "笛吹蒼島月，鞋踏赤城霞。", "又欲騰空去，尋仙到九華。"]'),
('9019e9de-081e-42cd-9921-4ae38073b861','早行','王鎡','宋','宋诗','song-poetry','','[]','客程因太早，却費一更眠。',48,'全唐诗/poet.song.240000.json','["客程因太早，却費一更眠。", "落月已歸海，殘星猶在天。", "櫓聲荷葉浦，螢火豆花田。", "隔岸誰家起，青燈遠樹邊。"]'),
('284dd951-3426-4481-92b3-a9f456ee4e40','秋深','王鎡','宋','宋诗','song-poetry','','[]','風露損衣裾，秋深懷故廬。',48,'全唐诗/poet.song.240000.json','["風露損衣裾，秋深懷故廬。", "僕方談夜夢，客至得家書。", "子黑石蓮老，柿紅霜葉疏。", "今年籬下菊，遥憶少人鋤。"]'),
('78efdcd9-d8b0-4304-865c-af32cdce7891','訪翟梅山','王鎡','宋','宋诗','song-poetry','','[]','諸老彫零盡，江湖今有誰。',48,'全唐诗/poet.song.240000.json','["諸老彫零盡，江湖今有誰。", "半生行客慣，多難識君遲。", "花屋春風酒，梅山雪夜詩。", "莫爲名釣出，世事正如棋。"]'),
('635ae1eb-c9ca-49a8-bad9-ecaf8025c3fd','感秋寄白雲趙寺丞','王鎡','宋','宋诗','song-poetry','','[]','囊裏不藏金，相隨只破琴。',48,'全唐诗/poet.song.240000.json','["囊裏不藏金，相隨只破琴。", "每因看月夜，長動故人心。", "腥草關河路，秋風楚越砧。", "愁來不成睡，破壁更蛩吟。"]'),
('8f5c3d21-df66-4404-9ac8-dbfb8b94f2a5','晚春即事','王鎡','宋','宋诗','song-poetry','','[]','雲氣不分明，天陰忽又晴。',48,'全唐诗/poet.song.240000.json','["雲氣不分明，天陰忽又晴。", "喜凉溪鵲浴，知雨沼蛙鳴。", "仙藥黄精飯，齋蔬白蕈羹。", "惜春吟未就，閑踏落花行。"]'),
('508bee38-23b0-404e-9d2d-6fdfe60c4f7f','溪村','王鎡','宋','宋诗','song-poetry','','[]','水路隨山轉，溪晴踏軟沙。',48,'全唐诗/poet.song.240000.json','["水路隨山轉，溪晴踏軟沙。", "斜陽曬魚網，疏竹露人家。", "行蟹上枯岸，饑禽銜落花。", "老翁分石坐，閑話到桑麻。"]'),
('2074b456-b06c-4708-8a9f-31e9dae68b34','寄友','王鎡','宋','宋诗','song-poetry','','[]','髮影明寒鏡，蕭蕭亦自憐。',48,'全唐诗/poet.song.240000.json','["髮影明寒鏡，蕭蕭亦自憐。", "故人難會面，行客又經年。", "晴雪添崖瀑，春雲雜曉烟。", "相思有書札，寫盡夜燈前。"]'),
('169d142f-dcc9-46b5-bca6-5407bab0ecdd','山中','王鎡','宋','宋诗','song-poetry','','[]','榮枯皆定數，枉作送窮吟。',48,'全唐诗/poet.song.240000.json','["榮枯皆定數，枉作送窮吟。", "有色非真畫，無腔是古琴。", "青松秦世事，黄菊晉人心。", "塵外烟蘿客，相尋入遠林。"]'),
('c2c7bc56-4dfc-4659-bd95-e27c5d1ff543','避亂柯巖綠坡諸公以詩見寄','王鎡','宋','宋诗','song-poetry','','[]','柯栝各西東，音書久不通。',48,'全唐诗/poet.song.240000.json','["柯栝各西東，音書久不通。", "山河隔今古，天地老英雄。", "局敗棋難著，愁多酒易中。", "花前多少恨，無語寄春風。"]'),
('e9c2feed-c838-453f-8be1-7d9be2835919','寄杜北山','王鎡','宋','宋诗','song-poetry','','[]','倦客蕭蕭兩鬢秋，柳絲無力絆歸舟。',64,'全唐诗/poet.song.240000.json','["倦客蕭蕭兩鬢秋，柳絲無力絆歸舟。", "曉風落葉辭高樹，夜月行人在別洲。", "千里關河鄉國夢，一江烟浪古今愁。", "雁聲過盡青天闊，却憶同登望海樓。"]'),
('434f4319-19c6-41f5-9b4b-bfce73657d9d','山居','王鎡','宋','宋诗','song-poetry','','[]','屋頭蘚樹蛻鳴蛩，池上溝泉鑿石通。',64,'全唐诗/poet.song.240000.json','["屋頭蘚樹蛻鳴蛩，池上溝泉鑿石通。", "香老蒲花春洞影，凉生槲葉午窗風。", "泥瓶開酒留樵客，篛笠穿雲訪藥翁。", "雖是一貧清似水，定無徭役到山中。"]'),
('e2bb58fe-737a-4c79-9899-ace1eba62c48','暮秋寄仙洲舍弟','王鎡','宋','宋诗','song-poetry','','[]','去年泛菊醉重陽，今日誰知各異鄉。',64,'全唐诗/poet.song.240000.json','["去年泛菊醉重陽，今日誰知各異鄉。", "落葉石闌霜信早，敗荷池屋雨聲凉。", "人情好惡花甘苦，世事榮枯草短長。", "別有駿鵰雙翮健，剛風摩透入蒼茫。"]'),
('d000b498-6ced-4c05-ad83-2bb1d0f03a28','金陵感秋','王鎡','宋','宋诗','song-poetry','','[]','魚書難寄水空流，兩袖西風破黑裘。',64,'全唐诗/poet.song.240000.json','["魚書難寄水空流，兩袖西風破黑裘。", "客夢蘆花晉城月，歸心楓葉浙山秋。", "世情老去諳方熟，愁事來時醉便休。", "滿目關河懷古恨，如今何處問孫劉。"]'),
('46d2bdb7-9717-40cc-8a74-8fcff89f99d1','春遊','王鎡','宋','宋诗','song-poetry','','[]','薄暖輕寒未肯分，遊衫換作粉紅新。',64,'全唐诗/poet.song.240000.json','["薄暖輕寒未肯分，遊衫換作粉紅新。", "綠香酒影摇宮扇，紅皺裙文上舞裀。", "楊柳錦鞍春富貴，海棠銀燭夜精神。", "風流難學唐崔護，花下題詩憶故人。"]'),
('e678e0dd-364a-4ec2-acb8-74a8e2392ce3','宿香嚴院','王鎡','宋','宋诗','song-poetry','','[]','地爐煨火柏枝香，借宿寒寮到上方。',64,'全唐诗/poet.song.240000.json','["地爐煨火柏枝香，借宿寒寮到上方。", "山近白雲歸古殿，風高黄葉響空廊。", "敲門僧踏梅花月，入夜猿啼楓樹霜。", "夢醒不知窗日上，時聞經磬出松堂。"]'),
('4444673d-966b-4b7d-8e03-9dd6ee91cff5','湖山即景次尹綠波','王鎡','宋','宋诗','song-poetry','','[]','湖山掩映雁潭秋，今古詩人說勝遊。',64,'全唐诗/poet.song.240000.json','["湖山掩映雁潭秋，今古詩人說勝遊。", "綠柳影分騎馬路，赤楓葉落釣魚舟。", "前坡風送歸樵笛，別墅雲藏賣酒樓。", "長記尋梅冰雪裏，氈靴駝帽鷫鸘裘。"]'),
('f3c855c5-a4b6-4388-9df4-f488a246ac0d','古杭感事  其一','王鎡','宋','宋诗','song-poetry','','[]','國事彫零王氣衰，東南豪傑竟何之。',64,'全唐诗/poet.song.240000.json','["國事彫零王氣衰，東南豪傑竟何之。", "雲寒廢殿排班石，草卧前朝記事碑。", "沙漲浙江龍去遠，天寬北闕鳳歸遲。", "可憐不老吳山月，曾照官家寵幸時。"]'),
('f8ff4d8f-5a14-44fb-a9c6-22fc8cda1815','古杭感事  其二','王鎡','宋','宋诗','song-poetry','','[]','入北鑾輿竟不回，銜花輦路長蒼苔。',64,'全唐诗/poet.song.240000.json','["入北鑾輿竟不回，銜花輦路長蒼苔。", "九重禁地爲僧舍，六代園陵變劫灰。", "宋國衣冠春草綠，趙宮珠翠野花開。", "雖然興廢俱天數，禍自奸臣誤國來。"]'),
('ec2ac3fb-3d98-4f9f-bfbe-37bb61038be8','尹綠坡閒吟所','王鎡','宋','宋诗','song-poetry','','[]','苔痕分路見人家，犬護籬根卧落花。',64,'全唐诗/poet.song.240000.json','["苔痕分路見人家，犬護籬根卧落花。", "一片林塘詩境界，四時花果隠生涯。", "鋤山揀日春栽藥，汲水和雲夜煮茶。", "耕錄有文須點看，旋摇松露入硃砂。"]'),
('45e1a2ac-4cac-4558-9186-d2adc8302200','登開元宮德和樓','王鎡','宋','宋诗','song-poetry','','[]','瑞雲深處碧玲瓏，得道高人在此中。',64,'全唐诗/poet.song.240000.json','["瑞雲深處碧玲瓏，得道高人在此中。", "玉樹影迷唐舊邸，金鐘聲繞漢諸宮。", "夜看西北天星近，曉對東南海日紅。", "咫尺便分仙俗路，吳山斜出錦屏風。"]'),
('6c6ffd25-0045-4c77-847d-0f7331fa0bef','寓龍虎山示張鍊師','王鎡','宋','宋诗','song-poetry','','[]','蓮盂送別萬峰雲，龍虎山前過小春。',64,'全唐诗/poet.song.240000.json','["蓮盂送別萬峰雲，龍虎山前過小春。", "草履慣穿枯嶺葉，布衣猶带舊京塵。", "氈寒不見游仙夢，路遠誰憐倦客貧。", "東望海門歸未得，北風吹雪滿唐巾。"]'),
('76dafd6f-e550-4a18-ae40-1b5d57a19176','山中述懷柬詳議梅磵四弟','王鎡','宋','宋诗','song-poetry','','[]','春入青山伴白雲，市朝新事不曾聞。',64,'全唐诗/poet.song.240000.json','["春入青山伴白雲，市朝新事不曾聞。", "心無利慾愁都散，路有仙凡悟便分。", "夜月蕉花秦世夢，寒烟草子宋時墳。", "抽丁不到空林客，自採楓香禮斗君。"]'),
('f3a357d4-92fe-4a8d-9654-ecd91b478547','時事','王鎡','宋','宋诗','song-poetry','','[]','羽書飛報南州捷，百萬戎師盡轉官。',64,'全唐诗/poet.song.240000.json','["羽書飛報南州捷，百萬戎師盡轉官。", "豪傑危中成事易，規模狹處濟時難。", "雲生殺氣鵰旗暗，風肅軍聲虎帳寒。", "何日山河□□□，□□□□舊衣冠。"]'),
('dfac2ca7-bd78-4375-8c4a-e2889349f25a','病中','王鎡','宋','宋诗','song-poetry','','[]','鏡裏初疑看不真，衰顔只恐是他人。',64,'全唐诗/poet.song.240000.json','["鏡裏初疑看不真，衰顔只恐是他人。", "醫言斷酒方除病，母戒觀書亦損神。", "卧久不知黄葉落，起來還見白髭新。", "橫梳頭髮斜陽下，半脫清風半委塵。"]'),
('1c14d662-d9e4-4be0-806c-27e4b770a6f6','裁衣曲','王鎡','宋','宋诗','song-poetry','','[]','燒罷心香午夜闌，玉纖輕捻剪刀寒。',32,'全唐诗/poet.song.240000.json','["燒罷心香午夜闌，玉纖輕捻剪刀寒。", "衣成恐不如郎意，獨著燈前照影看。"]'),
('83a991df-6b5a-47a3-97ea-eed8485dbdf0','春酌','王鎡','宋','宋诗','song-poetry','','[]','酒闌歌罷翠簾遮，午夜烏啼月未斜。',32,'全唐诗/poet.song.240000.json','["酒闌歌罷翠簾遮，午夜烏啼月未斜。", "多少斷雲心上事，結成香夢是梨花。"]'),
('bbd9be0e-f284-456f-a43b-843736918c5d','西湖','王鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','南北高峰叫杜鵑，斜陽浮翠斷橋邊。',32,'全唐诗/poet.song.240000.json','["南北高峰叫杜鵑，斜陽浮翠斷橋邊。", "畫船歸處江湖夢，一半樓臺楊柳烟。"]'),
('4a7bb04a-1981-4826-98ea-6a687b69af95','蘇小小墓','王鎡','宋','宋诗','song-poetry','','[]','同心難結繡雲長，紅玉沉泥草亦香。',32,'全唐诗/poet.song.240000.json','["同心難結繡雲長，紅玉沉泥草亦香。", "嬌魄年年寒食節，定應湖上作鴛鴦。"]'),
('d7ca15d1-cbb7-4855-bb59-3240549405f0','怯暖','王鎡','宋','宋诗','song-poetry','','[]','怯暖新裁白苧衣，棋聲深院客來稀。',32,'全唐诗/poet.song.240000.json','["怯暖新裁白苧衣，棋聲深院客來稀。", "春風無力晴絲軟，絆住楊花不肯飛。"]'),
('43c0f53e-2167-468d-806f-b7742954e0f4','秦望山','王鎡','宋','宋诗','song-poetry','','[]','祖龍癡欲望長年，却遣君房渡海船。',32,'全唐诗/poet.song.240000.json','["祖龍癡欲望長年，却遣君房渡海船。", "枉去蓬山覓丹藥，桃源亦自有神仙。"]'),
('46e4c445-b887-4f77-8686-773ba41f7adf','深春  其一','王鎡','宋','宋诗','song-poetry','','[]','夾泥花上燕巢邊，翠箔桑空蠶又眠。',32,'全唐诗/poet.song.240000.json','["夾泥花上燕巢邊，翠箔桑空蠶又眠。", "天氣纔晴風候別，坐看盆藕出雙錢。"]'),
('feb8fad8-f364-4802-bfd1-c4bc1c52d566','深春  其二','王鎡','宋','宋诗','song-poetry','','[]','燕子來時春又休，暖風吹綠上枝頭。',32,'全唐诗/poet.song.240000.json','["燕子來時春又休，暖風吹綠上枝頭。", "繡簾不隔荼䕷月，香影無人自入樓。"]'),
('46f62427-8624-45a1-8ff1-2caebe2af356','采蓮曲','王鎡','宋','宋诗','song-poetry','','[]','羅裙濺濕鬢雲偏，摇落香風滿畫船。',32,'全唐诗/poet.song.240000.json','["羅裙濺濕鬢雲偏，摇落香風滿畫船。", "忽憶夜來憔悴夢，鴛鴦正在藕花邊。"]'),
('8f3d7436-cbfc-439f-a11f-f57e2375d9c9','秋宮辭','王鎡','宋','宋诗','song-poetry','','[]','蟬噪凉生玉漏秋，夢回空憶到龍樓。',32,'全唐诗/poet.song.240000.json','["蟬噪凉生玉漏秋，夢回空憶到龍樓。", "妾身恨不如黄葉，得趁流泉出御溝。"]'),
('16a0314b-bebc-440b-83c1-701ef0f9ecaa','春閨辭','王鎡','宋','宋诗','song-poetry','','[]','桃飛紅雪上簾鈎，楊柳風絲拂畫樓。',32,'全唐诗/poet.song.240000.json','["桃飛紅雪上簾鈎，楊柳風絲拂畫樓。", "日透闌干人病酒，賣花聲過懶搔頭。"]'),
('93c6b5d0-f7c5-4db1-a459-4fb4c48783f7','訪庭植上人','王鎡','宋','宋诗','song-poetry','','[]','苔侵坐處石頭青，滿屋春雲不用扃。',32,'全唐诗/poet.song.240000.json','["苔侵坐處石頭青，滿屋春雲不用扃。", "入定醒來香印冷，一簾花雨濕殘經。"]'),
('62d4d956-19c7-4b60-95ee-7e09dc9d4b22','西亭新暑','王鎡','宋','宋诗','song-poetry','','[]','水晶簾掛小池亭，茉莉花香酒易醒。',32,'全唐诗/poet.song.240000.json','["水晶簾掛小池亭，茉莉花香酒易醒。", "日影不摇風力軟，蟢絲絆落翠蜻蜓。"]'),
('9fec99d9-fdcb-4f11-be79-b2e9f268cd28','春夢','王鎡','宋','宋诗','song-poetry','','[]','東風敲碎玉闌干，蝴蝶紛飛夢欲殘。',32,'全唐诗/poet.song.240000.json','["東風敲碎玉闌干，蝴蝶紛飛夢欲殘。", "翠被壓床銀燭暗，夜深誰問海棠寒。"]'),
('b97d0889-df56-46aa-896d-d96c1bd3f548','喜凉','王鎡','宋','宋诗','song-poetry','','[]','吹笛何人在小樓，夜深不下玉簾鈎。',32,'全唐诗/poet.song.240000.json','["吹笛何人在小樓，夜深不下玉簾鈎。", "凉風敲落梧桐葉，片片飛來盡是秋。"]'),
('3403afc5-7612-46f2-8e1b-d6c313350009','宿西湖上竺','王鎡','宋','宋诗','song-poetry','','["\u897f\u6e56"]','不收石上著殘棋，山月無聲鶴睡時。',32,'全唐诗/poet.song.240000.json','["不收石上著殘棋，山月無聲鶴睡時。", "落葉打窗霜滿屋，有僧吟得夜寒詩。"]'),
('da2b48e4-eb1e-46f0-a6f4-d49d09674182','水居','王鎡','宋','宋诗','song-poetry','','[]','飛鷗貼水水連天，一半青山一半烟。',32,'全唐诗/poet.song.240000.json','["飛鷗貼水水連天，一半青山一半烟。", "日暮潮迴漁父醉，不知船閣淺沙邊。"]'),
('8e40a373-bdec-4e12-a585-bfed61b47851','斷橋春望','王鎡','宋','宋诗','song-poetry','','[]','拾翠車閒輦路塵，山南山北杜鵑春。',32,'全唐诗/poet.song.240000.json','["拾翠車閒輦路塵，山南山北杜鵑春。", "誰家庭院東風裏，飛出桃花不見人。"]'),
('cf4f5945-7e7e-4c80-88ab-ed6c95551d7b','吳江旅思','王鎡','宋','宋诗','song-poetry','','[]','千絲楊柳拂征篷，一望菱花漾曉風。',32,'全唐诗/poet.song.240000.json','["千絲楊柳拂征篷，一望菱花漾曉風。", "人在畫樓高處立，鷺鷥飛入水晶宮。"]'),
('fd493d4f-62e2-4e5e-9153-12948a85ea60','花下作字付葉柘山使者','王鎡','宋','宋诗','song-poetry','','[]','花蘚層層潤石牀，綠陰多處自生凉。',32,'全唐诗/poet.song.240000.json','["花蘚層層潤石牀，綠陰多處自生凉。", "閒將筆染荼䕷露，寫得春辭滿紙香。"]'),
('8c7a187c-afa4-4282-877a-39a04002a2d4','春寒','王鎡','宋','宋诗','song-poetry','','[]','玉屏烟冷鷓鴣斑，翡翠簾遮好夢殘。',32,'全唐诗/poet.song.240000.json','["玉屏烟冷鷓鴣斑，翡翠簾遮好夢殘。", "雨又未休人又懶，杏花無力不禁寒。"]'),
('0e7a8b0b-f2ce-4e90-bc96-de05c6f2d63e','孫花翁墓','王鎡','宋','宋诗','song-poetry','','[]','詞入秦樓唱至今，夜魂應共水仙吟。',32,'全唐诗/poet.song.240000.json','["詞入秦樓唱至今，夜魂應共水仙吟。", "墳前幾樹桃花月，照得風流不死心。"]'),
('a5066cec-8051-4dfb-b711-8000ec8b2d1b','呈趙使君時方西遁','王鎡','宋','宋诗','song-poetry','','[]','欲買寒江載月船，牀頭金盡却誰憐。',32,'全唐诗/poet.song.240000.json','["欲買寒江載月船，牀頭金盡却誰憐。", "客囊空有詩千首，難向紅樓當酒錢。"]'),
('bd2c8764-b72c-44ec-8a23-5c7dc45666ef','蜻蜓','王鎡','宋','宋诗','song-poetry','','[]','輕綃剪翅約秋霜，點水低飛戀野塘。',32,'全唐诗/poet.song.240000.json','["輕綃剪翅約秋霜，點水低飛戀野塘。", "忽趁遊蜂過牆去，可憐不識百花香。"]'),
('311cdc85-d928-4275-84c7-3b58e58490f7','燈花','王鎡','宋','宋诗','song-poetry','','[]','喜信今宵報與誰，玉人曾剪畫雙眉。',32,'全唐诗/poet.song.240000.json','["喜信今宵報與誰，玉人曾剪畫雙眉。", "等閒開落銀缸見，只是春風不得知。"]'),
('38ed94fe-00bc-476d-b7a8-7a197d6d5964','重陽紀懷','王鎡','宋','宋诗','song-poetry','','[]','籬根醉倒任斜陽，隔夜茱萸便不香。',32,'全唐诗/poet.song.240000.json','["籬根醉倒任斜陽，隔夜茱萸便不香。", "莫把黄花遮破帽，教人見我鬢邊霜。"]'),
('95a69bd3-3179-4d9d-8aa9-e810d260d4c3','仙源即事  其一','王鎡','宋','宋诗','song-poetry','','[]','山花幽草自成春，深入仙源欲避秦。',32,'全唐诗/poet.song.240000.json','["山花幽草自成春，深入仙源欲避秦。", "地僻不知南北事，相逢盡是種桃人。"]'),
('46af5910-76bb-4eda-a469-7d1b3cb83db1','仙源即事  其二','王鎡','宋','宋诗','song-poetry','','[]','避世移家入亂山，松風杉雨打窗寒。',32,'全唐诗/poet.song.240000.json','["避世移家入亂山，松風杉雨打窗寒。", "牀頭一卷麻衣易，自點松明盡夜看。"]'),
('707af9e5-b4cd-46f6-861e-04b879258dc2','秋日過京口','王鎡','宋','宋诗','song-poetry','','[]','晚風簌簌荻花飛，絡緯聲乾豆葉稀。',32,'全唐诗/poet.song.240000.json','["晚風簌簌荻花飛，絡緯聲乾豆葉稀。", "水國易寒裘馬健，織金添作海青衣。"]'),
('b8eb0e1e-2107-4f98-a70f-162ea86e956c','軍中樂二首  其一','王鎡','宋','宋诗','song-poetry','','[]','靼衫閃色織雲羅，白馬金鞍載翠娥。',32,'全唐诗/poet.song.240000.json','["靼衫閃色織雲羅，白馬金鞍載翠娥。", "把盞醉歸營月上，胡琴捍撥採茶歌。"]'),
('12ea84f0-fdbe-4d78-8e7b-9a376ec9a859','軍中樂二首  其二','王鎡','宋','宋诗','song-poetry','','[]','珊瑚提榼紫金杯，氈帳藏春暖不開。',32,'全唐诗/poet.song.240000.json','["珊瑚提榼紫金杯，氈帳藏春暖不開。", "馬上嬌娃花滿笠，隨軍出看打毬回。"]'),
('052964a1-ebc6-4e5c-a79f-67322ab09801','白牡丹','王鎡','宋','宋诗','song-poetry','','[]','翠雲低護玉樓臺，露洗香苞逐漸開。',32,'全唐诗/poet.song.240000.json','["翠雲低護玉樓臺，露洗香苞逐漸開。", "昨夜賞花人酒醉，月中錯認水晶杯。"]'),
('8e666458-9b81-45b1-9360-76b559aa9ac5','睡海棠','王鎡','宋','宋诗','song-poetry','','[]','費盡臙脂捻得成，楊妃醉後越娉婷。',32,'全唐诗/poet.song.240000.json','["費盡臙脂捻得成，楊妃醉後越娉婷。", "定應夢著三郎事，吹老春風不肯醒。"]'),
('c950d582-f0f2-46fb-9cdc-06f23ec758b1','湖上晚望','王鎡','宋','宋诗','song-poetry','','[]','酒醒湖光生嫩凉，卧船吹笛藕花香。',32,'全唐诗/poet.song.240000.json','["酒醒湖光生嫩凉，卧船吹笛藕花香。", "遊人盡逐鶑花去，一片閒情在夕陽。"]'),
('84024905-20d8-4064-8ebc-d5053b858bae','胡地曲','王鎡','宋','宋诗','song-poetry','','[]','槍旗獵獵動風纓，土雨如雲殺氣腥。',32,'全唐诗/poet.song.240000.json','["槍旗獵獵動風纓，土雨如雲殺氣腥。", "認得打圍枯草際，霜鵰飛趁海東青。"]'),
('690668f4-da78-4e1b-b20f-407cb53cbc90','壽光宮','王鎡','宋','宋诗','song-poetry','','[]','井氣蒸雲濕石欄，白頭道士自燒丹。',32,'全唐诗/poet.song.240000.json','["井氣蒸雲濕石欄，白頭道士自燒丹。", "開門風带琴聲出，一陣松花滿醮壇。"]'),
('4119cbaa-6030-4c37-8a92-ac8ca13020a3','漁父吟','王鎡','宋','宋诗','song-poetry','','[]','竹絲籃裏白魚肥，日落江頭換酒歸。',32,'全唐诗/poet.song.240000.json','["竹絲籃裏白魚肥，日落江頭換酒歸。", "只恐明朝江雪凍，老妻連夜補簑衣。"]'),
('00609e9c-732b-4f7d-8c3c-cb931968ab13','閨詞','王鎡','宋','宋诗','song-poetry','','[]','逢春嬌病鬢蓬鬆，偷拆郎書讀未終。',32,'全唐诗/poet.song.240000.json','["逢春嬌病鬢蓬鬆，偷拆郎書讀未終。", "驀地人來無語答，含羞滿面發潮紅。"]'),
('b96b8fc7-06a8-4f92-a677-44ed1e806a80','述懷  其一','王鎡','宋','宋诗','song-poetry','','[]','平生自笑拙經營，薄有泉田稅犢耕。',64,'全唐诗/poet.song.240000.json','["平生自笑拙經營，薄有泉田稅犢耕。", "實地立身終是穩，權門炙手不爲榮。", "孤山名以吟梅重，彭澤官因愛菊輕。", "塵世幾人貪富貴，可憐頭白竟無成。"]'),
('336aef0c-8b15-4a45-b4d7-01237ac390ec','述懷  其二','王鎡','宋','宋诗','song-poetry','','[]','心如冰靜已無波，劫世虛言莫問他。',64,'全唐诗/poet.song.240000.json','["心如冰靜已無波，劫世虛言莫問他。", "老眼易昏書字大，醉言難謹忤人多。", "山厨烟火燒紅葉，水國衣裳製綠簑。", "濁富清貧分兩路，高眠不管吏徵科。"]'),
('5ab73a10-b203-4bbc-bff9-09d19818f160','春日即事','王鎡','宋','宋诗','song-poetry','','[]','黄金揮盡見空囊，肯把愁眉惱曲腸。',64,'全唐诗/poet.song.240000.json','["黄金揮盡見空囊，肯把愁眉惱曲腸。", "三月時光鶑世界，一年春夢蝶家鄉。", "教成舞妓看楊柳，嬌語眠姬惜海棠。", "昨日醉遊歸路晚，落花飛趁馬蹄香。"]'),
('96b46b47-63e5-422f-9273-1c6326780031','書懷','王鎡','宋','宋诗','song-poetry','','[]','處世功名莫躁爲，識時機變在防危。',64,'全唐诗/poet.song.240000.json','["處世功名莫躁爲，識時機變在防危。", "吉凶有數曾參易，勝負無心不著棋。", "事向直中多骨突，人於財上重交知。", "後車能悟前車覆，箴警何須座右碑。"]'),
('a4db2481-9c95-43e1-87ea-7b9fdcd0b836','山居即事  其一','王鎡','宋','宋诗','song-poetry','','[]','選定唐詩手自編，醒時消遣醉時眠。',64,'全唐诗/poet.song.240000.json','["選定唐詩手自編，醒時消遣醉時眠。", "家家雲氣山藏雨，處處蛙啼水滿田。", "松樹倒生臨澗影，竹根斜掛過牆鞭。", "客來無可延清話，旋摘新茶瓦鼎煎。"]'),
('0a991316-29e4-409d-b1f9-60172209fb04','山居即事  其二','王鎡','宋','宋诗','song-poetry','','[]','閒居却笑俗人忙，又欲移門向野塘。',64,'全唐诗/poet.song.240000.json','["閒居却笑俗人忙，又欲移門向野塘。", "午爨松脂粘斧膩，曉行雲氣濕衣凉。", "長生瑶草成丹藥，萬歲靈藤結紫香。", "林下知心時有月，黄昏相伴入藜牀。"]'),
('a1cf5469-d9cc-4e3a-9fea-23f4f8f807d8','返山居','王鎡','宋','宋诗','song-poetry','','[]','草廬夢醒舊南陽，萬事灰心笑一場。',64,'全唐诗/poet.song.240000.json','["草廬夢醒舊南陽，萬事灰心笑一場。", "齒漱石泉消酒渴，手挼草藥染衣香。", "菊花夜白因添月，柿葉秋紅不是霜。", "大雅今時無問字，天風時到響琴床。"]'),
('649bc948-53c6-465b-8de8-017174a12e66','村中夜歸','王鎡','宋','宋诗','song-poetry','','[]','風報輕寒入暮天，滯行多被酒留連。',64,'全唐诗/poet.song.240000.json','["風報輕寒入暮天，滯行多被酒留連。", "花村無月路全黑，竹屋有燈人未眠。", "雲氣蒼茫沉遠樹，春心浩蕩怯啼鵑。", "忽晴又雨都無准，泥污吟衫亦懶湔。"]'),
('0c36188e-35d9-419d-8cf5-d28bc3978907','謝尹綠坡見訪','王鎡','宋','宋诗','song-poetry','','[]','棕鞋閒踏軟紅塵，道眼青山認得真。',64,'全唐诗/poet.song.240000.json','["棕鞋閒踏軟紅塵，道眼青山認得真。", "不是江湖相識者，誰來泉石訪幽人。", "夜寒草屋三更雨，心事梨花一片春。", "莫笑家風太枯淡，地壚溫酒話逃秦。"]'),
('3ce66003-0447-45a4-b482-9ab8660aa82a','春雨感懷','王鎡','宋','宋诗','song-poetry','','[]','日色開晴又半朝，山溪纔漲響於潮。',64,'全唐诗/poet.song.240000.json','["日色開晴又半朝，山溪纔漲響於潮。", "花遭夜雨心先病，柳媚春風眼易嬌。", "世變漢人能北語，亂興晉室有童謠。", "自從國事推遷後，處處禍延林木焦。"]'),
('99ef42d9-1ed5-4f01-8543-b9826baafc7d','暮春','王鎡','宋','宋诗','song-poetry','','[]','渡頭步石巳平沉，三月溪流處處新。',64,'全唐诗/poet.song.240000.json','["渡頭步石巳平沉，三月溪流處處新。", "柳絮飄零遊子夢，草花清浄道人心。", "只消貧有詩傳世，不要狂思藥化金。", "一片夕陽天共遠，鵑聲相應隔山林。"]'),
('34dd0e35-0dc7-4769-9432-79f5ae60c865','和葉碧峰韻','王鎡','宋','宋诗','song-poetry','','[]','心視功名一羽輕，能吟好句出天生。',64,'全唐诗/poet.song.240000.json','["心視功名一羽輕，能吟好句出天生。", "要磨自己功夫到，肯學前人步武行。", "紙上烟雲纔欲掃，毫端風雨已先驚。", "學詩恰似求仙術，待得成時徹骨清。"]'),
('f8624e8e-c258-4a86-b6fb-7b559230a035','哭葉柘山','王鎡','宋','宋诗','song-poetry','','[]','兩肩山聳梅花瘦，戒飲心齋要獨清。',64,'全唐诗/poet.song.240000.json','["兩肩山聳梅花瘦，戒飲心齋要獨清。", "學得晉人文更古，寫如唐帖草尤精。", "青衫命欠生前貴，白髮詩香死後名。", "魂共靈華應不散，隨仙詔到五雲城。"]'),
('dd3ccf1e-ea25-469e-89d4-3662268a8ae7','姑蘇述古','王鎡','宋','宋诗','song-poetry','','[]','廢苑春風楊柳青，啼鶑猶學館娃聲。',64,'全唐诗/poet.song.240000.json','["廢苑春風楊柳青，啼鶑猶學館娃聲。", "百年氣數花開落，一代興亡潮長平。", "香徑跡荒輿輦絕，屧廊基在蘚苔生。", "繁華已逐英雄去，留得斜陽伴古城。"]');
